
  // ===== 모달 공통 키보드 핸들러 (Enter=저장, Tab/화살표=필드 이동) =====
  (function() {
    // 모달별 저장 버튼 매핑
    var MODAL_SAVE = {
      'planner-modal': 'planner-save-btn',
      'city-modal': 'city-save-btn',
      'trip-modal': null, // onclick 직접 호출
      'finance-modal': 'fin-save-btn',
      'hub-modal': 'hub-save-btn',
      'matrix-modal': 'modal-save-btn',
      'english-modal': 'english-save-btn',
      'income-modal': 'income-save-btn',
      'packing-cat-modal': null,
      'packing-item-modal': null,
      'journey-modal': 'journey-save-btn',
      'income-goal-modal': 'income-goal-save-btn',
      'goal-modal': 'goal-save-btn',
    };

    function getModalInputs(modal) {
      return Array.from(modal.querySelectorAll('input:not([type=hidden]):not([type=checkbox]):not(.hidden), select, textarea')).filter(function(el) {
        return el.offsetParent !== null; // visible only
      });
    }

    function findParentModal(el) {
      var node = el;
      while (node && node !== document) {
        if (node.id && MODAL_SAVE.hasOwnProperty(node.id)) return node;
        node = node.parentElement;
      }
      return null;
    }

    document.addEventListener('keydown', function(e) {
      var target = e.target;
      if (!target || !target.closest) return;
      var modal = findParentModal(target);
      if (!modal) return;

      // Enter → 저장 (select는 제외, textarea에서는 Shift+Enter만)
      if (e.key === 'Enter' && target.tagName !== 'TEXTAREA' && target.tagName !== 'BUTTON') {
        e.preventDefault();
        var saveBtnId = MODAL_SAVE[modal.id];
        if (saveBtnId) {
          var btn = document.getElementById(saveBtnId);
          if (btn && !btn.disabled) btn.click();
        } else {
          // save 버튼 ID 없으면 atl-btn-save 클래스로 찾기
          var btn = modal.querySelector('.atl-btn-save');
          if (btn && !btn.disabled) btn.click();
        }
        return;
      }

      // Arrow Down / Arrow Up → 필드 이동 (select에서는 기본 동작 유지)
      if ((e.key === 'ArrowDown' || e.key === 'ArrowUp') && target.tagName !== 'SELECT') {
        var inputs = getModalInputs(modal);
        var idx = inputs.indexOf(target);
        if (idx < 0) return;
        e.preventDefault();
        var next = e.key === 'ArrowDown' ? idx + 1 : idx - 1;
        if (next >= 0 && next < inputs.length) inputs[next].focus();
      }
    });
  })();

  // ===== 모달 내 select 포커스 시 드롭다운 자동 열기 =====
  document.addEventListener('focusin', function(e) {
    if (e.target.tagName === 'SELECT' && e.target.closest('.fixed.inset-0.z-50')) {
      try { e.target.showPicker(); } catch(err) {}
    }
  });

  // ===== 모달 바깥 클릭 시 닫기 (드래그 선택 보호) =====
  var _modalMouseDownTarget = null;
  document.addEventListener('mousedown', function(e) { _modalMouseDownTarget = e.target; });
  document.addEventListener('click', function(e) {
    var modals = document.querySelectorAll('.fixed.inset-0.z-50.bg-black\\/40');
    modals.forEach(function(modal) {
      if (modal.style.cssText.indexOf('none') >= 0) return;
      // mousedown과 click 모두 오버레이에서 발생했을 때만 닫기
      if (e.target === modal && _modalMouseDownTarget === modal) {
        modal.style.cssText = 'display:none!important';
      }
    });
    _modalMouseDownTarget = null;
  });

  // ===== PLANNER GOALS (milestones 연동) =====
  let plannerGoals = [];
  let editingGoalId = null;

  const GOAL_STATUS_COLORS = {
    '완료':   'bg-teal-100 text-teal-700 border-teal-200',
    '진행 중':'bg-indigo-100 text-indigo-700 border-indigo-200',
    '예정':   'bg-slate-100 text-slate-600 border-slate-200',
  };

  async function loadPlannerGoals() {
    var now = new Date();
    var monthStr = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    var MONTHS_KR2 = ['1월','2월','3월','4월','5월','6월','7월','8월','9월','10월','11월','12월'];
    var label = document.getElementById('planner-goal-month');
    if (label) label.textContent = now.getFullYear() + '년 ' + MONTHS_KR2[now.getMonth()] + ' 목표';

    try {
      var docs = await fbRead('milestones');
      plannerGoals = docs.filter(function(d){ return (d.month||'').startsWith(monthStr); });
      renderPlannerGoals();
    } catch(err) { console.error('Goals load error:', err); }
  }

  function renderPlannerGoals() {
    var el = document.getElementById('planner-goals-list');
    if (!el) return;
    if (plannerGoals.length === 0) {
      el.innerHTML = '<div class="text-xs text-slate-400 text-center py-4">이달의 목표를 추가해봐!</div>';
      return;
    }
    var done = plannerGoals.filter(function(g){ return g.status === '완료'; }).length;
    var pct = Math.round((done / plannerGoals.length) * 100);

    el.innerHTML =
      // Progress bar
      '<div class="flex items-center gap-3 mb-4 px-2">' +
      '<div class="flex-1 h-2 bg-slate-100 rounded-full overflow-hidden">' +
      '<div class="h-full gradient-primary rounded-full transition-all" style="width:' + pct + '%"></div></div>' +
      '<span class="text-xs font-black text-indigo-600 shrink-0">' + done + '/' + plannerGoals.length + ' (' + pct + '%)</span>' +
      '</div>' +
      plannerGoals.map(function(g) {
        var statusCls = GOAL_STATUS_COLORS[g.status] || GOAL_STATUS_COLORS['예정'];
        return '<div class="flex items-center justify-between px-3 py-3 rounded-xl hover:bg-slate-50 transition-colors group">' +
          '<div class="flex items-center gap-3 flex-1">' +
          '<button data-gid="' + g._id + '" onclick="toggleGoalStatus(this.dataset.gid)" class="w-5 h-5 rounded-full border-2 flex items-center justify-center shrink-0 transition-all ' +
          (g.status==='완료' ? 'bg-teal-500 border-teal-500 text-white' : 'border-slate-300 hover:border-indigo-400') + '">' +
          (g.status==='완료' ? '<span class="material-symbols-outlined text-xs" style="font-size:12px">check</span>' : '') +
          '</button>' +
          '<span class="text-sm font-semibold text-slate-700 ' + (g.status==='완료'?'line-through text-slate-400':'') + '">' + (g.goal||'') + '</span>' +
          '</div>' +
          '<div class="flex items-center gap-2 shrink-0">' +
          '<span class="text-[9px] font-black uppercase px-2 py-0.5 rounded-full border ' + statusCls + '">' + (g.status||'예정') + '</span>' +
          '<div class="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">' +
          '<button data-gid="' + g._id + '" onclick="editGoal(this.dataset.gid)" class="p-1 hover:bg-indigo-100 rounded text-slate-300 hover:text-indigo-600"><span class="material-symbols-outlined text-sm">edit</span></button>' +
          '<button data-gid="' + g._id + '" onclick="deleteGoal(this.dataset.gid)" class="p-1 hover:bg-rose-100 rounded text-slate-300 hover:text-rose-500"><span class="material-symbols-outlined text-sm">delete</span></button>' +
          '</div></div></div>';
      }).join('');
  }

  function openGoalModal(id) {
    editingGoalId = id || null;
    document.getElementById('goal-modal-title').textContent = editingGoalId ? '목표 수정' : '목표 추가';
    if (editingGoalId) {
      var g = plannerGoals.find(function(g){ return g._id === editingGoalId; });
      document.getElementById('goal-text').value = g ? (g.goal||'') : '';
      document.getElementById('goal-status').value = g ? (g.status||'진행 중') : '진행 중';
    } else {
      document.getElementById('goal-text').value = '';
      document.getElementById('goal-status').value = '진행 중';
    }
    document.getElementById('goal-modal').style.cssText = 'display:flex!important';
  }

  function closeGoalModal() {
    document.getElementById('goal-modal').style.cssText = 'display:none!important';
    editingGoalId = null;
  }

  async function saveGoalEntry() {
    var btn = document.getElementById('goal-save-btn');
    btn.textContent = '저장 중...'; btn.disabled = true;
    var now = new Date();
    var monthStr = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    var obj = {
      month: monthStr,
      goal: document.getElementById('goal-text').value.trim(),
      status: document.getElementById('goal-status').value,
    };
    if (!obj.goal) { alert('목표 내용을 입력해줘!'); btn.textContent='저장'; btn.disabled=false; return; }
    try {
      if (editingGoalId) {
        await fbUpdate('milestones', editingGoalId, obj);
        var g = plannerGoals.find(function(g){ return g._id === editingGoalId; });
        if (g) Object.assign(g, obj);
      } else {
        var saved = await fbAdd('milestones', obj);
        plannerGoals.push(saved);
      }
      renderPlannerGoals();
      closeGoalModal();
    } catch(err) { alert('저장에 실패했어요.'); }
    finally { btn.textContent = '저장'; btn.disabled = false; }
  }

  function editGoal(id) { openGoalModal(id); }

  async function deleteGoal(id) {
    try {
      await fbDelete('milestones', id);
      plannerGoals = plannerGoals.filter(function(g){ return g._id !== id; });
      renderPlannerGoals();
    } catch(err) { alert('삭제에 실패했어요.'); }
  }

  async function toggleGoalStatus(id) {
    var g = plannerGoals.find(function(g){ return g._id === id; });
    if (!g) return;
    var next = g.status === '완료' ? '진행 중' : '완료';
    try {
      await fbUpdate('milestones', id, {status: next});
      g.status = next;
      renderPlannerGoals();
    } catch(err) { console.error(err); }
  }

  // ===== PLANNER: GOOGLE SHEETS INTEGRATION =====
  let plannerData = [];
  let editingPlannerIndex = null;
  let plannerYear = new Date().getFullYear();
  let plannerMonth = new Date().getMonth(); // 0-indexed

  const COLOR_MAP = {
    'sky':     'bg-pastel-sky text-pastel-sky-text border-pastel-sky-text/20',
    'amber':   'bg-pastel-amber text-pastel-amber-text border-pastel-amber-text/20',
    'violet':  'bg-pastel-violet text-pastel-violet-text border-pastel-violet-text/20',
    'rose':    'bg-pastel-rose text-pastel-rose-text border-pastel-rose-text/20',
    'lime':    'bg-pastel-lime text-pastel-lime-text border-pastel-lime-text/20',
    'cyan':    'bg-pastel-cyan text-pastel-cyan-text border-pastel-cyan-text/20',
    'orange':  'bg-pastel-orange text-pastel-orange-text border-pastel-orange-text/20',
    'indigo':  'bg-indigo-100 text-indigo-800 border-indigo-200',
    'birthday': 'bg-[#facc15] text-[#1d1a23] border-[#facc15]/40',
    'pink':    'bg-pink-100 text-pink-700 border-pink-200',
    'fuchsia': 'bg-fuchsia-100 text-fuchsia-700 border-fuchsia-200',
  };
  const CAT_TRACK = {
    '글쓰기':'writing','영어':'english','스터디':'study',
    '업무':'work','개인':'personal','연차':'vacation'
  };
  const CAT_COLOR = {
    '업무':'rose','연차':'cyan','특별휴가':'pink','개인':'fuchsia','글쓰기':'sky',
    '영어':'lime','스터디':'violet','생일':'birthday'
  };

  // ===== 대한민국 공휴일 =====
  function getKoreanHolidays(year) {
    var holidays = {};
    function add(m, d, name) {
      var key = year + '-' + String(m).padStart(2,'0') + '-' + String(d).padStart(2,'0');
      holidays[key] = name;
    }
    // 양력 고정 공휴일
    add(1,1,'신정');
    add(3,1,'삼일절');
    add(5,1,'노동절');
    add(5,5,'어린이날');
    add(6,6,'현충일');
    add(7,17,'제헌절');
    add(8,15,'광복절');
    add(10,3,'개천절');
    add(10,9,'한글날');
    add(12,25,'크리스마스');

    // 음력 공휴일 (설날, 추석, 부처님오신날) — 연도별 양력 변환 테이블
    var lunarMap = {
      2024: { seol:['02-09','02-10','02-11'], chuseok:['09-16','09-17','09-18'], buddha:'05-15' },
      2025: { seol:['01-28','01-29','01-30'], chuseok:['10-05','10-06','10-07'], buddha:'05-05' },
      2026: { seol:['02-16','02-17','02-18'], chuseok:['09-24','09-25','09-26'], buddha:'05-24' },
      2027: { seol:['02-06','02-07','02-08'], chuseok:['09-14','09-15','09-16'], buddha:'05-13' },
      2028: { seol:['01-25','01-26','01-27'], chuseok:['10-02','10-03','10-04'], buddha:'05-02' },
      2029: { seol:['02-12','02-13','02-14'], chuseok:['09-21','09-22','09-23'], buddha:'05-20' },
      2030: { seol:['02-02','02-03','02-04'], chuseok:['09-11','09-12','09-13'], buddha:'05-09' },
    };
    if (lunarMap[year]) {
      var lm = lunarMap[year];
      lm.seol.forEach(function(d){ holidays[year+'-'+d] = '설날'; });
      lm.chuseok.forEach(function(d){ holidays[year+'-'+d] = '추석'; });
      holidays[year+'-'+lm.buddha] = '부처님오신날';
    }

    // 임시 공휴일 (선거 등)
    var specialMap = {
      2026: [['06-03','지방선거']],
    };
    if (specialMap[year]) {
      specialMap[year].forEach(function(pair){ holidays[year+'-'+pair[0]] = pair[1]; });
    }

    // 대체공휴일 (2024~2030, 공휴일이 주말/다른 공휴일과 겹칠 때)
    var substMap = {
      2024: [['02-12','설날 대체공휴일'],['05-06','어린이날 대체공휴일']],
      2025: [['03-03','삼일절 대체공휴일'],['05-06','부처님오신날 대체공휴일'],['10-08','추석 대체공휴일']],
      // 현충일·신정·제헌절은 한국법상 대체공휴일 미적용 → 제외
      // 2026 추석: 9/24(목)~9/26(토). 추석/설날은 일요일 겹침만 대체 적용 → 09-28 대체공휴일 없음
      2026: [['03-02','삼일절 대체공휴일'],['05-25','부처님오신날 대체공휴일'],['08-17','광복절 대체공휴일'],['10-05','개천절 대체공휴일']],
      2027: [['02-09','설날 대체공휴일'],['08-16','광복절 대체공휴일'],['10-04','개천절 대체공휴일'],['10-11','한글날 대체공휴일'],['12-27','크리스마스 대체공휴일']],
      2028: [['10-05','추석 대체공휴일']],
      2029: [['05-07','어린이날 대체공휴일'],['05-21','부처님오신날 대체공휴일'],['09-24','추석 대체공휴일']],
      2030: [['02-05','설날 대체공휴일'],['05-06','어린이날 대체공휴일']],
    };
    if (substMap[year]) {
      substMap[year].forEach(function(pair){ holidays[year+'-'+pair[0]] = pair[1]; });
    }

    return holidays;
  }

  async function loadPlanner() {
    try {
      // ★ 중요: renderCalendar의 auto-dedup이 cache render와 fresh fetch 사이에서
      //   race condition을 일으켜 작품 일정 이중 등록되는 버그가 있어
      //   → loadPlanner 시작 시 flag 미리 set, dedup은 _loadPlannerBackground만 담당
      window._calDedupeRanOnce = true;

      // ★ 1단계: localStorage 캐시로 즉시 렌더 (모바일 체감속도 개선)
      try {
        var rawCache = localStorage.getItem('atelier_snapshot_planner');
        if (rawCache) {
          var cached = JSON.parse(rawCache);
          if (cached && cached.data && cached.data.length > 0) {
            plannerData = cached.data.map(function(d){ return objToRow('planner', d).concat([d._id]); });
            _initCalNavSelects();
            renderCalendar();
            console.log('[loadPlanner] 캐시 렌더 (', plannerData.length, '건) — 백그라운드 fetch 진행');
          }
        }
      } catch(e) { /* cache parse 실패 무시 */ }

      // ★ 2단계: 신선한 데이터 fetch
      const docs = await fbRead('planner');
      plannerData = docs.map(function(d){ return objToRow('planner', d).concat([d._id]); });

      // ★ 3단계: 즉시 render — 사용자는 여기까지면 캘린더 보임
      _initCalNavSelects();
      renderCalendar();
      updatePlannerTracks();
      loadPlannerGoals();
      _loadSeriesMap();
      _loadYearlyBirthdays();
      if (typeof loadWorks === 'function') loadWorks();
      if (typeof renderWorkTimeline === 'function') renderWorkTimeline();

      // ★ 4단계: 무거운 작업은 백그라운드로 (사용자 대기 X)
      setTimeout(function(){ _loadPlannerBackground(); }, 0);
    } catch(err) {
      console.error('Planner load error:', err);
    }
  }

  // 백그라운드 작업: 색상 마이그레이션 + 매트릭스 sync + dedup + orphan cleanup
  async function _loadPlannerBackground() {
    try {
      // 색상 마이그레이션: 작품 파이프라인 일정(work_id 포함)은 시리즈 색상 유지 → skip
      var migrated = 0;
      for (var mi = 0; mi < plannerData.length; mi++) {
        var row = plannerData[mi];
        if ((row[4]||'').indexOf('work_id:') >= 0) continue;
        var catTrimmed = (row[2]||'').trim();
        var correctColor = CAT_COLOR[catTrimmed];
        if (correctColor && row[3] !== correctColor) {
          row[3] = correctColor;
          if (catTrimmed !== row[2]) row[2] = catTrimmed;
          try {
            await fbUpdate('planner', row[7], { color: correctColor, category: catTrimmed });
            migrated++;
          } catch(e) { console.error('Color migration error:', e); }
        }
      }
      if (migrated > 0) {
        console.log('Planner color migrated:', migrated, 'entries');
        renderCalendar(); // 색상 바뀐 거 반영
      }
      // 캘린더→매트릭스 일괄 동기화 (단일+다일 일정 모두)
      var matrixDocs = await fbRead('matrix');
      matrixData = matrixDocs.map(function(d){ return objToRow('matrix', d).concat([d._id]); });
      var FIELDS = ['date','day','work','leave','personal','writing','serial1','english','ai_study','workingout'];
      var days = ['일','월','화','수','목','금','토'];
      // 캘린더→매트릭스 전체 동기화 (날짜별로 모든 필드 재구성)
      var MAPPED_FIELDS = [2,3,4,5,6,7,8]; // work,leave,personal,writing,serial1,english,ai_study
      var plannerByDate = {};
      for (var si = 0; si < plannerData.length; si++) {
        var sRow = plannerData[si];
        var sEnd = sRow[5] || sRow[0];
        var sField = PLANNER_TO_MATRIX[(sRow[2]||'').trim()];
        if ((sRow[2]||'').trim() === '글쓰기' && _isPublishingEvent(sRow[1], sRow[4])) sField = 'serial1';
        if (!sRow[0] || !sField || !sRow[1]) continue;
        var sFIdx = FIELDS.indexOf(sField);
        if (sFIdx <= 0) continue;
        var sCur = new Date(sRow[0]+'T00:00:00'), sEndD = new Date(sEnd+'T00:00:00');
        while (sCur <= sEndD) {
          var sDs = sCur.getFullYear()+'-'+String(sCur.getMonth()+1).padStart(2,'0')+'-'+String(sCur.getDate()).padStart(2,'0');
          if (!plannerByDate[sDs]) plannerByDate[sDs] = {};
          if (!plannerByDate[sDs][sFIdx]) plannerByDate[sDs][sFIdx] = [];
          // 연차: 주말/공휴일은 스킵, 평일만 매트릭스에 반영
          var syncVal = sRow[1];
          var isLeave = (sRow[2]||'').trim() === '연차';
          if (isLeave) {
            var dow = sCur.getDay();
            var syncHolidays = getKoreanHolidays(sCur.getFullYear());
            if (dow === 0 || dow === 6 || syncHolidays[sDs]) { sCur.setDate(sCur.getDate()+1); continue; }
            syncVal = '1.0 ' + sRow[1];
          }
          plannerByDate[sDs][sFIdx].push(syncVal);
          sCur.setDate(sCur.getDate()+1);
        }
      }
      var matrixSynced = 0;
      var syncDates = Object.keys(plannerByDate);
      for (var sd = 0; sd < syncDates.length; sd++) {
        var dateStr = syncDates[sd];
        var fieldMap = plannerByDate[dateStr];
        var sMRow = matrixData.find(function(r){return r[0]===dateStr;});
        var needUpdate = false;
        if (sMRow) {
          for (var mf = 0; mf < MAPPED_FIELDS.length; mf++) {
            var fi = MAPPED_FIELDS[mf];
            var expected = fieldMap[fi] ? fieldMap[fi].join(', ') : '';
            if (sMRow[fi] !== expected) { sMRow[fi] = expected; needUpdate = true; }
          }
          if (needUpdate) {
            var smId = sMRow[10]||sMRow[9];
            if (smId) try { await fbUpdate('matrix', smId, rowToObj('matrix', sMRow)); matrixSynced++; } catch(e){}
          }
        } else {
          var dd = new Date(dateStr+'T00:00:00');
          var sNewRow = [dateStr, days[dd.getDay()], '','','','','','','',''];
          for (var mf2 = 0; mf2 < MAPPED_FIELDS.length; mf2++) {
            var fi2 = MAPPED_FIELDS[mf2];
            if (fieldMap[fi2]) sNewRow[fi2] = fieldMap[fi2].join(', ');
          }
          try { var sSaved = await fbAdd('matrix', rowToObj('matrix', sNewRow)); matrixData.push(sNewRow.concat([sSaved._id])); matrixSynced++; } catch(e){}
        }
      }
      // Phase B: 유령 데이터 정리 (loadPlanner)
      var CLEANUP_FIELDS_P = [3, 5, 7, 8];
      for (var ci2 = 0; ci2 < matrixData.length; ci2++) {
        var cRow2 = matrixData[ci2];
        var cDate2 = cRow2[0];
        if (!cDate2) continue;
        var cMap2 = plannerByDate[cDate2];
        var cNeedUp2 = false;
        for (var cf2 = 0; cf2 < CLEANUP_FIELDS_P.length; cf2++) {
          var cfi2 = CLEANUP_FIELDS_P[cf2];
          var cExp2 = (cMap2 && cMap2[cfi2]) ? cMap2[cfi2].join(', ') : '';
          if (cRow2[cfi2] && cRow2[cfi2] !== cExp2) {
            console.log('[MatrixClean] ' + cDate2 + ' field[' + cfi2 + ']: "' + cRow2[cfi2] + '" → "' + cExp2 + '"');
            cRow2[cfi2] = cExp2;
            cNeedUp2 = true;
          }
        }
        if (cNeedUp2) {
          var cId2 = cRow2[10] || cRow2[9];
          if (cId2) try { await fbUpdate('matrix', cId2, rowToObj('matrix', cRow2)); matrixSynced++; } catch(e) {}
        }
      }
      if (matrixSynced > 0) {
        console.log('Matrix synced from planner:', matrixSynced, 'entries');
      }

      // 안전망: 누적된 중복 + 삭제된 작품의 고아 일정 자동 정리 (idempotent)
      if (typeof cleanupDuplicateWorkEvents === 'function') {
        try {
          var dupCnt = await cleanupDuplicateWorkEvents();
          if (dupCnt > 0) console.log('[loadPlanner BG] 자동 중복 정리:', dupCnt, '개');
        } catch(e) { console.warn('auto dedupe failed', e); }
      }
      if (typeof cleanupOrphanWorkEvents === 'function') {
        try {
          var orphanCnt = await cleanupOrphanWorkEvents();
          if (orphanCnt > 0) console.log('[loadPlanner BG] 자동 고아 정리:', orphanCnt, '개');
        } catch(e) { console.warn('auto orphan cleanup failed', e); }
      }
    } catch(err) {
      console.error('Planner background load error:', err);
    }
  }

  function renderCalendar() {
    const MONTHS_KR = ['1월','2월','3월','4월','5월','6월','7월','8월','9월','10월','11월','12월'];
    _syncCalNavSelects();
    // ★ 세션 1회 자동 정리: 중복(stale) + 고아(삭제된 작품의 잔재) 둘 다
    if (!window._calDedupeRanOnce && typeof cleanupDuplicateWorkEvents === 'function' && (plannerData||[]).length > 0) {
      window._calDedupeRanOnce = true;
      (async function(){
        try {
          var dupN = await cleanupDuplicateWorkEvents();
          var orphanN = 0;
          if (typeof cleanupOrphanWorkEvents === 'function') {
            orphanN = await cleanupOrphanWorkEvents();
          }
          var totalN = (dupN || 0) + (orphanN || 0);
          if (totalN > 0) {
            console.log('[CalDedup] 자동 정리: 중복', dupN || 0, '+ 고아', orphanN || 0, '=', totalN, '개');
            if (typeof showSyncToast === 'function') {
              var parts = [];
              if (dupN > 0) parts.push('중복 ' + dupN);
              if (orphanN > 0) parts.push('삭제된 작품 잔재 ' + orphanN);
              showSyncToast('<span class="material-symbols-outlined text-sm mr-1">cleaning_services</span> ' + parts.join(' · ') + ' 자동 정리됨');
            }
            renderCalendar();
          }
        } catch(e) { console.warn('[CalDedup] 실패:', e); }
      })();
    }

    const grid = document.getElementById('planner-grid');
    grid.innerHTML = '';

    const firstDay = new Date(plannerYear, plannerMonth, 1).getDay(); // 0=Sun
    const daysInMonth = new Date(plannerYear, plannerMonth + 1, 0).getDate();
    const offset = firstDay; // Sun=0 시작

    const today = new Date();
    const isCurrentMonth = today.getFullYear() === plannerYear && today.getMonth() === plannerMonth;
    const holidays = getKoreanHolidays(plannerYear);

    function buildDayCell(yr, mn, d, gridIdx, isOutMonth) {
      const dateStr = yr + '-' + String(mn+1).padStart(2,'0') + '-' + String(d).padStart(2,'0');
      const dayOfWeek = gridIdx % 7;
      const isWeekend = dayOfWeek === 0 || dayOfWeek === 6;
      const isToday = !isOutMonth && isCurrentMonth && d === today.getDate();
      const cellHolidays = (isOutMonth && yr !== plannerYear) ? getKoreanHolidays(yr) : holidays;

      var monthDay = '-' + String(mn+1).padStart(2,'0') + '-' + String(d).padStart(2,'0');
      const events = plannerData.filter(function(r) {
        var start = (r[0]||'').toString();
        var end = (r[5]||'').toString();
        if (end && end > start) {
          return dateStr >= start && dateStr <= end;
        }
        if (start.startsWith(dateStr)) return true;
        if (r[2] === '생일' && start.endsWith(monthDay) && !start.startsWith(String(yr))) {
          var docId = r[7];
          if (docId && _yearlyBirthdayIds[docId]) return true;
        }
        return false;
      });
      events.sort(function(a, b) {
        var aRange = (a[5] && a[5] > a[0]) ? 1 : 0;
        var bRange = (b[5] && b[5] > b[0]) ? 1 : 0;
        if (aRange !== bRange) return bRange - aRange;
        if (a[2] === '업무' && b[2] !== '업무') return -1;
        if (a[2] !== '업무' && b[2] === '업무') return 1;
        return (parseInt(a[6])||0) - (parseInt(b[6])||0);
      });

      const isHoliday = !!cellHolidays[dateStr];
      const holidayName = cellHolidays[dateStr] || '';

      var hasLeave = events.some(function(ev) { return ev[2] === '연차'; });
      var hasSpecial = events.some(function(ev) { return ev[2] === '특별휴가'; });

      const cell = document.createElement('div');
      cell.className = 'px-3 pt-3 pb-1 min-h-24 transition-all cursor-pointer group';
      if (isOutMonth) {
        cell.style.background = 'rgba(243,244,245,0.4)';
        cell.style.opacity = '0.5';
      }
      // 공휴일은 어떤 일정이 들어오든 무조건 빨간 배경 유지 (연차/특별/오늘과 그라데이션 결합)
      else if (isHoliday) {
        if (hasLeave) cell.style.background = 'linear-gradient(135deg,#FFCDCD 60%,#FCC98F60)';
        else if (hasSpecial) cell.style.background = 'linear-gradient(135deg,#FFCDCD 60%,#FFE0E060)';
        else if (isToday) cell.style.background = 'linear-gradient(135deg,#FFCDCD 60%,rgba(107,56,212,0.10))';
        else cell.style.background = '#FFCDCD';
      }
      else if (hasLeave) { cell.style.background = isToday ? 'linear-gradient(135deg,rgba(107,56,212,0.04),rgba(252,201,143,0.4))' : '#FCC98F40'; }
      else if (isToday) { cell.style.background = hasSpecial ? 'linear-gradient(135deg,rgba(107,56,212,0.04),rgba(255,224,224,0.5))' : 'rgba(107,56,212,0.04)'; }
      else if (hasSpecial) { cell.style.background = '#FFE0E0'; }
      if (isToday) { cell.style.outline = '2px solid rgba(107,56,212,0.3)'; cell.style.outlineOffset = '-2px'; cell.style.borderRadius = '12px'; }
      cell.dataset.date = dateStr;
      cell.onclick = function() { selectPlannerDate(dateStr, this); };
      cell.ondblclick = function() { openPlannerModal(null, dateStr); };

      cell.addEventListener('dragover', function(e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = (e.ctrlKey || e.metaKey) ? 'copy' : 'move';
        this.classList.add('bg-indigo-100', 'border-indigo-300');
      });
      cell.addEventListener('dragleave', function() {
        this.classList.remove('bg-indigo-100', 'border-indigo-300');
      });
      cell.addEventListener('drop', function(e) {
        e.preventDefault();
        e.stopPropagation();
        this.classList.remove('bg-indigo-100', 'border-indigo-300');
        var dragIdx = parseInt(e.dataTransfer.getData('text/plain'));
        var newDate = this.dataset.date;
        if (!isNaN(dragIdx) && newDate) {
          if (plannerCtrlDrag) {
            copiedPlannerEvent = plannerData[dragIdx].slice(0, 7);
            pastePlannerEvent(newDate);
          } else {
            dropPlannerEvent(dragIdx, newDate);
          }
        }
      });

      let dayNum = '<span class="';
      if (isToday) dayNum += 'inline-flex items-center justify-center w-7 h-7 rounded-full text-white text-xs font-bold shadow-sm" style="background:linear-gradient(135deg,#6b38d4,#8455ef)';
      else if (isHoliday || isWeekend) dayNum += 'font-bold text-sm" style="color:#8B1A1A';
      else dayNum += 'font-bold text-sm text-[#191c1d]';
      dayNum += '">' + d + '</span>';
      if (isHoliday) dayNum += '<span class="text-[8px] font-bold ml-1" style="color:#8B1A1A">' + holidayName + '</span>';

      const eventHtml = events.map(function(ev, ei) {
        const realIdx = plannerData.indexOf(ev);
        const color = COLOR_MAP[ev[3]] || COLOR_MAP['blue'];
        var start = (ev[0]||'').toString();
        var end = (ev[5]||'').toString();
        var isRange = end && end > start;
        var isFirst = !isRange || dateStr === start;
        var isLast = !isRange || dateStr === end;

        if (!isRange) {
          var docId = ev[7] || '';
          var evSeriesId = _getSeriesIdForDoc(docId);
          var seriesBtn = evSeriesId ? '<button onclick="event.stopPropagation();openSeriesDeleteConfirm(\'' + evSeriesId + '\')" class="text-current" title="시리즈 전체 삭제">⊘</button>' : '';
          var isPub = ((ev[4]||'').indexOf('phase:publishing') >= 0) || /^\d+화\s*\(/.test(ev[1]||'');
          var evColor3 = (ev[3]||'').trim();
          var pubCls = isPub ? 'mt-1.5 mb-1.5 text-[12px] px-3 py-1.5 rounded-full font-black border-l-4 flex items-center justify-between gap-1 cursor-grab text-white' : 'mt-1 text-[13px] px-1.5 py-1 rounded-md font-bold truncate border-l-2 flex items-center justify-between gap-1 cursor-grab';
          var pubInline = isPub ? 'box-shadow:0 2px 6px rgba(0,0,0,0.18),0 0 0 2px white;text-shadow:0 1px 2px rgba(0,0,0,0.25);z-index:2;position:relative' : '';
          var pubPrefix = isPub ? '🎯 ' : '';
          return '<div class="' + pubCls + ' ' + (isPub ? '' : color) + '" style="' + pubInline + (isPub ? ';background:' + (_seriesHexMap[evColor3]||'#6366f1') + ';border-left-color:rgba(0,0,0,0.2)' : '') + '" ' +
            'data-pidx="' + realIdx + '" ' +
            'draggable="true" ondragstart="event.stopPropagation();plannerDragStart(event,' + realIdx + ')" ondragend="plannerDragEnd(event)" ' +
            'ondragover="event.preventDefault();event.stopPropagation();this.classList.add(\'ring-2\',\'ring-indigo-400\')" ' +
            'ondragleave="this.classList.remove(\'ring-2\',\'ring-indigo-400\')" ' +
            'ondrop="event.preventDefault();event.stopPropagation();this.classList.remove(\'ring-2\',\'ring-indigo-400\');reorderPlannerEvent(event,' + realIdx + ')" ' +
            'onclick="event.stopPropagation();selectPlannerEvent(' + realIdx + ',this)" ondblclick="event.stopPropagation();openPlannerModal(' + realIdx + ')">' +
            '<span class="truncate">' + pubPrefix + (ev[1]||'') + '</span>' +
            '<div class="flex gap-0.5 shrink-0 opacity-0 group-hover:opacity-100">' +
            '<button onclick="event.stopPropagation();openPlannerModal(' + realIdx + ')" class="text-current">✎</button>' +
            '<button onclick="event.stopPropagation();deletePlannerRow(' + realIdx + ')" class="text-current">×</button>' +
            seriesBtn +
            '</div></div>';
        }

        var dayOfWeekR = gridIdx % 7;
        var isWeekStart = dayOfWeekR === 0;
        var isWeekEnd = dayOfWeekR === 6;
        var isMonthStart = !isOutMonth && d === 1;
        var isMonthEnd = !isOutMonth && d === daysInMonth;

        var blockStart = isFirst || isMonthStart || isWeekStart;
        var blockEnd = isLast || isMonthEnd || isWeekEnd;
        var showTitle = blockStart;

        var rl = blockStart ? 'border-radius:6px 0 0 6px;' : 'border-radius:0;';
        var rr = blockEnd ? 'border-radius:0 6px 6px 0;' : '';
        if (blockStart && blockEnd) { rl = 'border-radius:6px;'; rr = ''; }
        else if (!blockStart && blockEnd) { rl = 'border-radius:0 6px 6px 0;'; rr = ''; }
        else if (!blockStart && !blockEnd) { rl = 'border-radius:0;'; rr = ''; }

        var colorParts = color.split(' ');
        var bgColor = colorParts.find(function(c){ return c.startsWith('bg-'); }) || 'bg-indigo-100';
        var textColor = colorParts.find(function(c){ return c.startsWith('text-'); }) || 'text-indigo-700';

        var ml = blockStart ? 'margin-left:0;padding-left:8px;' : 'margin-left:-13px;padding-left:0;';
        var mr = blockEnd ? 'margin-right:0;padding-right:8px;' : 'margin-right:-13px;padding-right:0;';

        return '<div class="mt-1 ' + bgColor + ' flex items-center overflow-visible cursor-grab" ' +
          'style="height:26px;' + rl + rr + ml + mr + 'position:relative;z-index:5;" ' +
          'data-pidx="' + realIdx + '" ' +
          'draggable="true" ondragstart="event.stopPropagation();plannerDragStart(event,' + realIdx + ')" ondragend="plannerDragEnd(event)" ' +
          'onclick="event.stopPropagation();selectPlannerEvent(' + realIdx + ',this)" ondblclick="event.stopPropagation();openPlannerModal(' + realIdx + ')">' +
          (showTitle
            ? '<span class="text-[13px] font-bold truncate whitespace-nowrap ' + textColor + '" style="padding:0 4px">' + (ev[1]||'') + '</span>'
            : '') +
          '</div>';
      }).join('');

      cell.innerHTML = dayNum + eventHtml;
      return cell;
    }

    // Previous month trailing days (with events, faded)
    const prevMonthDays = new Date(plannerYear, plannerMonth, 0).getDate();
    const prevYr = plannerMonth === 0 ? plannerYear - 1 : plannerYear;
    const prevMn = plannerMonth === 0 ? 11 : plannerMonth - 1;
    for (let i = 0; i < offset; i++) {
      const prevDay = prevMonthDays - offset + 1 + i;
      grid.appendChild(buildDayCell(prevYr, prevMn, prevDay, i, true));
    }

    // Current month days
    for (let d = 1; d <= daysInMonth; d++) {
      grid.appendChild(buildDayCell(plannerYear, plannerMonth, d, offset + d - 1, false));
    }

    // Next month leading days (with events, faded)
    const total = offset + daysInMonth;
    const remainder = total % 7 === 0 ? 0 : 7 - (total % 7);
    const nextYr = plannerMonth === 11 ? plannerYear + 1 : plannerYear;
    const nextMn = plannerMonth === 11 ? 0 : plannerMonth + 1;
    for (let i = 0; i < remainder; i++) {
      grid.appendChild(buildDayCell(nextYr, nextMn, i + 1, total + i, true));
    }
    updateCalLeaveTracker();
  }

  function updatePlannerTracks() {
    const currentMonthStr = plannerYear + '-' + String(plannerMonth+1).padStart(2,'0');
    const counts = { writing:0, english:0, study:0, work:0, personal:0, vacation:0 };
    var trackHolidays = getKoreanHolidays(plannerYear);
    plannerData.forEach(function(row) {
      const startDate = (row[0]||'').toString();
      const endDate = (row[5]||startDate).toString();
      const track = CAT_TRACK[(row[2]||'').trim()];
      if (!track || !startDate) return;

      if (track === 'vacation') {
        // 연차: 날짜 범위를 펼쳐서 현재 월의 평일만 카운팅
        var cur = new Date(startDate+'T00:00:00'), endD = new Date(endDate+'T00:00:00');
        while (cur <= endD) {
          var ds = cur.getFullYear()+'-'+String(cur.getMonth()+1).padStart(2,'0')+'-'+String(cur.getDate()).padStart(2,'0');
          if (ds.startsWith(currentMonthStr)) {
            var dow = cur.getDay();
            if (dow !== 0 && dow !== 6 && !trackHolidays[ds]) counts[track] += 1;
          }
          cur.setDate(cur.getDate()+1);
        }
      } else if (endDate > startDate) {
        // 다일 일정: 현재 월에 속하는 날짜만 카운팅
        var cur2 = new Date(startDate+'T00:00:00'), endD2 = new Date(endDate+'T00:00:00');
        while (cur2 <= endD2) {
          var ds2 = cur2.getFullYear()+'-'+String(cur2.getMonth()+1).padStart(2,'0')+'-'+String(cur2.getDate()).padStart(2,'0');
          if (ds2.startsWith(currentMonthStr)) counts[track]++;
          cur2.setDate(cur2.getDate()+1);
        }
      } else if (startDate.startsWith(currentMonthStr)) {
        counts[track]++;
      }
    });
    // 연간 누적 계산
    var yearStr = String(plannerYear);
    var yearCounts = { writing:0, english:0, study:0, work:0, personal:0, vacation:0 };
    var yearHolidays = getKoreanHolidays(plannerYear);
    plannerData.forEach(function(row) {
      var sd = (row[0]||'').toString();
      var ed = (row[5]||sd).toString();
      var track = CAT_TRACK[(row[2]||'').trim()];
      if (!track || !sd.startsWith(yearStr)) return;
      if (track === 'vacation') {
        var c = new Date(sd+'T00:00:00'), e = new Date(ed+'T00:00:00');
        while (c <= e) {
          var cds = c.getFullYear()+'-'+String(c.getMonth()+1).padStart(2,'0')+'-'+String(c.getDate()).padStart(2,'0');
          if (cds.startsWith(yearStr) && c.getDay()!==0 && c.getDay()!==6 && !yearHolidays[cds]) yearCounts[track]++;
          c.setDate(c.getDate()+1);
        }
      } else if (ed > sd) {
        var c2 = new Date(sd+'T00:00:00'), e2 = new Date(ed+'T00:00:00');
        while (c2 <= e2) { var cds2=c2.getFullYear()+'-'+String(c2.getMonth()+1).padStart(2,'0')+'-'+String(c2.getDate()).padStart(2,'0'); if(cds2.startsWith(yearStr)) yearCounts[track]++; c2.setDate(c2.getDate()+1); }
      } else { yearCounts[track]++; }
    });

    const daysInMonth = new Date(plannerYear, plannerMonth+1, 0).getDate();
    Object.keys(counts).forEach(function(track) {
      const el = document.getElementById('planner-track-'+track);
      const bar = document.getElementById('planner-bar-'+track);
      const yearEl = document.getElementById('planner-year-'+track);
      if (el) el.textContent = counts[track];
      if (bar) bar.style.width = Math.min(Math.round((counts[track]/daysInMonth)*100), 100) + '%';
      if (yearEl) yearEl.textContent = yearCounts[track] + ' /년';
    });
  }

  function updateCalLeaveTracker() {
    var yr = String(plannerYear);
    var used = 0;
    plannerData.forEach(function(row) {
      if (row[2] !== '연차') return;
      var d = (row[0] || '').toString();
      if (!d.startsWith(yr)) return;
      var notes = (row[4] || '').toString();
      var m = notes.match(/^leave:([\d.]+)/);
      if (m) { used += parseFloat(m[1]); }
      else { used += 1; }
    });
    // plannerYear 기준 총계: 캐시 우선, 없으면 백그라운드 fetch 후 재호출
    var total;
    if (_leaveTotalByYear[plannerYear] !== undefined) {
      total = _leaveTotalByYear[plannerYear];
    } else {
      // matrixYear와 같으면 _leaveTotal 사용 (이미 loadLeaveSettings로 로드됐을 수 있음)
      total = (plannerYear === matrixYear) ? (_leaveTotal || 17) : 17;
      // 정확한 값 fetch 후 재렌더
      getLeaveTotalForYear(plannerYear).then(function() { updateCalLeaveTracker(); });
    }
    var left = total - used;
    var usedEl = document.getElementById('cal-leave-used');
    var totalEl = document.getElementById('cal-leave-total');
    var leftEl = document.getElementById('cal-leave-left');
    if (usedEl) usedEl.textContent = used % 1 === 0 ? used : used.toFixed(1);
    if (totalEl) totalEl.textContent = total % 1 === 0 ? total : total.toFixed(1);
    if (leftEl) {
      leftEl.textContent = left % 1 === 0 ? left : left.toFixed(1);
      leftEl.style.color = left < 0 ? '#ef4444' : '#4f46e5';
    }
    var tracker = document.getElementById('cal-leave-tracker');
    if (tracker) tracker.title = plannerYear + '년 연차 현황: ' + used + '일 사용, ' + left + '일 남음';

    // 특별휴가 집계
    var specialUsed = 0;
    plannerData.forEach(function(row) {
      if (row[2] !== '특별휴가') return;
      var d = (row[0] || '').toString();
      if (!d.startsWith(yr)) return;
      var notes = (row[4] || '').toString();
      var sm = notes.match(/^leave:([\d.]+)/);
      if (sm) { specialUsed += parseFloat(sm[1]); }
      else { specialUsed += 1; }
    });
    var spEl = document.getElementById('cal-special-used');
    var spTracker = document.getElementById('cal-special-tracker');
    if (spEl) spEl.textContent = specialUsed % 1 === 0 ? specialUsed : specialUsed.toFixed(1);
    if (spTracker) {
      spTracker.style.display = specialUsed > 0 ? '' : 'none';
      spTracker.title = plannerYear + '년 특별휴가: ' + specialUsed + '일 사용';
    }
  }

  function prevMonth() {
    plannerMonth--;
    if (plannerMonth < 0) { plannerMonth = 11; plannerYear--; }
    renderCalendar();
    updatePlannerTracks();
  }

  function nextMonth() {
    plannerMonth++;
    if (plannerMonth > 11) { plannerMonth = 0; plannerYear++; }
    renderCalendar();
    updatePlannerTracks();
  }

  function _initCalNavSelects() {
    var ySel = document.getElementById('cal-year-select');
    var mSel = document.getElementById('cal-month-select');
    if (!ySel || !mSel) return;
    var curY = new Date().getFullYear();
    ySel.innerHTML = '';
    for (var y = curY - 3; y <= curY + 5; y++) {
      ySel.innerHTML += '<option value="' + y + '">' + y + '</option>';
    }
    mSel.innerHTML = '';
    for (var m = 0; m < 12; m++) {
      mSel.innerHTML += '<option value="' + m + '">' + (m + 1) + '월</option>';
    }
    _syncCalNavSelects();
  }
  function _syncCalNavSelects() {
    var ySel = document.getElementById('cal-year-select');
    var mSel = document.getElementById('cal-month-select');
    if (ySel) ySel.value = plannerYear;
    if (mSel) mSel.value = plannerMonth;
  }
  function calNavJump() {
    var ySel = document.getElementById('cal-year-select');
    var mSel = document.getElementById('cal-month-select');
    if (ySel) plannerYear = parseInt(ySel.value);
    if (mSel) plannerMonth = parseInt(mSel.value);
    renderCalendar();
    updatePlannerTracks();
  }
  function calNavToday() {
    var now = new Date();
    plannerYear = now.getFullYear();
    plannerMonth = now.getMonth();
    renderCalendar();
    updatePlannerTracks();
  }

  function toggleLeaveDay() {
    var cat = document.getElementById('p-category').value;
    var wrap = document.getElementById('p-leave-day-wrap');
    var isLeave = cat === '연차' || cat === '특별휴가';
    wrap.style.display = isLeave ? 'block' : 'none';
    if (isLeave) calcLeaveDays();
    var bdayWrap = document.getElementById('p-birthday-wrap');
    bdayWrap.style.display = cat === '생일' ? 'block' : 'none';
  }

  // ===== REUSABLE CUSTOM DROPDOWN (AtelierDropdown) =====
  var _atelierDropdowns = {};

  function AtelierDropdown(cfg) {
    // cfg: { id, containerId, hiddenSelectId, icon, options:[{value,label,dot?,emoji?}], onSelect }
    var self = this;
    self.id = cfg.id;
    self.options = cfg.options;
    self.onSelect = cfg.onSelect || function(){};
    self.hiddenSelect = document.getElementById(cfg.hiddenSelectId);
    self.container = document.getElementById(cfg.containerId);
    self.focusIdx = -1;
    self.isOpen = false;

    // Build trigger
    var trigId = cfg.id + '-trigger';
    var popId = cfg.id + '-popover';
    self.container.innerHTML =
      '<button type="button" id="' + trigId + '" role="combobox" aria-haspopup="listbox" aria-expanded="false" aria-label="' + (cfg.ariaLabel||'선택') + '"' +
      ' class="w-full flex items-center gap-2.5 px-3 py-2.5 rounded-xl bg-white border border-slate-200 hover:border-[#6b38d4]/40 focus:outline-none focus:ring-2 focus:ring-[#6b38d4]/30 focus:border-[#6b38d4]/40 transition-all text-left cursor-pointer">' +
      (cfg.icon ? '<span class="material-symbols-outlined" style="font-size:18px;color:#94a3b8">' + cfg.icon + '</span>' : '') +
      '<span id="' + cfg.id + '-dot" class="w-2.5 h-2.5 rounded-full shrink-0" style="' + (cfg.options[0].dot ? 'background:' + cfg.options[0].dot : 'display:none') + '"></span>' +
      '<span id="' + cfg.id + '-label" class="flex-1 text-sm font-bold text-[#1d1a23]"></span>' +
      '<span class="material-symbols-outlined text-slate-400" style="font-size:16px">expand_more</span>' +
      '</button>' +
      '<ul id="' + popId + '" role="listbox" aria-label="' + (cfg.ariaLabel||'목록') + '" class="bg-white rounded-xl shadow-lg border border-slate-100 p-1" style="display:none;list-style:none;margin:0;padding:4px;position:fixed;z-index:9999"></ul>';

    self.trigger = document.getElementById(trigId);
    self.popover = document.getElementById(popId);

    self.syncTrigger = function(value) {
      var opt = self.options.find(function(o){ return o.value === value; }) || self.options[0];
      var dot = document.getElementById(self.id + '-dot');
      var label = document.getElementById(self.id + '-label');
      if (opt.dot) { dot.style.background = opt.dot; dot.style.display = ''; } else { dot.style.display = 'none'; }
      var prefix = opt.emoji ? opt.emoji + ' ' : '';
      label.textContent = prefix + opt.label;
    };

    self.renderOptions = function() {
      var current = self.hiddenSelect.value;
      var html = '';
      for (var i = 0; i < self.options.length; i++) {
        var opt = self.options[i];
        var isSelected = opt.value === current;
        var isFocused = i === self.focusIdx;
        var bg = isFocused ? 'background:#6b38d4;color:#fff;' : (isSelected && !isFocused ? '' : '');
        var dotBorder = isFocused ? 'border:2px solid rgba(255,255,255,0.6);' : 'border:2px solid transparent;';
        var prefix = opt.emoji ? '<span style="font-size:13px;margin-right:2px">' + opt.emoji + '</span> ' : '';
        var dotHtml = opt.dot ? '<span class="w-3 h-3 rounded-full shrink-0" style="background:' + opt.dot + ';' + dotBorder + '"></span>' : '';
        html += '<li role="option" id="' + self.id + '-opt-' + i + '" aria-selected="' + isSelected + '" data-idx="' + i + '"' +
          ' class="flex items-center gap-2.5 px-3 py-2 rounded-lg cursor-pointer" style="' + bg + '">' +
          dotHtml + prefix + '<span class="text-sm font-bold">' + opt.label + '</span>' +
          (isSelected ? '<span class="material-symbols-outlined ml-auto" style="font-size:16px">check</span>' : '') +
          '</li>';
      }
      self.popover.innerHTML = html;
      // Mouse events
      var items = self.popover.querySelectorAll('li');
      items.forEach(function(li) {
        li.addEventListener('mouseenter', function() {
          self.focusIdx = parseInt(this.dataset.idx);
          // Update visual focus without re-rendering DOM
          items.forEach(function(el) {
            var idx = parseInt(el.dataset.idx);
            if (idx === self.focusIdx) {
              el.style.background = '#6b38d4'; el.style.color = '#fff';
            } else {
              el.style.background = ''; el.style.color = '';
            }
          });
        });
        li.addEventListener('click', function(e) {
          e.stopPropagation();
          self.selectByIndex(parseInt(this.dataset.idx));
        });
      });
      // Update aria-activedescendant
      if (self.focusIdx >= 0) {
        self.trigger.setAttribute('aria-activedescendant', self.id + '-opt-' + self.focusIdx);
      } else {
        self.trigger.removeAttribute('aria-activedescendant');
      }
    };

    self.open = function() {
      if (self.isOpen) return;
      self.isOpen = true;
      // Set focusIdx to current selected
      var cur = self.hiddenSelect.value;
      self.focusIdx = 0;
      for (var i = 0; i < self.options.length; i++) {
        if (self.options[i].value === cur) { self.focusIdx = i; break; }
      }
      self.renderOptions();
      // Position fixed popover relative to trigger
      var rect = self.trigger.getBoundingClientRect();
      self.popover.style.left = rect.left + 'px';
      self.popover.style.width = rect.width + 'px';
      self.popover.style.top = (rect.bottom + 4) + 'px';
      self.popover.style.display = '';
      self.trigger.setAttribute('aria-expanded', 'true');
    };

    self.close = function() {
      if (!self.isOpen) return;
      self.isOpen = false;
      self.popover.style.display = 'none';
      self.trigger.setAttribute('aria-expanded', 'false');
      self.trigger.removeAttribute('aria-activedescendant');
    };

    self.toggle = function() { self.isOpen ? self.close() : self.open(); };

    self.selectByIndex = function(idx) {
      if (idx < 0 || idx >= self.options.length) return;
      var opt = self.options[idx];
      self.hiddenSelect.value = opt.value;
      self.syncTrigger(opt.value);
      self.close();
      self.onSelect(opt.value);
    };

    self.moveFocus = function(delta) {
      self.focusIdx = Math.max(0, Math.min(self.options.length - 1, self.focusIdx + delta));
      self.renderOptions();
      // Scroll into view
      var el = document.getElementById(self.id + '-opt-' + self.focusIdx);
      if (el) el.scrollIntoView({ block: 'nearest' });
    };

    // Trigger click
    self.trigger.addEventListener('click', function(e) { e.stopPropagation(); self.toggle(); });

    // Keyboard on trigger
    self.trigger.addEventListener('keydown', function(e) {
      if (!self.isOpen) {
        if (e.key === 'Enter' || e.key === ' ' || e.key === 'ArrowDown') {
          e.preventDefault();
          self.open();
          return;
        }
        return;
      }
      switch (e.key) {
        case 'ArrowDown': e.preventDefault(); self.moveFocus(1); break;
        case 'ArrowUp': e.preventDefault(); self.moveFocus(-1); break;
        case 'Home': e.preventDefault(); self.focusIdx = 0; self.renderOptions(); break;
        case 'End': e.preventDefault(); self.focusIdx = self.options.length - 1; self.renderOptions(); break;
        case 'Enter': case ' ': e.preventDefault(); self.selectByIndex(self.focusIdx); break;
        case 'Escape': e.preventDefault(); self.close(); break;
        case 'Tab': self.close(); break;
        default:
          // Type-ahead search
          if (e.key.length === 1) {
            var ch = e.key.toLowerCase();
            for (var ti = 0; ti < self.options.length; ti++) {
              if (self.options[ti].label.toLowerCase().startsWith(ch) || self.options[ti].label.charAt(0) === e.key) {
                self.focusIdx = ti;
                self.renderOptions();
                break;
              }
            }
          }
      }
    });

    // Close on outside click (check both container and fixed popover)
    document.addEventListener('click', function(e) {
      if (!self.container.contains(e.target) && !self.popover.contains(e.target)) self.close();
    });

    // Close on scroll (fixed popover would misalign)
    var scrollParent = self.container.closest('.atl-modal-body') || self.container.closest('[style*="overflow"]');
    if (scrollParent) {
      scrollParent.addEventListener('scroll', function() { self.close(); });
    }

    // Initial sync
    self.syncTrigger(self.hiddenSelect.value);
    _atelierDropdowns[self.id] = self;
  }

