  function cleanCityName(name) {
    if (!name) return '';
    // "Oświęcim (아우슈비츠)" → "Oświęcim"
    var cleaned = name.replace(/\s*\(.*?\)/g, '').trim();
    // "Plitvička / Zagreb" → 첫 번째 이름 사용
    if (cleaned.indexOf('/') >= 0) cleaned = cleaned.split('/')[0].trim();
    // 한글만 남은 경우 원래 이름의 영문 부분 추출
    if (/^[\uAC00-\uD7A3\s]+$/.test(cleaned) && /[a-zA-Z]/.test(name)) {
      cleaned = name.replace(/[\uAC00-\uD7A3\s()]/g, '').trim();
    }
    return cleaned || name;
  }

  async function geocodeCity(cityName) {
    if (_geocodeCache[cityName]) return _geocodeCache[cityName];
    var searchName = cleanCityName(cityName);
    if (!searchName) return null;
    try {
      var res = await fetch('https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(searchName) + '&count=1&language=en');
      var data = await res.json();
      if (data.results && data.results.length > 0) {
        var r = data.results[0];
        _geocodeCache[cityName] = { lat: r.latitude, lng: r.longitude, name: r.name };
        return _geocodeCache[cityName];
      }
      // 영어로 못 찾으면 한국어로 재시도
      if (searchName !== cityName) {
        res = await fetch('https://geocoding-api.open-meteo.com/v1/search?name=' + encodeURIComponent(cityName.split('(')[0].split('/')[0].trim()) + '&count=1&language=ko');
        data = await res.json();
        if (data.results && data.results.length > 0) {
          var r2 = data.results[0];
          _geocodeCache[cityName] = { lat: r2.latitude, lng: r2.longitude, name: r2.name };
          return _geocodeCache[cityName];
        }
      }
    } catch(e) { console.warn('Geocode failed:', e); }
    return null;
  }

  async function fetchWeather(cityName, dateStr) {
    var banner = document.getElementById('weather-banner');
    if (!banner) return;

    var cacheKey = cityName + ':' + dateStr;
    if (_weatherCache[cacheKey]) { showWeatherBanner(_weatherCache[cacheKey]); return; }

    var geo = await geocodeCity(cityName);
    if (!geo) { banner.classList.add('hidden'); return; }

    try {
      var today = new Date();
      var target = new Date(dateStr + 'T00:00:00');
      var diffDays = Math.round((target - today) / (1000*60*60*24));

      var url, isHistorical = false;
      if (diffDays >= -2 && diffDays <= 15) {
        // 최근~16일 이내 예보
        url = 'https://api.open-meteo.com/v1/forecast?latitude=' + geo.lat + '&longitude=' + geo.lng +
          '&daily=weathercode,temperature_2m_max,temperature_2m_min,precipitation_probability_max,windspeed_10m_max' +
          '&timezone=auto&start_date=' + dateStr + '&end_date=' + dateStr;
      } else if (diffDays < -2) {
        // 과거 날씨 (실제 기록)
        url = 'https://archive-api.open-meteo.com/v1/archive?latitude=' + geo.lat + '&longitude=' + geo.lng +
          '&daily=weathercode,temperature_2m_max,temperature_2m_min,windspeed_10m_max' +
          '&timezone=auto&start_date=' + dateStr + '&end_date=' + dateStr;
      } else {
        // 16일 이후 미래: 작년 같은 날짜 기후 참고
        isHistorical = true;
        var lastYear = new Date(target); lastYear.setFullYear(lastYear.getFullYear() - 1);
        var lyStr = lastYear.getFullYear()+'-'+String(lastYear.getMonth()+1).padStart(2,'0')+'-'+String(lastYear.getDate()).padStart(2,'0');
        url = 'https://archive-api.open-meteo.com/v1/archive?latitude=' + geo.lat + '&longitude=' + geo.lng +
          '&daily=weathercode,temperature_2m_max,temperature_2m_min,windspeed_10m_max' +
          '&timezone=auto&start_date=' + lyStr + '&end_date=' + lyStr;
      }

      var res = await fetch(url);
      var data = await res.json();
      if (data.daily && data.daily.time && data.daily.time.length > 0) {
        var w = {
          code: data.daily.weathercode[0],
          tempMax: Math.round(data.daily.temperature_2m_max[0]),
          tempMin: Math.round(data.daily.temperature_2m_min[0]),
          rain: data.daily.precipitation_probability_max ? (data.daily.precipitation_probability_max[0] || 0) : null,
          wind: Math.round(data.daily.windspeed_10m_max[0]),
          historical: isHistorical,
          city: geo.name
        };
        _weatherCache[cacheKey] = w;
        showWeatherBanner(w);
      } else {
        banner.classList.add('hidden');
      }
    } catch(e) {
      console.warn('Weather fetch failed:', e);
      banner.classList.add('hidden');
    }
  }

  function showWeatherBanner(w) {
    var banner = document.getElementById('weather-banner');
    if (!banner) return;
    var wmo = WMO_WEATHER[w.code] || WMO_WEATHER[2];
    banner.style.background = wmo.bg;
    banner.classList.remove('hidden');
    document.getElementById('weather-icon').textContent = wmo.icon;
    document.getElementById('weather-temp').textContent = w.tempMax + '°';
    document.getElementById('weather-desc').textContent = wmo.desc;
    document.getElementById('weather-high-low').innerHTML = '<span class="text-rose-500">↑' + w.tempMax + '°</span> <span class="text-blue-500">↓' + w.tempMin + '°</span>' + (w.historical ? ' <span class="text-slate-400">(작년 참고)</span>' : '');
    var extraParts = [];
    if (w.rain !== null) extraParts.push('💧 ' + w.rain + '%');
    extraParts.push('💨 ' + w.wind + 'km/h');
    document.getElementById('weather-extra').innerHTML = extraParts.join(' · ');
  }

  function prevDay() {
    if (currentDayIndex > 0) { currentDayIndex--; renderDayView(); }
  }
  function nextDay() {
    var dayMap = getDayMap();
    if (currentDayIndex < dayMap.length - 1) { currentDayIndex++; renderDayView(); }
  }

  // ── 데스크탑 주간 그리드 뷰 (엑셀 스타일, lg 이상) ──
  var currentWeekChunkStart = 0;
  var WEEK_CHUNK_SIZE = 5;

  function syncWeekChunkToCurrentDay() {
    var chunkOf = Math.floor(currentDayIndex / WEEK_CHUNK_SIZE) * WEEK_CHUNK_SIZE;
    currentWeekChunkStart = chunkOf;
  }

  function renderWeekView() {
    var grid = document.getElementById('journey-week-grid');
    if (!grid) return;
    var dayMap = getDayMap();
    if (!dayMap.length) {
      grid.innerHTML = '<div class="text-xs text-slate-400 py-2">도시를 추가하면 일차가 자동 생성돼!</div>';
      var lbl0 = document.getElementById('journey-week-chunk-label');
      if (lbl0) lbl0.textContent = '—';
      var rng0 = document.getElementById('journey-week-range');
      if (rng0) rng0.textContent = '—';
      return;
    }
    // 청크 클램프 (마지막 청크는 잔여 일수만큼만 — 5일 안 채워도 그대로)
    if (currentWeekChunkStart < 0) currentWeekChunkStart = 0;
    if (currentWeekChunkStart >= dayMap.length) currentWeekChunkStart = Math.max(0, dayMap.length - 1);

    var chunkEnd = Math.min(currentWeekChunkStart + WEEK_CHUNK_SIZE, dayMap.length);
    var chunk = dayMap.slice(currentWeekChunkStart, chunkEnd);

    // 라벨
    var label = (currentWeekChunkStart + 1) + '~' + chunkEnd + '일차 (' + dayMap.length + '일 중)';
    var lbl = document.getElementById('journey-week-chunk-label');
    if (lbl) lbl.textContent = label;
    var rng = document.getElementById('journey-week-range');
    if (rng) {
      var first = chunk[0].date || '';
      var last = chunk[chunk.length - 1].date || '';
      rng.textContent = first + (first !== last && last ? ' ~ ' + last : '');
    }

    grid.innerHTML = chunk.map(function(entry, idx) {
      var actualIdx = currentWeekChunkStart + idx;
      var dayNum = entry.day;
      var dateStr = entry.date;
      var cityName = entry.cityName || '';

      // 일정 + 시간 있는 기념품(특정 장소 방문)을 함께 표시
      var items = journeyData.filter(function(d){
        if ((d.date||'') !== dateStr) return false;
        if (d.type === '일정') return true;
        if (d.type === '기념품' && d.time) return true; // 시간 있는 기념품은 일정처럼 끼워넣기
        return false;
      });
      items.sort(function(a,b){ return (a.time||'').localeCompare(b.time||''); });

      var weekday = '';
      if (dateStr) {
        var d = new Date(dateStr);
        weekday = ['일','월','화','수','목','금','토'][d.getDay()];
      }
      var isCurrent = (actualIdx === currentDayIndex);
      var headerBg = isCurrent
        ? 'background:linear-gradient(135deg,#6366f1,#a855f7);color:white;'
        : 'background:linear-gradient(135deg,#e0e7ff,#fce7f3);color:#4338ca;';

      // 당일치기 도시 (숙박 도시와 다른 일정 도시들)
      var dayTrips = getDayTripCities(items, cityName);
      var baseN2 = _normCityKey(cityName);

      // ─── 미니 패널 (교통편 / 사전예약 / 쇼핑) 계산 ───
      var miniPanelHtml = '';
      // (1) 교통편 가이드 — 이 도시 첫날만
      var thisCity = (citiesData||[]).find(function(c){ return c.name === cityName; });
      if (thisCity && thisCity.transit_guide && dateStr === thisCity.start_date) {
        var tgSafe = String(thisCity.transit_guide).replace(/</g,'&lt;').replace(/\n/g,' · ');
        miniPanelHtml += '<div class="mb-2 p-2 rounded-lg border-l-[3px]" style="background:#eef2ff;border-left-color:#6366f1">' +
          '<div class="flex items-start gap-1.5">' +
            '<span class="material-symbols-outlined text-indigo-500" style="font-size:13px;margin-top:1px">directions_transit</span>' +
            '<div class="flex-1 min-w-0">' +
              '<div class="text-[9px] font-black uppercase tracking-widest text-indigo-600 mb-0.5">' + cityName + ' 교통편</div>' +
              '<div class="text-[11px] text-slate-700 leading-snug">' + tgSafe + '</div>' +
            '</div>' +
          '</div>' +
        '</div>';
      }
      // (2) 사전 예약 미니 패널은 제거 — 일정 카드 자체에 빨간색으로 강조되고 권장 예약 시점도 표시되므로 중복 방지
      // (3) 쇼핑 가이드 — 시간 없는 기념품만 (시간 있는 건 위에서 일정에 통합됨)
      var sourceSouvenirs = journeyData.filter(function(j){
        if (j.type !== '기념품') return false;
        if (j.time) return false; // 시간 있는 건 일정 리스트에 들어가므로 제외
        if (j.date && j.date === dateStr) return true;
        // 도시 부분 매칭 ('Frankfurt am Main' ⊃ 'Frankfurt', '독일 드레스덴' ⊃ '드레스덴')
        if (!j.date && j.city && cityName) {
          var jn = _normCityKey(j.city), cn = _normCityKey(cityName);
          if (jn && cn && (jn === cn || jn.indexOf(cn) >= 0 || cn.indexOf(jn) >= 0)) return true;
        }
        return false;
      });
      if (sourceSouvenirs.length > 0) {
        miniPanelHtml += '<div class="mb-2 p-2.5 rounded-lg border-l-[3px]" style="background:#fff7ed;border-left-color:#f97316">' +
          '<div class="flex items-center gap-1.5 mb-1.5">' +
            '<span class="material-symbols-outlined text-orange-600" style="font-size:13px">shopping_bag</span>' +
            '<span class="text-[9px] font-black uppercase tracking-widest text-orange-700">쇼핑 ' + sourceSouvenirs.length + '개 (장소 자유)</span>' +
          '</div>' +
          '<ul class="space-y-1.5">' +
            sourceSouvenirs.map(function(s){
              var titleSafe = String(s.title||'').replace(/</g,'&lt;');
              var descSafe = String(s.description||'').replace(/</g,'&lt;');
              var price = s.amount ? ' <span class="text-[10px] text-orange-600 font-bold">€' + s.amount + '</span>' : '';
              var titlePart = titleSafe ? '<span class="font-bold text-slate-900">' + titleSafe + '</span>' : '';
              var descPart = descSafe ? '<span class="text-slate-600"> — ' + descSafe + '</span>' : '';
              return '<li class="text-[11px] leading-snug pl-2 border-l border-orange-200">' + titlePart + descPart + price + '</li>';
            }).join('') +
          '</ul>' +
        '</div>';
      }

      var itemsHtml = items.length === 0
        ? '<div class="text-xs text-slate-400 py-4 italic text-center">일정 없음</div>'
        : items.map(function(item){
            // ─── 편집 모드 ───
            if (_weekEditingId === item._id) {
              var curColor = isReservationItem(item) ? 'pink' : (isPinnedItem(item) ? 'mint' : 'none');
              var iid = item._id;
              var safeTime = (item.time||'').replace(/"/g,'&quot;');
              var safeEnd = (item.end_time||'').replace(/"/g,'&quot;');
              var safeTitle = (item.title||'').replace(/"/g,'&quot;');
              var safeCity = (item.city||'').replace(/"/g,'&quot;');
              var safeDesc = (item.description||'').replace(/"/g,'&quot;');
              return '<div class="py-3 px-1.5 border-b border-slate-100 last:border-b-0 bg-indigo-50/50 -mx-1 px-2 border-l-[3px] border-indigo-400" onclick="event.stopPropagation()">' +
                '<div class="flex items-center gap-1 mb-1.5">' +
                  '<input id="we-time-' + iid + '" type="text" value="' + safeTime + '" placeholder="09:00" class="w-14 text-[11px] font-bold text-indigo-700 bg-white border border-indigo-200 rounded px-1.5 py-0.5 outline-none focus:border-indigo-500 text-center"/>' +
                  '<span class="text-[9px] text-slate-400">-</span>' +
                  '<input id="we-end-' + iid + '" type="text" value="' + safeEnd + '" placeholder="끝" class="w-14 text-[11px] font-bold text-indigo-700 bg-white border border-indigo-200 rounded px-1.5 py-0.5 outline-none focus:border-indigo-500 text-center"/>' +
                '</div>' +
                '<input id="we-title-' + iid + '" type="text" value="' + safeTitle + '" placeholder="제목" class="w-full text-[13px] font-semibold bg-white border border-indigo-200 rounded px-2 py-1 outline-none focus:border-indigo-500 mb-1.5"/>' +
                '<div class="flex items-center gap-1 mb-1.5">' +
                  '<span class="text-[10px] text-amber-600 font-bold">📍</span>' +
                  '<input id="we-city-' + iid + '" type="text" value="' + safeCity + '" placeholder="' + (cityName||'행선지') + '" class="w-full text-[11px] bg-white border border-amber-200 rounded px-1.5 py-0.5 outline-none focus:border-amber-500 text-amber-700"/>' +
                '</div>' +
                '<textarea id="we-desc-' + iid + '" placeholder="내용 (Ctrl+Enter 저장)" rows="2" class="w-full text-[11px] bg-white border border-indigo-200 rounded px-1.5 py-1 outline-none focus:border-indigo-500 resize-none mb-1.5" onkeydown="if((event.metaKey||event.ctrlKey)&&event.key===\'Enter\'){event.preventDefault();saveWeekEdit(\'' + iid + '\')}">' + safeDesc + '</textarea>' +
                // 색상 선택
                '<div class="flex items-center gap-1 mb-2 text-[10px] font-bold">' +
                  '<span class="text-slate-500 mr-1">색상:</span>' +
                  '<label class="cursor-pointer flex items-center gap-0.5 px-1.5 py-0.5 rounded border ' + (curColor==='none' ? 'bg-slate-100 border-slate-400' : 'bg-white border-slate-200') + '">' +
                    '<input type="radio" name="we-color-' + iid + '" value="none" class="hidden" ' + (curColor==='none'?'checked':'') + ' onchange="this.closest(\'div\').querySelectorAll(\'label\').forEach(function(l){l.className=l.className.replace(/bg-\\\\S+/g,\'\').replace(/border-(slate|emerald|rose)-\\\\d+/g,\'\').trim()+\' bg-white border-slate-200\'});this.closest(\'label\').className=this.closest(\'label\').className.replace(/bg-white/,\'bg-slate-100\').replace(/border-slate-200/,\'border-slate-400\')"/>' +
                    '<span>⚪ 일반</span>' +
                  '</label>' +
                  '<label class="cursor-pointer flex items-center gap-0.5 px-1.5 py-0.5 rounded border ' + (curColor==='mint' ? 'bg-emerald-100 border-emerald-400' : 'bg-white border-slate-200') + '">' +
                    '<input type="radio" name="we-color-' + iid + '" value="mint" class="hidden" ' + (curColor==='mint'?'checked':'') + ' onchange="this.closest(\'div\').querySelectorAll(\'label\').forEach(function(l){l.className=l.className.replace(/bg-\\\\S+/g,\'\').replace(/border-(slate|emerald|rose)-\\\\d+/g,\'\').trim()+\' bg-white border-slate-200\'});this.closest(\'label\').className=this.closest(\'label\').className.replace(/bg-white/,\'bg-emerald-100\').replace(/border-slate-200/,\'border-emerald-400\')"/>' +
                    '<span>📌 고정</span>' +
                  '</label>' +
                  '<label class="cursor-pointer flex items-center gap-0.5 px-1.5 py-0.5 rounded border ' + (curColor==='pink' ? 'bg-rose-100 border-rose-400' : 'bg-white border-slate-200') + '">' +
                    '<input type="radio" name="we-color-' + iid + '" value="pink" class="hidden" ' + (curColor==='pink'?'checked':'') + ' onchange="this.closest(\'div\').querySelectorAll(\'label\').forEach(function(l){l.className=l.className.replace(/bg-\\\\S+/g,\'\').replace(/border-(slate|emerald|rose)-\\\\d+/g,\'\').trim()+\' bg-white border-slate-200\'});this.closest(\'label\').className=this.closest(\'label\').className.replace(/bg-white/,\'bg-rose-100\').replace(/border-slate-200/,\'border-rose-400\')"/>' +
                    '<span>🎫 예약</span>' +
                  '</label>' +
                '</div>' +
                // 버튼
                '<div class="flex gap-1 justify-between">' +
                  '<button onclick="deleteWeekItem(\'' + iid + '\')" class="px-2 py-1 rounded text-[10px] font-bold text-rose-500 hover:bg-rose-50">🗑️ 삭제</button>' +
                  '<div class="flex gap-1">' +
                    '<button onclick="cancelWeekEdit()" class="px-2 py-1 rounded text-[10px] font-bold text-slate-500 hover:bg-slate-100">취소</button>' +
                    '<button onclick="saveWeekEdit(\'' + iid + '\')" class="px-2 py-1 rounded bg-indigo-600 text-white text-[10px] font-bold hover:bg-indigo-700 flex items-center gap-0.5">' +
                      '<span class="material-symbols-outlined" style="font-size:12px">check</span> 저장' +
                    '</button>' +
                  '</div>' +
                '</div>' +
              '</div>';
            }
            // ─── 일반 표시 모드 ───
            var time = item.time || '';
            var endTime = item.end_time ? '-' + item.end_time : '';
            var title = (item.title || '').replace(/</g,'&lt;');
            var desc = (item.description || '').replace(/</g,'&lt;');
            var isSouvenir = (item.type === '기념품');
            var pinned = !isSouvenir && isPinnedItem(item);
            var reserv = !isSouvenir && isReservationItem(item);
            // 일정 city 가 숙박과 다르면 작은 칩
            var itemCityRaw = (item.city||'').trim();
            var cityChip = '';
            if (itemCityRaw) {
              var iN = _normCityKey(itemCityRaw);
              if (iN && iN !== baseN2) {
                cityChip = '<span class="inline-block text-[10px] font-bold px-1.5 py-0.5 rounded-md bg-amber-100 text-amber-700 mr-1.5 align-middle">📍' + _displayCityShort(itemCityRaw).replace(/</g,'&lt;') + '</span>';
              }
            }
            // 우선순위: 기념품(주황) > 예약(핑크) > 시간고정(민트) > 일반
            var itemBg, timeC, badge;
            if (isSouvenir) {
              itemBg = 'bg-orange-50 border-l-[3px] border-orange-400 -ml-2 pl-3 pr-2';
              timeC = 'text-orange-700';
              badge = ' <span class="text-[10px] ml-0.5">🛍</span>';
            } else if (reserv) {
              itemBg = 'bg-rose-50 border-l-[3px] border-rose-400 -ml-2 pl-3 pr-2';
              timeC = 'text-rose-700';
              badge = ' <span class="text-[10px] ml-0.5">🎫</span>';
            } else if (pinned) {
              itemBg = 'bg-emerald-50 border-l-[3px] border-emerald-400 -ml-2 pl-3 pr-2';
              timeC = 'text-emerald-700';
              badge = ' <span class="text-[10px] ml-0.5">📌</span>';
            } else {
              itemBg = '';
              timeC = 'text-indigo-600';
              badge = '';
            }
            // 기념품일 때 카드 내용 다르게 (제목 = 품목, 부제 = 장소/대상, 가격 표시)
            var renderTitle, renderDesc;
            if (isSouvenir) {
              renderTitle = (item.description || '쇼핑').replace(/</g,'&lt;');
              var meta = [];
              if (item.location) meta.push('📍 ' + String(item.location).replace(/</g,'&lt;'));
              if (item.title) meta.push('대상: ' + String(item.title).replace(/</g,'&lt;'));
              if (item.amount) meta.push('€' + item.amount);
              renderDesc = meta.length ? meta.join(' · ') : '';
            } else {
              renderTitle = title;
              renderDesc = desc;
            }
            var safeId = (item._id||'').replace(/'/g,"\\'");
            // 사전 예약 일정이면 권장 예약 시점 라인 추가
            var prebookLine = '';
            if (reserv) {
              var info = _getPrebookLeadInfo(item);
              if (info && info.recDate) {
                prebookLine = '<div class="mt-1.5 px-2 py-1 rounded bg-rose-100/70 border border-rose-200 flex items-center gap-1 text-[10px]"><span class="material-symbols-outlined text-rose-600" style="font-size:11px">schedule</span><span class="text-rose-700 font-bold">' + info.label + ' 예약 (~' + info.recDate + ')</span></div>';
              }
            }
            return '<div class="py-3 px-1.5 border-b border-slate-100 last:border-b-0 cursor-pointer hover:bg-indigo-50/30 transition-colors ' + itemBg + '" onclick="event.stopPropagation();' + (isSouvenir ? '' : 'startWeekEdit(\'' + safeId + '\')') + '" title="' + (isSouvenir ? '쇼핑 일정' : '클릭하여 편집') + '">' +
              (time ? '<div class="text-[11px] font-bold ' + timeC + ' mb-1.5" style="letter-spacing:0.04em">' + time + endTime + badge + '</div>' : '') +
              '<div class="text-[13px] font-semibold text-slate-800 mb-1" style="line-height:1.5;letter-spacing:-0.01em">' + cityChip + (renderTitle || '(제목 없음)') + '</div>' +
              (renderDesc ? '<div class="text-[11px] text-slate-500" style="line-height:1.6;letter-spacing:0.01em;white-space:pre-line;word-break:keep-all;overflow-wrap:break-word">' + renderDesc + '</div>' : '') +
              prebookLine +
            '</div>';
          }).join('');

      // 헤더: 도시명 + 당일치기 작은 라인
      var headerCityHtml = '<div class="text-sm font-bold mt-1" style="letter-spacing:-0.01em">' + dayNum + '일차' + (cityName ? ' · ' + cityName : '') + '</div>';
      if (dayTrips.length > 0) {
        var tripsTxt = dayTrips.map(function(c){ return _displayCityShort(c).replace(/</g,'&lt;'); }).join(', ');
        var dtColor = isCurrent ? 'rgba(255,255,255,0.85)' : '#b45309';
        headerCityHtml += '<div class="text-[11px] font-bold mt-1" style="color:' + dtColor + ';letter-spacing:0.02em" title="당일치기 행선지">🚆 ' + tripsTxt + ' (당일)</div>';
      }

      // 인라인 추가 폼 (이 카드가 add 모드면 표시)
      var addFormHtml = '';
      var cityEsc = (cityName||'').replace(/'/g, "\\'").replace(/"/g, '&quot;');
      if (_weekAddingDate === dateStr) {
        var phCity = cityName ? ('비우면 ' + cityName) : '행선지 (선택)';
        addFormHtml =
          '<div class="border-t-2 border-indigo-300 p-2 bg-indigo-50/40" onclick="event.stopPropagation()">' +
            '<div class="flex items-center gap-1 mb-1">' +
              '<input id="wk-add-time-' + idx + '" type="text" placeholder="09:00" class="w-12 text-[10px] font-bold text-indigo-700 bg-white border border-indigo-200 rounded px-1 py-0.5 outline-none focus:border-indigo-500 text-center"/>' +
              '<span class="text-[9px] text-slate-400">-</span>' +
              '<input id="wk-add-end-' + idx + '" type="text" placeholder="끝" class="w-12 text-[10px] font-bold text-indigo-700 bg-white border border-indigo-200 rounded px-1 py-0.5 outline-none focus:border-indigo-500 text-center"/>' +
            '</div>' +
            '<input id="wk-add-title-' + idx + '" type="text" placeholder="제목 입력..." class="w-full text-[11px] font-semibold bg-white border border-indigo-200 rounded px-1.5 py-1 outline-none focus:border-indigo-500 mb-1"/>' +
            '<div class="flex items-center gap-0.5 mb-1">' +
              '<span class="text-[9px] text-amber-600 font-bold">📍</span>' +
              '<input id="wk-add-city-' + idx + '" type="text" placeholder="' + phCity + '" title="당일치기/숙박지와 다를 때만" class="w-full text-[10px] bg-white border border-amber-200 rounded px-1 py-0.5 outline-none focus:border-amber-500 text-amber-700"/>' +
            '</div>' +
            '<textarea id="wk-add-desc-' + idx + '" placeholder="내용 (선택, Ctrl+Enter로 저장)" rows="2" class="w-full text-[10px] bg-white border border-indigo-200 rounded px-1.5 py-1 outline-none focus:border-indigo-500 resize-none mb-1" onkeydown="if((event.metaKey||event.ctrlKey)&&event.key===\'Enter\'){event.preventDefault();saveWeekAdd(\'' + dateStr + '\',\'' + cityEsc + '\',' + idx + ')}"></textarea>' +
            '<div class="flex gap-1 justify-end">' +
              '<button onclick="cancelWeekAdd()" class="px-2 py-1 rounded text-[10px] font-bold text-slate-500 hover:bg-slate-100">취소</button>' +
              '<button onclick="saveWeekAdd(\'' + dateStr + '\',\'' + cityEsc + '\',' + idx + ')" class="px-2 py-1 rounded bg-indigo-600 text-white text-[10px] font-bold hover:bg-indigo-700 flex items-center gap-0.5">' +
                '<span class="material-symbols-outlined" style="font-size:12px">check</span> 저장' +
              '</button>' +
            '</div>' +
          '</div>';
      } else {
        addFormHtml =
          '<button onclick="event.stopPropagation();startWeekAdd(\'' + dateStr + '\')" class="border-t border-slate-100 py-1.5 text-[10px] font-bold text-indigo-500 hover:bg-indigo-50 hover:text-indigo-700 flex items-center justify-center gap-1 transition-colors w-full" title="이 날에 일정 추가">' +
            '<span class="material-symbols-outlined" style="font-size:14px">add</span> 일정 추가' +
          '</button>';
      }

      return '<div class="bg-white rounded-2xl border ' + (_weekAddingDate === dateStr ? 'border-indigo-300 shadow-md' : 'border-slate-200') + ' overflow-hidden flex flex-col hover:shadow-md transition-shadow group/wcard">' +
        '<div class="px-4 py-3 text-center relative" style="' + headerBg + '">' +
          '<div class="text-[11px] font-black uppercase tracking-widest opacity-90">' + dateStr + (weekday ? ' (' + weekday + ')' : '') + '</div>' +
          headerCityHtml +
        '</div>' +
        '<div class="px-3 py-2 flex-1 min-h-[160px]">' + miniPanelHtml + itemsHtml + '</div>' +
        addFormHtml +
      '</div>';
    }).join('');

    // 포커스: 추가 모드면 시간 input에 자동 포커스
    if (_weekAddingDate) {
      var chunkPos = chunk.findIndex(function(e){ return e.date === _weekAddingDate; });
      if (chunkPos >= 0) {
        setTimeout(function() {
          var inp = document.getElementById('wk-add-time-' + chunkPos);
          if (inp) inp.focus();
        }, 30);
      }
    }
  }

  // ── 주간 카드 인라인 추가/편집 함수들 ──
  var _weekAddingDate = null;
  var _weekEditingId = null;
  function startWeekAdd(dateStr) {
    _weekEditingId = null; // 다른 편집 중이면 닫기
    _weekAddingDate = dateStr;
    renderWeekView();
  }
  function cancelWeekAdd() {
    _weekAddingDate = null;
    renderWeekView();
  }
  function startWeekEdit(itemId) {
    _weekAddingDate = null; // 추가 중이면 닫기
    _weekEditingId = itemId;
    renderWeekView();
    // 폼 자동 포커스
    setTimeout(function() {
      var el = document.getElementById('we-title-' + itemId);
      if (el) { el.focus(); el.select && el.select(); }
    }, 30);
  }
  function cancelWeekEdit() {
    _weekEditingId = null;
    renderWeekView();
  }
  async function saveWeekEdit(itemId) {
    var item = (typeof journeyData !== 'undefined' ? journeyData : []).find(function(j){ return j._id === itemId; });
    if (!item) return;
    var get = function(id) {
      var el = document.getElementById(id);
      return el ? el.value.trim() : '';
    };
    var time = get('we-time-' + itemId);
    var endTime = get('we-end-' + itemId);
    var title = get('we-title-' + itemId);
    var city = get('we-city-' + itemId);
    var desc = get('we-desc-' + itemId);
    var colorEl = document.querySelector('input[name="we-color-' + itemId + '"]:checked');
    var color = colorEl ? colorEl.value : 'none';
    if (!title) { alert('제목을 입력해주세요'); return; }
    var updates = {
      time: time,
      end_time: endTime,
      title: title,
      city: city,
      description: desc,
      pinned: color === 'mint',
      reservation: color === 'pink'
    };
    Object.assign(item, updates);
    try {
      await fbUpdate('journey', itemId, updates);
      _weekEditingId = null;
      renderWeekView();
    } catch(e) {
      alert('저장 실패: ' + (e.message || e));
    }
  }
  async function deleteWeekItem(itemId) {
    if (!confirm('이 일정을 삭제할까요?\n(atelier_trash에 백업됩니다)')) return;
    try {
      await fbDelete('journey', itemId);
      var idx = (typeof journeyData !== 'undefined' ? journeyData : []).findIndex(function(j){ return j._id === itemId; });
      if (idx >= 0) journeyData.splice(idx, 1);
      _weekEditingId = null;
      renderWeekView();
    } catch(e) {
      alert('삭제 실패: ' + (e.message || e));
    }
  }
  if (typeof window !== 'undefined') {
    window.startWeekEdit = startWeekEdit;
    window.cancelWeekEdit = cancelWeekEdit;
    window.saveWeekEdit = saveWeekEdit;
    window.deleteWeekItem = deleteWeekItem;
  }
  async function saveWeekAdd(dateStr, baseCity, idx) {
    var time = (document.getElementById('wk-add-time-' + idx).value || '').trim();
    var endTime = (document.getElementById('wk-add-end-' + idx).value || '').trim();
    var title = (document.getElementById('wk-add-title-' + idx).value || '').trim();
    var cityInput = (document.getElementById('wk-add-city-' + idx).value || '').trim();
    var desc = (document.getElementById('wk-add-desc-' + idx).value || '').trim();
    if (!title) { alert('제목을 입력해주세요!'); return; }
    var cityFinal = cityInput || baseCity || '';
    var obj = {
      trip_id: currentTripId,
      type: '일정',
      date: dateStr,
      time: time,
      end_time: endTime,
      city: cityFinal,
      title: title,
      description: desc
    };
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      // 같은 날짜에 연속 추가할 수 있게 유지 — 폼은 다시 빈 상태로
      renderWeekView();
      if (typeof renderDayView === 'function') renderDayView();
      // 추가 후 시간 input에 다시 포커스 → 연속 입력 편리
      setTimeout(function() {
        var newIdx = (function() {
          var dm = getDayMap();
          var chunkEnd = Math.min(currentWeekChunkStart + WEEK_CHUNK_SIZE, dm.length);
          var chunk = dm.slice(currentWeekChunkStart, chunkEnd);
          return chunk.findIndex(function(e){ return e.date === dateStr; });
        })();
        if (newIdx >= 0) {
          var inp = document.getElementById('wk-add-time-' + newIdx);
          if (inp) inp.focus();
        }
      }, 60);
    } catch(e) {
      alert('저장 실패: ' + (e.message || e));
    }
  }
  if (typeof window !== 'undefined') {
    window.startWeekAdd = startWeekAdd;
    window.cancelWeekAdd = cancelWeekAdd;
    window.saveWeekAdd = saveWeekAdd;
  }

  function prevWeekChunk() {
    if (currentWeekChunkStart <= 0) return;
    currentWeekChunkStart -= WEEK_CHUNK_SIZE;
    if (currentWeekChunkStart < 0) currentWeekChunkStart = 0;
    renderWeekView();
  }
  function nextWeekChunk() {
    var dayMap = getDayMap();
    var nextStart = currentWeekChunkStart + WEEK_CHUNK_SIZE;
    if (nextStart >= dayMap.length) return; // 더 이상 다음 청크 없음
    currentWeekChunkStart = nextStart;
    renderWeekView();
  }
  function jumpToDay(idx, openAdd) {
    currentDayIndex = idx;
    syncWeekChunkToCurrentDay();
    renderDayView();
    // 일차 카드 영역으로 부드럽게 스크롤 + 옵션: 일정 추가 폼 자동 열기
    setTimeout(function() {
      var dayCard = document.getElementById('journey-schedule-list');
      if (dayCard) {
        var sec = dayCard.closest('section');
        if (sec) sec.scrollIntoView({behavior:'smooth', block:'start'});
      }
      if (openAdd) {
        setTimeout(function(){
          if (typeof addScheduleInline === 'function') addScheduleInline();
        }, 350);
      }
    }, 50);
  }

  function inlineEditTd(td, saveCallback) {
    if (td.querySelector('input')) return;
    var orig = td.textContent.trim();
    var input = document.createElement('input');
    input.type = 'text';
    input.value = orig;
    input.className = 'border-0 border-b border-indigo-400 bg-transparent px-1 py-0.5 text-[10px] outline-none w-full focus:border-indigo-600';
    td.textContent = '';
    td.appendChild(input);
    input.focus();
    input.select();
    var done = false;
    function finish(save) {
      if (done) return; done = true;
      if (save) { saveCallback(input.value.trim()); }
      else { td.textContent = orig; }
    }
    input.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') { e.preventDefault(); finish(true); }
      if (e.key === 'Escape') { e.preventDefault(); finish(false); }
    });
    input.addEventListener('blur', function() { finish(true); });
  }

  function fbInlineEdit(td, idx, field, rerenderType) {
    inlineEditTd(td, async function(val) {
      journeyData[idx][field] = val;
      var upd = {}; upd[field] = val;
      try {
        await fbUpdate('journey', journeyData[idx]._id, upd);
      } catch(e) { alert('저장 실패'); }
      if (rerenderType === '항공편') renderJourneyFlights();
      else if (rerenderType === '이동수단') { renderJourneyTransport(); renderDayView(); }
      else if (rerenderType === '렌트카') renderJourneyRental();
      else if (rerenderType === '숙소') renderJourneyLodging();
      else if (rerenderType === '기념품') renderJourneySouvenir();
      updateJourneyCost();
    });
  }

