  function openStayEditModal(idx) {
    var item = journeyData[idx];
    if (!item) return;
    _stayEditIdx = idx;
    _stayEditType = item.description === 'Airbnb' ? 'Airbnb' : 'Hotel';
    _stayEditCancel = item.cancel || '가능';

    // 도시 datalist 갱신
    var dl = document.getElementById('stay-edit-city-list');
    if (dl) dl.innerHTML = (citiesData||[]).map(function(c){ return '<option value="'+c.name+'">'; }).join('');

    // 필드 채우기
    var setV = function(id, val) { var el = document.getElementById(id); if (el) el.value = val || ''; };
    setV('stay-edit-city', item.city);
    setV('stay-edit-name', item.title);
    setV('stay-edit-address', item.address);
    setV('stay-edit-phone', item.phone);
    setV('stay-edit-payment-date', item.payment_date);
    setV('stay-edit-checkin-date', item.date);
    setV('stay-edit-checkout-date', item.checkout_date);
    setV('stay-edit-checkin-time', item.checkin);
    setV('stay-edit-checkout-time', item.checkout);
    setV('stay-edit-cancel-date', item.cancel_date);
    setV('stay-edit-price', item.amount ? Number(String(item.amount).replace(/[^0-9.]/g,'')).toLocaleString('ko-KR') : '');
    setV('stay-edit-notes', item.notes);

    _stayEditPayStatus = item.payment_status || '결제 예정';
    selectStayEditType(_stayEditType);
    selectStayCancel(_stayEditCancel);
    selectStayPayStatus(_stayEditPayStatus);
    openTravelModal('stay-edit-modal-wrap');
  }

  async function saveStayEdit() {
    if (_stayEditIdx === null) return;
    var item = journeyData[_stayEditIdx];
    if (!item) return;
    var name = document.getElementById('stay-edit-name').value.trim();
    if (!name) { alert('숙소명을 입력해주세요'); return; }
    var updates = {
      city: document.getElementById('stay-edit-city').value.trim(),
      title: name,
      address: document.getElementById('stay-edit-address').value.trim(),
      phone: document.getElementById('stay-edit-phone').value.trim(),
      payment_date: document.getElementById('stay-edit-payment-date').value,
      date: document.getElementById('stay-edit-checkin-date').value,
      checkout_date: document.getElementById('stay-edit-checkout-date').value,
      checkin: document.getElementById('stay-edit-checkin-time').value.trim(),
      checkout: document.getElementById('stay-edit-checkout-time').value.trim(),
      cancel: _stayEditCancel,
      cancel_date: document.getElementById('stay-edit-cancel-date').value,
      amount: document.getElementById('stay-edit-price').value.replace(/,/g,''),
      notes: (document.getElementById('stay-edit-notes')||{}).value || '',
      payment_status: _stayEditPayStatus || '',
      description: _stayEditType === 'Airbnb' ? 'Airbnb' : ''
    };
    try {
      await fbUpdate('journey', item._id, updates);
      Object.assign(journeyData[_stayEditIdx], updates);
      await syncJourneyToFinance(journeyData[_stayEditIdx]);
      closeTravelModal('stay-edit-modal-wrap');
      renderJourneyLodging();
      updateJourneyCost();
      updateTravelMiniSummary();
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 숙소 수정 완료');
    } catch(e) { alert('저장 실패: ' + e.message); }
  }

  function selectStayType(type) {
    _stayType = type;
    var hotelBtn = document.getElementById('stay-type-hotel');
    var airbnbBtn = document.getElementById('stay-type-airbnb');
    if (type === 'Hotel') {
      hotelBtn.className = 'flex items-center justify-center gap-2 py-2.5 rounded-xl bg-white ring-2 ring-indigo-500 text-indigo-600 text-sm font-bold shadow-sm';
      airbnbBtn.className = 'flex items-center justify-center gap-2 py-2.5 rounded-xl bg-white text-slate-500 text-sm font-semibold hover:ring-2 hover:ring-indigo-300 transition-all';
    } else {
      airbnbBtn.className = 'flex items-center justify-center gap-2 py-2.5 rounded-xl bg-white ring-2 ring-indigo-500 text-indigo-600 text-sm font-bold shadow-sm';
      hotelBtn.className = 'flex items-center justify-center gap-2 py-2.5 rounded-xl bg-white text-slate-500 text-sm font-semibold hover:ring-2 hover:ring-indigo-300 transition-all';
    }
  }

  async function saveInlineStay() {
    var city = document.getElementById('stay-city').value.trim();
    var name = document.getElementById('stay-name').value.trim();
    if (!name) { alert('숙소명을 입력해줘!'); return; }
    var getV = function(id){ var el = document.getElementById(id); return el ? (el.value||'').trim() : ''; };
    var obj = {
      trip_id: currentTripId, type: '숙소',
      city: city, title: name,
      address: getV('stay-address'),
      phone: getV('stay-phone'),
      date: document.getElementById('stay-checkin-date').value,
      checkout_date: document.getElementById('stay-checkout-date').value,
      checkin: getV('stay-checkin-time'),
      checkout: getV('stay-checkout-time'),
      cancel: _stayAddCancel || '',
      cancel_date: document.getElementById('stay-cancel-date').value,
      payment_date: document.getElementById('stay-payment-date').value,
      payment_status: _stayAddPayStatus || '',
      amount: document.getElementById('stay-price').value.replace(/,/g,''),
      notes: getV('stay-notes'),
      description: _stayType === 'Airbnb' ? 'Airbnb' : ''
    };
    try {
      var saved = await fbAdd('journey', obj);
      journeyData.push(saved);
      await syncJourneyToFinance(saved);
      renderJourneyLodging();
      updateJourneyCost();
      // 폼 초기화
      ['stay-city','stay-name','stay-address','stay-phone','stay-checkin-date','stay-checkout-date','stay-checkin-time','stay-checkout-time','stay-cancel-date','stay-payment-date','stay-price','stay-notes'].forEach(function(id){ var el=document.getElementById(id); if(el) el.value=''; });
      _stayType = 'Hotel'; selectStayType('Hotel');
      _stayAddCancel = '가능'; selectStayAddCancel('가능');
      _stayAddPayStatus = '결제 예정'; selectStayAddPayStatus('결제 예정');
    } catch(err) { alert('저장에 실패했어요.'); }
  }

  function renderJourneyLodging() {
    var container = document.getElementById('journey-lodging-list');
    if (!container) return;

    if (!isSeedTrip()) {
      var fbItems = journeyData.filter(function(d){ return d.type === '숙소'; });
      fbItems.sort(function(a,b){ return (a.date||'').localeCompare(b.date||''); });
      if (fbItems.length === 0) { container.innerHTML = '<div class="text-center py-8 text-sm text-slate-400">숙소를 추가해봐!</div>'; return; }
      container.innerHTML = fbItems.map(function(item) {
        var realIdx = journeyData.indexOf(item);
        var cancelColor = item.cancel === '가능' ? 'text-emerald-600' : (item.cancel === '조건부' ? 'text-amber-600' : 'text-rose-600');
        var cancelText = item.cancel === '가능'
          ? (item.cancel_date ? '무료 취소 ~' + item.cancel_date : '무료 취소 가능')
          : (item.cancel === '조건부' ? (item.cancel_date ? '조건부 ~' + item.cancel_date : '조건부') : (item.cancel === '불가' ? '환불 불가' : (item.cancel||'—')));
        // 숙소 유형 뱃지 (description === 'Airbnb' 이면 Airbnb)
        var isAirbnb = (item.description||'').toLowerCase().indexOf('airbnb') >= 0;
        var typeBadge = isAirbnb
          ? '<span class="flex items-center gap-1 px-2.5 py-0.5 bg-rose-50 text-rose-600 rounded-full text-[9px] font-bold uppercase tracking-wider"><span class="material-symbols-outlined text-xs">home</span>AIRBNB</span>'
          : '<span class="flex items-center gap-1 px-2.5 py-0.5 bg-slate-50 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-wider"><span class="material-symbols-outlined text-xs">hotel</span>HOTEL</span>';
        // 결제 상태 뱃지
        var payStatus = item.payment_status || '';
        var payBadge = '';
        if (payStatus) {
          var payClass = payStatus === '결제 완료' ? 'bg-emerald-100 text-emerald-700' :
                         payStatus === '결제 예정' ? 'bg-amber-100 text-amber-700' :
                         payStatus === '현장 결제' ? 'bg-sky-100 text-sky-700' :
                         'bg-slate-100 text-slate-600';
          var payIcon = payStatus === '결제 완료' ? 'check_circle' :
                        payStatus === '결제 예정' ? 'schedule' :
                        payStatus === '현장 결제' ? 'storefront' : 'payments';
          payBadge = '<span class="flex items-center gap-1 px-2.5 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-wider ' + payClass + '"><span class="material-symbols-outlined text-xs">' + payIcon + '</span>' + payStatus + '</span>';
        }
        // 메모를 칩으로 분해 (객실/인원/금연/식사/보증금 등)
        var memoChips = '';
        if (item.notes) {
          var chips = String(item.notes).split(/\s*·\s*|\s*,\s*/).filter(function(c){ return c.trim(); });
          if (chips.length) {
            memoChips = '<div class="flex flex-wrap gap-1.5 pt-1">' + chips.map(function(c){
              var t = c.trim();
              var icon = 'bookmark';
              if (/금연|흡연/.test(t)) icon = 'smoke_free';
              else if (/식사|조식|석식|브런치/.test(t)) icon = 'restaurant';
              else if (/보증금|deposit/i.test(t)) icon = 'account_balance_wallet';
              else if (/성인|아동|어린이|유아|명/.test(t)) icon = 'group';
              else if (/침대|룸|객실|싱글|더블|트윈|퀸|킹|슬리퍼/.test(t)) icon = 'bed';
              return '<span class="inline-flex items-center gap-1 px-2 py-0.5 bg-violet-50 text-violet-700 rounded-md text-[10px] font-semibold"><span class="material-symbols-outlined" style="font-size:11px">' + icon + '</span>' + t + '</span>';
            }).join('') + '</div>';
          }
        }
        // 결제일 미니 표시
        var paymentDateRow = item.payment_date
          ? '<div class="flex items-center gap-1.5 text-[10px] text-slate-400 mt-1"><span class="material-symbols-outlined" style="font-size:11px">event_available</span>결제일 ' + item.payment_date + '</div>'
          : '';
        return '<div class="bg-white rounded-2xl p-5 hover:shadow-md transition-all" style="box-shadow:0px 4px 16px rgba(25,28,29,0.04);border-left:3px solid #6b38d4;">' +
          '<div class="flex flex-col md:flex-row justify-between gap-4">' +
            '<div class="flex-1 space-y-3">' +
              '<div class="flex flex-wrap items-center gap-2.5">' +
                (item.city ? '<span class="bg-indigo-100 text-indigo-700 px-2.5 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-widest">' + item.city + '</span>' : '') +
                '<h4 class="font-headline text-xl font-bold text-slate-900 flex items-center gap-1.5">' + (item.title||'—') + '</h4>' +
                typeBadge +
                payBadge +
                (item.phone ? '<span class="text-slate-500 text-[11px] font-medium flex items-center gap-1"><span class="material-symbols-outlined text-xs">call</span>' + item.phone + '</span>' : '') +
              '</div>' +
              (item.address ? '<p class="text-[11px] text-slate-400 flex items-center gap-1"><span class="material-symbols-outlined" style="font-size:12px">location_on</span>' + item.address + '</p>' : '') +
              '<div class="grid grid-cols-2 lg:grid-cols-4 gap-4 pt-1">' +
                '<div><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Check-in</p><p class="text-[13px] font-semibold text-slate-900 leading-tight">' + (item.date||'—') + '</p>' + (item.checkin ? '<p class="text-[11px] text-slate-500">' + item.checkin + '</p>' : '') + '</div>' +
                '<div><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Check-out</p><p class="text-[13px] font-semibold text-slate-900 leading-tight">' + (item.checkout_date||'—') + '</p>' + (item.checkout ? '<p class="text-[11px] text-slate-500">' + item.checkout + '</p>' : '') + '</div>' +
                '<div><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Cancellation</p><p class="text-[13px] font-semibold ' + cancelColor + ' leading-tight">' + cancelText + '</p></div>' +
                '<div class="text-right lg:text-left"><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Rate</p><p class="font-headline text-lg font-extrabold text-slate-900 leading-tight">' + (item.amount ? '₩'+Number(String(item.amount).replace(/[^0-9.]/g,'')).toLocaleString('ko-KR') : '—') + '</p>' + paymentDateRow + '</div>' +
              '</div>' +
              memoChips +
            '</div>' +
            '<div class="flex items-start gap-2">' +
              '<button onclick="editJourneyItem(' + realIdx + ')" class="p-2 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors text-slate-600"><span class="material-symbols-outlined text-xl">edit_square</span></button>' +
              '<button onclick="deleteJourneyRow(' + realIdx + ')" class="p-2 rounded-xl bg-slate-50 hover:bg-rose-100 transition-colors text-slate-400 hover:text-rose-500"><span class="material-symbols-outlined text-xl">delete</span></button>' +
            '</div>' +
          '</div>' +
        '</div>';
      }).join('');
      return;
    }

    // 시드 여행: localStorage 기반
    var data = getLodgingData();
    if (data.length === 0) { container.innerHTML = '<div class="text-center py-8 text-sm text-slate-400">숙소를 추가해봐!</div>'; return; }
    container.innerHTML = data.map(function(d, idx) {
      var cancelOk = d.cancel_override !== undefined ? d.cancel_override : (d.cancel_date >= new Date().toISOString().split('T')[0]);
      var cancelColor = cancelOk ? 'text-emerald-600' : 'text-rose-600';
      var cancelText = cancelOk ? '무료 취소 가능 ~' + shortDate(d.cancel_date) : '환불 불가';
      var rawType = d.type || 'Hotel';
      var baseType = rawType.replace(/\s*\(.*\)/, '');
      var typeIcon = baseType.indexOf('Airbnb') >= 0 ? 'home' : 'hotel';
      return '<div class="bg-white rounded-2xl p-5 hover:shadow-md transition-all" style="box-shadow:0px 4px 16px rgba(25,28,29,0.04);border-left:3px solid #6b38d4;">' +
        '<div class="flex flex-col md:flex-row justify-between gap-4">' +
          '<div class="flex-1 space-y-4">' +
            '<div class="flex flex-wrap items-center gap-3">' +
              '<span class="bg-indigo-100 text-indigo-700 px-2.5 py-0.5 rounded-full text-[9px] font-bold uppercase tracking-widest">' + d.city + '</span>' +
              '<h4 class="font-headline text-xl font-bold text-slate-900 flex items-center gap-1.5">' + d.title + '<span class="material-symbols-outlined text-indigo-600 text-lg" style="font-variation-settings:\'FILL\' 1;">verified</span></h4>' +
              '<div class="flex items-center gap-2.5">' +
                '<span class="flex items-center gap-1 px-2.5 py-0.5 bg-slate-50 text-slate-500 rounded-full text-[9px] font-bold uppercase tracking-wider"><span class="material-symbols-outlined text-xs">' + typeIcon + '</span>' + baseType + '</span>' +
                (d.phone ? '<span class="text-slate-500 text-[11px] font-medium flex items-center gap-1"><span class="material-symbols-outlined text-xs">call</span>' + d.phone + '</span>' : '') +
              '</div>' +
            '</div>' +
            '<div class="grid grid-cols-2 lg:grid-cols-4 gap-4 pt-1">' +
              '<div><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Check-in</p><p class="text-[13px] font-semibold text-slate-900 leading-tight">' + shortDate(d.date) + '</p><p class="text-[11px] text-slate-500">' + d.checkin + '</p></div>' +
              '<div><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Check-out</p><p class="text-[13px] font-semibold text-slate-900 leading-tight">' + shortDate(d.checkout_date) + '</p><p class="text-[11px] text-slate-500">' + d.checkout + '</p></div>' +
              '<div><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Cancellation</p><p class="text-[13px] font-semibold ' + cancelColor + ' leading-tight cursor-pointer" onclick="toggleLodgingCancel(' + idx + ')">' + cancelText + '</p></div>' +
              '<div class="text-right lg:text-left"><p class="text-[9px] font-bold uppercase tracking-widest text-slate-400 mb-0.5">Rate</p><p class="font-headline text-lg font-extrabold text-slate-900 leading-tight">' + d.price + '</p><p class="text-[11px] text-slate-500">per night</p></div>' +
            '</div>' +
          '</div>' +
          '<div class="flex items-start gap-2">' +
            '<button onclick="openLodgingEditModal(' + idx + ')" class="p-2 rounded-xl bg-slate-50 hover:bg-slate-100 transition-colors text-slate-600"><span class="material-symbols-outlined text-xl">edit_square</span></button>' +
            '<button onclick="deleteLodgingLocal(' + idx + ')" class="p-2 rounded-xl bg-slate-50 hover:bg-rose-100 transition-colors text-slate-400 hover:text-rose-500"><span class="material-symbols-outlined text-xl">delete</span></button>' +
          '</div>' +
        '</div>' +
      '</div>';
    }).join('');
  }


