  function isSeedTrip() {
    var trip = tripsData.find(function(t){ return t._id === currentTripId; });
    if (!trip) return false;
    var n = (trip.name||'').replace(/\s/g,'').toLowerCase();
    return n.indexOf('체코') >= 0 || n.indexOf('크로아티아') >= 0 || n === SEED_TRIP_NAME.replace(/\s/g,'').toLowerCase();
  }

