  async function saveTripEntry() {
    var obj = {
      name: document.getElementById('trip-name').value,
      start_date: document.getElementById('trip-start').value,
      end_date: document.getElementById('trip-end').value,
      // imageUrl is managed via dashboard upload, not modal
    };
    if (!obj.name) return alert('여행 이름을 입력해줘!');
    var editId = document.getElementById('trip-modal').dataset.editId;
    try {
      if (editId) {
        await fbUpdate('trips', editId, obj);
        var t = tripsData.find(function(t){ return t._id === editId; });
        if (t) Object.assign(t, obj);
        delete document.getElementById('trip-modal').dataset.editId;
        document.getElementById('trip-modal-title').textContent = '여행 추가';
        closeTripModal();
        selectTrip(editId);
      } else {
        var saved = await fbAdd('trips', obj);
        tripsData.push(saved);
        closeTripModal();
        selectTrip(saved._id);
      }
    } catch(err) { alert('저장에 실패했어요.'); }
  }

  // Journey item modal
  function getJourneyForms(type) {
    var cities = citiesData.map(function(c){ return c.name; });
    // City pairs for transport routes
    var routeOptions = [];
    for (var i = 0; i < cities.length - 1; i++) {
      routeOptions.push(cities[i] + ' → ' + cities[i+1]);
    }
    // Also add reverse routes
    for (var i = cities.length - 1; i > 0; i--) {
      routeOptions.push(cities[i] + ' → ' + cities[i-1]);
    }

    if (type === '일정') return [
      {id:'jf-date', label:'날짜', type:'date'},
      {id:'jf-time', label:'시간', type:'text', placeholder:'예: 09:00'},
      {id:'jf-city', label:'도시', type: cities.length ? 'select_custom' : 'text', options: cities, placeholder:'예: Prague'},
      {id:'jf-title', label:'여행지 *', type:'text', placeholder:'예: 구시가지 광장 투어', autocomplete:'place'},
      {id:'jf-desc', label:'설명', type:'text', placeholder:'예: 천문 시계 앞에서 만나...'},
    ];
    if (type === '이동수단') return [
      {id:'jf-date', label:'탑승 날짜', type:'date'},
      {id:'jf-time', label:'시간', type:'text', placeholder:'예: 08:45'},
      {id:'jf-payment-date', label:'결제일', type:'date'},
      {id:'jf-title', label:'이동 수단명 *', type:'text', placeholder:'예: DB ICE Train'},
      {id:'jf-desc', label:'루트 *', type: routeOptions.length ? 'select_custom' : 'text', options: routeOptions, placeholder:'예: Prague → Olomouc'},
      {id:'jf-status', label:'상태', type:'select', options:['확정','대기 중','취소']},
      {id:'jf-amount', label:'가격 (₩)', type:'text', inputmode:'numeric', placeholder:'예: 200,000', oninput:"this.value=this.value.replace(/[^0-9]/g,'').replace(/\\B(?=(\\d{3})+(?!\\d))/g,',')"},
    ];
    if (type === '기념품') return [
      {id:'jf-title', label:'대상 *', type:'text', placeholder:'예: 가족, 동료, 나'},
      {id:'jf-desc', label:'품목 *', type:'text', placeholder:'예: Marvis 치약 세트'},
      {id:'jf-city', label:'구매 도시', type: cities.length ? 'select_custom' : 'text', options: cities, placeholder:'예: Prague'},
      {id:'jf-amount', label:'가격 (€)', type:'text', inputmode:'numeric', placeholder:'예: 24'},
      {id:'jf-date', label:'방문 날짜', type:'date', placeholder:'특정 날에 가야하면 입력 (선택)'},
      {id:'jf-time', label:'방문 시간', type:'text', placeholder:'예: 14:00 (입력 시 일정에 표시됨)'},
      {id:'jf-location', label:'장소', type:'text', placeholder:'예: 토스카나 로컬 가죽 공방 (선택)'},
    ];
    if (type === '항공편') return [
      {id:'jf-title', label:'항공사 *', type:'text', placeholder:'예: Turkish Airline'},
      {id:'jf-desc', label:'루트 *', type:'text', placeholder:'예: 인천(ICN) → 이스탄불(IST)'},
      {id:'jf-city', label:'편명', type:'text', placeholder:'예: TK91'},
      {id:'jf-date', label:'탑승 날짜', type:'date'},
      {id:'jf-time', label:'출발 시간', type:'text', placeholder:'예: 23:20'},
      {id:'jf-payment-date', label:'결제일', type:'date'},
      {id:'jf-amount', label:'가격 (₩)', type:'text', inputmode:'numeric', placeholder:'예: 1,743,400', oninput:"this.value=this.value.replace(/[^0-9]/g,'').replace(/\\B(?=(\\d{3})+(?!\\d))/g,',')"},
    ];
    if (type === '렌트카') return [
      {id:'jf-title', label:'렌트카 회사 *', type:'text', placeholder:'예: Hertz, Sixt'},
      {id:'jf-desc', label:'차종', type:'text', placeholder:'예: BMW X3'},
      {id:'jf-city', label:'픽업 도시', type: cities.length ? 'select_custom' : 'text', options: cities, placeholder:'예: Pienza'},
      {id:'jf-drop-city', label:'드롭 도시', type: cities.length ? 'select_custom' : 'text', options: cities, placeholder:'다르면 입력 (같으면 빈칸)'},
      {id:'jf-date', label:'픽업 날짜', type:'date'},
      {id:'jf-time', label:'픽업 시간', type:'text', placeholder:'예: 10:00'},
      {id:'jf-pickup-location', label:'픽업 장소', type:'text', placeholder:'예: FCO 공항'},
      {id:'jf-checkout-date', label:'드롭 날짜', type:'date'},
      {id:'jf-checkout', label:'드롭 시간', type:'text', placeholder:'예: 18:00'},
      {id:'jf-drop-location', label:'드롭 장소', type:'text', placeholder:'예: Orvieto 시내'},
      {id:'jf-payment-date', label:'결제일', type:'date'},
      {id:'jf-amount', label:'가격 (₩)', type:'text', inputmode:'numeric', placeholder:'예: 1,050,000', oninput:"this.value=this.value.replace(/[^0-9]/g,'').replace(/\\B(?=(\\d{3})+(?!\\d))/g,',')"},
      {id:'jf-notes', label:'메모', type:'text', placeholder:'예: 풀커버 보험 포함'},
    ];
    if (type === '숙소') return [
      {id:'jf-city', label:'도시 *', type: cities.length ? 'select_custom' : 'text', options: cities, placeholder:'예: Prague', onchange:'onJourneyCityChange()'},
      {id:'jf-stay-type', label:'유형', type:'select', options:['Hotel','Airbnb']},
      {id:'jf-title', label:'숙소명 *', type:'text', placeholder:'예: Hotel Josef', autocomplete:'lodging'},
      {id:'jf-address', label:'주소', type:'text', placeholder:'예: Rybná 20, 110 00 Praha'},
      {id:'jf-phone', label:'전화번호', type:'text', placeholder:'예: +420 221 700 111'},
      {id:'jf-payment-date', label:'결제일 *', type:'date'},
      {id:'jf-payment-status', label:'결제 상태', type:'select', options:['결제 예정','결제 완료','현장 결제']},
      {id:'jf-date', label:'체크인 날짜', type:'date'},
      {id:'jf-checkout-date', label:'체크아웃 날짜', type:'date'},
      {id:'jf-checkin', label:'체크인 시간', type:'text', placeholder:'예: 15:00'},
      {id:'jf-checkout', label:'체크아웃 시간', type:'text', placeholder:'예: 11:00'},
      {id:'jf-cancel', label:'무료 취소', type:'select', options:['가능', '불가', '조건부']},
      {id:'jf-cancel-date', label:'무료 취소 마감일', type:'date'},
      {id:'jf-amount', label:'가격 (₩)', type:'text', inputmode:'numeric', placeholder:'예: 150,375', oninput:"this.value=this.value.replace(/[^0-9]/g,'').replace(/\\B(?=(\\d{3})+(?!\\d))/g,',')"},
      {id:'jf-notes', label:'메모', type:'text', placeholder:'예: 퀸침대 1개, 성인 2명, 금연, 식사 불포함, 보증금 €20'},
    ];
    return [];
  }

  function openJourneyModal(type) {
    currentJourneyType = type;
    var titles = {'일정':'일정 추가','이동수단':'이동 수단 추가','렌트카':'렌트카 추가','기념품':'기념품 추가','항공편':'항공편 추가'};
    document.getElementById('journey-modal-title').textContent = titles[type]||'항목 추가';
    var fields = getJourneyForms(type);
    document.getElementById('journey-modal-body').innerHTML = fields.map(function(f){
      var input;
      if (f.type === 'select') {
        input = '<select id="'+f.id+'" '+(f.onchange?'onchange="'+f.onchange+'"':'')+' class="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-200 outline-none bg-white">'+
          f.options.map(function(o){return '<option>'+o+'</option>';}).join('')+'</select>';
      } else if (f.type === 'select_custom') {
        input = '<input id="'+f.id+'" type="text" list="'+f.id+'-list" placeholder="'+(f.placeholder||'')+'"'+(f.onchange?' oninput="'+f.onchange+'" onchange="'+f.onchange+'"':'')+' class="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-200 outline-none"/>'+
          '<datalist id="'+f.id+'-list">'+(f.options||[]).map(function(o){return '<option value="'+o+'">'+o+'</option>';}).join('')+'</datalist>';
      } else {
        var dateAttrs = '';
        if (f.type === 'date') {
          var trip = getCurrentTrip();
          if (trip && trip.start_date) dateAttrs += ' min="' + trip.start_date + '"';
          if (trip && trip.end_date) dateAttrs += ' max="' + trip.end_date + '"';
        }
        input = '<input id="'+f.id+'" type="'+f.type+'" '+(f.placeholder?'placeholder="'+f.placeholder+'"':'')+' '+(f.inputmode?'inputmode="'+f.inputmode+'"':'')+' '+(f.autocomplete?'data-autocomplete="'+f.autocomplete+'"':'')+(f.oninput?' oninput="'+f.oninput+'"':'')+dateAttrs+' class="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-200 outline-none"/>';
      }
      var wrapper = f.showIf ? 'id="wrap-'+f.id+'" style="display:none"' : '';
      return '<div '+wrapper+'><label class="block text-[10px] font-bold uppercase tracking-widest text-slate-500 mb-1.5">'+f.label+'</label>'+input+'</div>';
    }).join('');
    // Pre-fill date with current day (within trip range)
    var dateEl = document.getElementById('jf-date');
    if (dateEl) {
      var dayMap = getDayMap();
      var entry = dayMap[currentDayIndex];
      if (entry && entry.date) {
        dateEl.value = entry.date;
      } else {
        var trip = getCurrentTrip();
        dateEl.value = (trip && trip.start_date) ? trip.start_date : new Date().toISOString().split('T')[0];
      }
    }
    document.getElementById('journey-modal').style.cssText = 'display:flex!important';
    // Init places autocomplete
    if (type === '숙소') setTimeout(initPlacesAutocomplete, 100);
    if (type === '일정') setTimeout(initSchedulePlacesAutocomplete, 100);
  }

  function editJourneyItem(idx) {
    var item = journeyData[idx];
    editingJourneyIndex = idx;
    currentJourneyType = item.type;

    // 항공편은 전용 수정 모달 사용
    if (item.type === '항공편') {
      openFlightEditModal(idx);
      return;
    }
    // 숙소도 전용 수정 모달 사용
    if (item.type === '숙소') {
      openStayEditModal(idx);
      return;
    }
    // 이동수단도 전용 수정 모달 사용
    if (item.type === '이동수단') {
      openTransportEditModal(idx);
      return;
    }
    // 렌트카도 전용 수정 모달 사용
    if (item.type === '렌트카') {
      openRentalEditModal(idx);
      return;
    }

    var titles = {'일정':'일정 수정','이동수단':'이동 수단 수정','기념품':'기념품 수정'};
    document.getElementById('journey-modal-title').textContent = titles[item.type]||'수정';
    var fields = getJourneyForms(item.type);
    document.getElementById('journey-modal-body').innerHTML = fields.map(function(f){
      var input;
      if (f.type === 'select') {
        input = '<select id="'+f.id+'" class="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-200 outline-none bg-white">'+
          f.options.map(function(o){return '<option>'+o+'</option>';}).join('')+'</select>';
      } else if (f.type === 'select_custom') {
        input = '<input id="'+f.id+'" type="text" list="'+f.id+'-list" class="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-200 outline-none"/>'+
          '<datalist id="'+f.id+'-list">'+(f.options||[]).map(function(o){return '<option value="'+o+'">'+o+'</option>';}).join('')+'</datalist>';
      } else {
        var dateAttrsE = '';
        if (f.type === 'date') {
          var tripE = getCurrentTrip();
          if (tripE && tripE.start_date) dateAttrsE += ' min="' + tripE.start_date + '"';
          if (tripE && tripE.end_date) dateAttrsE += ' max="' + tripE.end_date + '"';
        }
        input = '<input id="'+f.id+'" type="'+f.type+'" '+(f.placeholder?'placeholder="'+f.placeholder+'"':'')+(f.oninput?' oninput="'+f.oninput+'"':'')+dateAttrsE+' class="w-full border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-indigo-200 outline-none"/>';
      }
      return '<div><label class="block text-[10px] font-bold uppercase tracking-widest text-slate-500 mb-1.5">'+f.label+'</label>'+input+'</div>';
    }).join('');
    // Fill existing values
    var amountFmt = item.amount ? Number(String(item.amount).replace(/[^0-9.]/g,'')).toLocaleString('ko-KR') : '';
    var fieldMap = {
      'jf-payment-date': item.payment_date, 'jf-date': item.date, 'jf-checkout-date': item.checkout_date, 'jf-time': item.time, 'jf-city': item.city,
      'jf-drop-city': item.drop_city,
      'jf-title': item.title, 'jf-desc': item.description,
      'jf-status': item.status, 'jf-amount': amountFmt,
      'jf-address': item.address, 'jf-phone': item.phone,
      'jf-checkin': item.checkin, 'jf-checkout': item.checkout,
      'jf-cancel': item.cancel,
      'jf-cancel-date': item.cancel_date,
      'jf-pickup-location': item.pickup_location,
      'jf-drop-location': item.drop_location,
      'jf-notes': item.notes
    };
    Object.keys(fieldMap).forEach(function(id){
      var el = document.getElementById(id);
      if (el && fieldMap[id]) el.value = fieldMap[id];
    });
    document.getElementById('journey-modal').style.cssText = 'display:flex!important';
    if (item.type === '숙소') setTimeout(initPlacesAutocomplete, 100);
    if (item.type === '일정') setTimeout(initSchedulePlacesAutocomplete, 100);
  }

  function openCurrentTripEditModal() {
    if (currentTripId) openEditTripModal(currentTripId);
  }

  function confirmDeleteCurrentTrip() {
    if (!currentTripId) return;
    var trip = getCurrentTrip();
    if (!trip) return;
    if (confirm('"' + trip.name + '" 여행을 정말 삭제할까요?\n관련된 일정·숙소·항공편 등 데이터는 남아있어요.')) {
      deleteTripEntry(currentTripId);
    }
  }

  function openEditTripModal(tripId) {
    var trip = tripsData.find(function(t){ return t._id === tripId; });
    if (!trip) return;
    document.getElementById('trip-name').value = trip.name||'';
    document.getElementById('trip-start').value = trip.start_date||'';
    document.getElementById('trip-end').value = trip.end_date||'';
    document.getElementById('trip-modal').dataset.editId = tripId;
    document.getElementById('trip-modal-title').textContent = '여행 수정';
    document.getElementById('trip-modal').style.cssText = 'display:flex!important';
  }

  async function deleteTripEntry(tripId) {
    var trip = tripsData.find(function(t){ return t._id === tripId; });
    if (!confirm('"' + (trip?trip.name:'') + '" 여행을 삭제할까요?')) return;
    try {
      await fbDelete('trips', tripId);
      tripsData = tripsData.filter(function(t){ return t._id !== tripId; });
      currentTripId = null;
      renderTripTabs();
      if (tripsData.length > 0) {
        selectTrip(findClosestTrip(tripsData)._id);
      } else {
        document.getElementById('journey-empty-state').style.display = 'flex';
        document.getElementById('journey-content').style.display = 'none';
      }
    } catch(err) { alert('삭제에 실패했어요.'); }
  }

  // ===== GOOGLE PLACES AUTOCOMPLETE =====
  var _lodgingAutocomplete = null;
  function initPlacesAutocomplete() {
    var input = document.getElementById('jf-title');
    if (!input || !input.dataset.autocomplete || typeof google === 'undefined' || typeof google.maps === 'undefined') return;
    if (_lodgingAutocomplete) { google.maps.event.clearInstanceListeners(_lodgingAutocomplete); _lodgingAutocomplete = null; }
    _lodgingAutocomplete = new google.maps.places.Autocomplete(input, {
      types: ['lodging', 'establishment'],
      fields: ['geometry', 'name', 'formatted_address', 'formatted_phone_number'],
    });
    _lodgingAutocomplete.addListener('place_changed', function() {
      var place = _lodgingAutocomplete.getPlace();
      if (!place.geometry) return;
      input.value = place.name || input.value;
      var addrEl = document.getElementById('jf-address');
      if (addrEl && place.formatted_address) addrEl.value = place.formatted_address;
      var phoneEl = document.getElementById('jf-phone');
      if (phoneEl && place.formatted_phone_number) phoneEl.value = place.formatted_phone_number;
    });
    setTimeout(function(){ var pacs = document.querySelectorAll('.pac-container'); pacs.forEach(function(p){ p.style.zIndex = '99999'; }); }, 300);
  }

  var _cityAutocomplete = null;
  function initCityPlacesAutocomplete() {
    try {
      var input = document.getElementById('city-name');
      if (!input || typeof google === 'undefined' || typeof google.maps === 'undefined' || typeof google.maps.places === 'undefined') return;
      if (_cityAutocomplete) { try { google.maps.event.clearInstanceListeners(_cityAutocomplete); } catch(e){} _cityAutocomplete = null; }
      _cityAutocomplete = new google.maps.places.Autocomplete(input, {
        types: ['(cities)'],
        fields: ['name'],
      });
      _cityAutocomplete.addListener('place_changed', function() {
        var place = _cityAutocomplete.getPlace();
        if (place.name) input.value = place.name;
      });
      setTimeout(function(){ var pacs = document.querySelectorAll('.pac-container'); pacs.forEach(function(p){ p.style.zIndex = '99999'; }); }, 300);
    } catch(e) {
      console.warn('City Places Autocomplete init failed:', e);
      _cityAutocomplete = null;
    }
  }

  var _selectedPlaceLat = null;
  var _selectedPlaceLng = null;
  var _travelTimeCache = {};

  function getTravelTime(originLat, originLng, destLat, destLng, callback) {
    var cacheKey = originLat.toFixed(5) + ',' + originLng.toFixed(5) + '->' + destLat.toFixed(5) + ',' + destLng.toFixed(5);
    if (_travelTimeCache[cacheKey]) { callback(_travelTimeCache[cacheKey]); return; }
    if (typeof google === 'undefined' || !google.maps || !google.maps.DistanceMatrixService) { callback(null); return; }
    var service = new google.maps.DistanceMatrixService();
    var origin = new google.maps.LatLng(originLat, originLng);
    var dest = new google.maps.LatLng(destLat, destLng);
    // 먼저 도보 시도
    service.getDistanceMatrix({
      origins: [origin], destinations: [dest], travelMode: 'WALKING'
    }, function(res, status) {
      if (status !== 'OK' || !res.rows[0] || !res.rows[0].elements[0] || res.rows[0].elements[0].status !== 'OK') { callback(null); return; }
      var walkEl = res.rows[0].elements[0];
      var walkMin = Math.round(walkEl.duration.value / 60);
      // 도보 20분 이내면 도보로
      if (walkMin <= 20) {
        var result = { mode: 'walk', duration: walkEl.duration.text, distance: walkEl.distance.text };
        _travelTimeCache[cacheKey] = result;
        callback(result);
      } else {
        // 대중교통으로 재검색
        service.getDistanceMatrix({
          origins: [origin], destinations: [dest], travelMode: 'TRANSIT'
        }, function(res2, status2) {
          if (status2 === 'OK' && res2.rows[0] && res2.rows[0].elements[0] && res2.rows[0].elements[0].status === 'OK') {
            var transitEl = res2.rows[0].elements[0];
            var result = { mode: 'transit', duration: transitEl.duration.text, distance: transitEl.distance.text };
            _travelTimeCache[cacheKey] = result;
            callback(result);
          } else {
            // 대중교통 실패 시 도보 결과 사용
            var result = { mode: 'walk', duration: walkEl.duration.text, distance: walkEl.distance.text };
            _travelTimeCache[cacheKey] = result;
            callback(result);
          }
        });
      }
    });
  }

  // ─── 콘솔 도구: 기념품 진단/정리 ───
  // 현재 기념품 데이터 확인
  window._listSouvenirs = function() {
    var arr = (journeyData||[]).filter(function(j){return j.type==='기념품';});
    console.log('═══ 현재 트립 기념품 ' + arr.length + '개 ═══');
    console.table(arr.map(function(s){
      return {
        city: s.city || '(없음)',
        대상: s.title || '',
        품목: (s.description||'').slice(0,50),
        가격: s.amount || '',
        장소: s.location || '',
        date: s.date || '',
        time: s.time || '',
        _id: s._id
      };
    }));
    // 도시별 카운트
    var byCity = {};
    arr.forEach(function(s){ var c = s.city||'(없음)'; byCity[c] = (byCity[c]||0) + 1; });
    console.log('도시별:', byCity);
    // 현재 트립 도시 목록도 출력 (매칭 확인용)
    console.log('현재 트립 도시:', (citiesData||[]).map(function(c){return c.name;}));
  };

  // 기념품 city 일괄 수정 (오타/이름 불일치 정정)
  window._fixSouvenirCity = async function(oldCity, newCity) {
    var arr = (journeyData||[]).filter(function(j){return j.type==='기념품' && j.city === oldCity;});
    if (arr.length === 0) { console.log('해당 city 기념품 없음:', oldCity); return; }
    var ok = 0;
    for (var i = 0; i < arr.length; i++) {
      try { await fbUpdate('journey', arr[i]._id, {city: newCity}); arr[i].city = newCity; ok++; } catch(e){}
    }
    console.log('✓ ' + ok + '개 city 변경:', oldCity, '→', newCity);
    if (typeof renderWeekView==='function') renderWeekView();
    if (typeof renderDayView==='function') renderDayView();
    if (typeof renderJourneySouvenir==='function') renderJourneySouvenir();
  };

  // ─── 매트릭스 ↔ 작품 동기화 진단/복구 도구 ───
  // 1) 진단: 어디서 데이터가 끊겼는지 확인
  window._diagnoseMatrix = function() {
    if (typeof loadWorks === 'function') loadWorks();
    var works = (typeof _works !== 'undefined' && _works) ? _works : [];
    var pData = (typeof plannerData !== 'undefined' && plannerData) ? plannerData : [];
    var publishingRows = pData.filter(function(r){ return ((r[4]||'').toString()).indexOf('phase:publishing') >= 0; });
    var matrixYr = (typeof _matrixYear !== 'undefined') ? _matrixYear : new Date().getFullYear();

    console.log('═══════════════════════════════════════════');
    console.log('📊 매트릭스 동기화 진단');
    console.log('═══════════════════════════════════════════');
    console.log('1. 작품 (_works) 총 ' + works.length + '개');
    console.table(works.map(function(w){
      return { title: w.title, series: w.series_name, status: w.status||'draft', start: w.publish_start||'-', end: w.publish_end||'-' };
    }));
    console.log('2. 캘린더(plannerData)에 \'phase:publishing\' 표시된 일정 ' + publishingRows.length + '개');
    if (publishingRows.length) {
      console.table(publishingRows.slice(0,30).map(function(r){
        return { date: r[0], episode: r[1], notes: (r[4]||'').slice(0,60) };
      }));
    } else {
      console.warn('⚠️ phase:publishing 일정이 0개. 작품이 캘린더에 sync 안 됨 → 매트릭스 에피소드가 비어 있을 것');
    }
    console.log('3. 매트릭스(' + matrixYr + ') 시리즈별 월간 데이터');
    if (typeof getSeriesData === 'function') {
      getSeriesData(matrixYr).forEach(function(s) {
        var hasEps = 0;
        for (var k in s.monthly) if (s.monthly[k] && s.monthly[k].eps) hasEps++;
        console.log('  ▸', s.name, '— 에피소드 있는 월:', hasEps);
      });
    }
    console.log('═══════════════════════════════════════════');
    console.log('💡 복구 명령: _fullResyncWorks() — 모든 확정 작품을 캘린더+매트릭스에 강제 재동기화');
  };

  // 2) 강제 재동기화: 캘린더의 모든 publishing 일정을 비우고 모든 confirmed 작품으로 재구성
  // (work_id 마커 없는 옛 일정까지 정리해서 중복 100% 차단)
  window._fullResyncWorks = async function() {
    if (typeof loadWorks === 'function') loadWorks();
    var works = (typeof _works !== 'undefined' && _works) ? _works : [];
    var confirmed = works.filter(function(w){ return w.status === 'confirmed'; });
    console.log('═══ ' + confirmed.length + '개 확정 작품 재동기화 시작 ═══');
    if (confirmed.length === 0) {
      console.warn('⚠️ 확정 작품이 없음. 작품을 확정하지 않았다면 confirmWork(id)로 확정하세요.');
      console.log('미확정 작품 목록:', works.map(function(w){return w.title + ' (' + (w.status||'draft') + ')';}));
      return;
    }

    // ▶ 1단계: 캘린더의 모든 publishing/draft/synopsis/revision 작품 관련 일정을 모두 삭제 (work_id 유무 무관)
    var workNotePattern = /phase:(publishing|draft|synopsis|revision)|work_id:/;
    var toRemove = [];
    plannerData.forEach(function(row, idx) {
      if (workNotePattern.test((row[4]||'').toString())) toRemove.push(idx);
    });
    toRemove.sort(function(a, b) { return b - a; });
    var removedCount = 0;
    for (var i = 0; i < toRemove.length; i++) {
      var rid = plannerData[toRemove[i]][7];
      if (rid) { try { await fbDelete('planner', rid); removedCount++; } catch(e){} }
      plannerData.splice(toRemove[i], 1);
    }
    console.log('🗑️ 기존 작품 일정 ' + removedCount + '개 정리됨 (중복 방지)');

    // ▶ 2단계: 모든 confirmed 작품을 캘린더에 재추가
    var ok = 0, fail = 0;
    for (var j = 0; j < confirmed.length; j++) {
      var w = confirmed[j];
      try {
        if (typeof autoAddScheduleToCalendar === 'function') await autoAddScheduleToCalendar(w);
        ok++;
        console.log('✓', w.title);
      } catch(e) { fail++; console.error('실패:', w.title, e); }
    }

    // ▶ 3단계: 매트릭스 + 캘린더 + 타임라인 갱신
    if (typeof syncCalToMatrix === 'function') syncCalToMatrix();
    if (typeof renderIncomeMatrix === 'function') renderIncomeMatrix();
    if (typeof renderCalendar === 'function') renderCalendar();
    if (typeof renderWorkTimeline === 'function') renderWorkTimeline();

    // ▶ 4단계: 안전망 — 혹시 모를 누적 중복 자동 정리
    var dupCleaned = 0;
    if (typeof cleanupDuplicateWorkEvents === 'function') {
      try { dupCleaned = await cleanupDuplicateWorkEvents(); } catch(e) { console.warn('dedupe failed', e); }
    }

    console.log('═══ 완료: ' + ok + '개 sync' + (fail ? ', ' + fail + '개 실패' : '') + ', 기존 ' + removedCount + '개 정리됨, 중복 ' + dupCleaned + '개 추가 정리 ═══');
    if (typeof showSyncToast === 'function') showSyncToast('🔄 ' + ok + '개 작품 재동기화' + (dupCleaned > 0 ? ' (중복 ' + dupCleaned + '개 정리)' : ''));
  };

  // 중복 기념품 자동 제거 (city + 대상 + 품목 + 가격이 동일하면 중복으로 판단)
  window._dedupeSouvenirs = async function() {
    var arr = (journeyData||[]).filter(function(j){return j.type==='기념품';});
    var seen = {}; var toDelete = [];
    arr.forEach(function(s){
      var key = (s.city||'') + '|' + (s.title||'') + '|' + (s.description||'') + '|' + (s.amount||'');
      if (seen[key]) {
        toDelete.push(s);
      } else {
        seen[key] = true;
      }
    });
    if (toDelete.length === 0) {
      console.log('🎉 중복 없음 (' + arr.length + '개 모두 고유)');
      if (typeof showSyncToast === 'function') showSyncToast('중복 없음');
      return;
    }
    console.log('🗑️ 중복 ' + toDelete.length + '개 발견 (전체 ' + arr.length + '개 중)');
    console.table(toDelete.map(function(s){return {city:s.city, 대상:s.title, 품목:(s.description||'').slice(0,40), id:s._id};}));
    if (!confirm('중복 ' + toDelete.length + '개를 삭제할까요?\n각 항목당 첫 번째만 남고 나머지는 삭제됩니다.')) {
      console.log('취소됨');
      return;
    }
    var ok = 0, fail = 0;
    for (var i = 0; i < toDelete.length; i++) {
      try {
        await fbDelete('journey', toDelete[i]._id);
        var idx = journeyData.findIndex(function(j){ return j._id === toDelete[i]._id; });
        if (idx >= 0) journeyData.splice(idx, 1);
        ok++;
      } catch(e) { console.error('삭제 실패:', toDelete[i]._id, e); fail++; }
    }
    console.log('✅ ' + ok + '개 삭제 완료' + (fail ? ', 실패 ' + fail : ''));
    if (typeof renderWeekView === 'function') renderWeekView();
    if (typeof renderDayView === 'function') renderDayView();
    if (typeof renderJourneySouvenir === 'function') renderJourneySouvenir();
    if (typeof updateTravelMiniSummary === 'function') updateTravelMiniSummary();
    if (typeof showSyncToast === 'function') showSyncToast('🧹 중복 ' + ok + '개 삭제됨');
  };

  // 현재 트립의 모든 기념품 삭제 (중복 추가 등 초기화용)
  window._clearAllSouvenirs = async function() {
    if (!confirm('현재 트립의 모든 기념품을 삭제할까요?')) return;
    var arr = (journeyData||[]).filter(function(j){return j.type==='기념품';});
    var ok = 0;
    for (var i = 0; i < arr.length; i++) {
      try { await fbDelete('journey', arr[i]._id); ok++; } catch(e){}
    }
    // journeyData에서도 제거
    for (var j = journeyData.length - 1; j >= 0; j--) {
      if (journeyData[j].type === '기념품') journeyData.splice(j, 1);
    }
    console.log('✓ ' + ok + '개 기념품 삭제됨');
    if (typeof renderWeekView==='function') renderWeekView();
    if (typeof renderDayView==='function') renderDayView();
    if (typeof renderJourneySouvenir==='function') renderJourneySouvenir();
  };

  // ─── 콘솔 도구: 기념품 일괄 추가 ───
  // 사용: _addSouvenirs([{city,item,target,amount,location,time,date}, ...])
  window._addSouvenirs = async function(list) {
    if (!Array.isArray(list) || !list.length) {
      console.log('사용법: _addSouvenirs([{city, item, target, amount, location?, time?, date?}, ...])');
      return;
    }
    var ok = 0, fail = 0;
    for (var i = 0; i < list.length; i++) {
      var s = list[i];
      var obj = {
        trip_id: currentTripId, type: '기념품',
        title: s.target || '나',
        description: s.item || '',
        city: s.city || '',
        amount: String(s.amount||''),
        location: s.location || '',
        time: s.time || '',
        date: s.date || ''
      };
      try {
        var saved = await fbAdd('journey', obj);
        journeyData.push(saved);
        ok++;
        console.log('✓', s.city, '-', s.item);
      } catch(e) { fail++; console.error('실패:', s, e); }
    }
    if (typeof renderJourneySouvenir === 'function') renderJourneySouvenir();
    if (typeof renderWeekView === 'function') renderWeekView();
    if (typeof renderDayView === 'function') renderDayView();
    if (typeof updateTravelMiniSummary === 'function') updateTravelMiniSummary();
    console.log('═══ 완료: ' + ok + '개 추가됨' + (fail ? ', 실패 ' + fail : ''));
    if (typeof showSyncToast === 'function') showSyncToast('🛍 ' + ok + '개 기념품 추가됨');
  };

  // ─── 콘솔 도구: 도시 교통편 일괄 입력 ───
  // 사용 예: window._setCityTransit({ Frankfurt: '수단: S-Bahn 편도 €6 · ...', Berlin: '...' })
  window._setCityTransit = async function(map) {
    if (!map || typeof map !== 'object') {
      console.log('사용법: _setCityTransit({ "Frankfurt": "수단: S-Bahn ...", "Berlin": "수단: BVG ..." })');
      console.log('현재 도시들:', (citiesData||[]).map(function(c){return c.name;}));
      return;
    }
    var done = 0, miss = [];
    var keys = Object.keys(map);
    for (var i = 0; i < keys.length; i++) {
      var keyword = keys[i];
      var guide = map[keyword];
      var matches = (citiesData||[]).filter(function(c){
        return (c.name||'').toLowerCase().indexOf(keyword.toLowerCase()) >= 0;
      });
      if (matches.length === 0) { miss.push(keyword); continue; }
      for (var j = 0; j < matches.length; j++) {
        var c = matches[j];
        try {
          await fbUpdate('trip_cities', c._id, { transit_guide: guide });
          c.transit_guide = guide;
          console.log('✓', c.name, '←', keyword);
          done++;
        } catch(e) { console.error('실패:', c.name, e); }
      }
    }
    if (typeof renderDayView === 'function') renderDayView();
    if (typeof renderWeekView === 'function') renderWeekView();
    if (typeof renderCityCards === 'function') renderCityCards();
    console.log('═══ 완료: ' + done + '개 도시 교통편 저장됨' + (miss.length ? ', 매칭 안 됨: ' + miss.join(', ') : ''));
    if (typeof showSyncToast === 'function') showSyncToast('🚆 ' + done + '개 도시 교통편 저장됨');
  };

  // 현재 트립의 모든 도시에 한 번에 빈 transit_guide 세팅 보장 (호환성)
  window._listCityTransits = function() {
    console.log('═══ 현재 트립 도시별 교통편 ═══');
    (citiesData||[]).forEach(function(c){
      console.log(c.name + ': ' + (c.transit_guide ? c.transit_guide.slice(0,80) + '...' : '(비어있음)'));
    });
  };

  var _scheduleAutocomplete = null;
  function initSchedulePlacesAutocomplete() {
    try {
      var input = document.getElementById('jf-title');
      if (!input || !input.dataset.autocomplete || typeof google === 'undefined' || typeof google.maps === 'undefined' || typeof google.maps.places === 'undefined') return;
      if (_scheduleAutocomplete) { try { google.maps.event.clearInstanceListeners(_scheduleAutocomplete); } catch(e){} _scheduleAutocomplete = null; }
      _scheduleAutocomplete = new google.maps.places.Autocomplete(input, {
        types: ['establishment'],
        fields: ['name', 'formatted_address', 'geometry'],
      });
      _scheduleAutocomplete.addListener('place_changed', function() {
        var place = _scheduleAutocomplete.getPlace();
        if (place.name) input.value = place.name;
        var descEl = document.getElementById('jf-desc');
        if (descEl && place.formatted_address && !descEl.value) descEl.value = place.formatted_address;
        if (place.geometry && place.geometry.location) {
          _selectedPlaceLat = place.geometry.location.lat();
          _selectedPlaceLng = place.geometry.location.lng();
        }
      });
      setTimeout(function(){ var pacs = document.querySelectorAll('.pac-container'); pacs.forEach(function(p){ p.style.zIndex = '99999'; }); }, 300);
    } catch(e) {
      console.warn('Schedule Places Autocomplete init failed:', e);
      _scheduleAutocomplete = null;
    }
  }

  function toggleCancelDate() {
    var val = document.getElementById('jf-cancel') ? document.getElementById('jf-cancel').value : '';
    var wrap = document.getElementById('wrap-jf-cancel-date');
    if (wrap) wrap.style.display = val === '가능' ? 'block' : 'none';
  }

  function closeJourneyModal() {
    document.getElementById('journey-modal').style.cssText = 'display:none!important';
    currentJourneyType = null;
  }

  // ===== TRAVEL 인라인 폼 → 모달 헬퍼 =====
  function openTravelModal(id) {
    var el = document.getElementById(id);
    if (el) el.style.cssText = 'display:flex!important';
  }
  function closeTravelModal(id) {
    var el = document.getElementById(id);
    if (el) el.style.cssText = 'display:none!important';
  }
  function openFlightAddModal() {
    openTravelModal('flight-add-modal-wrap');
    // 신규 항공편 추가 시 결제일을 오늘로 기본 설정 (탑승일이 아닌 결제일 기준 budget 등록)
    var pd = document.getElementById('flt-payment-date');
    if (pd && !pd.value) {
      var now = new Date();
      pd.value = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0') + '-' + String(now.getDate()).padStart(2,'0');
    }
  }

