  // 기존 기념품에 설명(note) 한 줄씩 추가 (description 두 번째 라인)
  window.addSouvenirNotes2026 = async function() {
    var trip = (typeof tripsData !== 'undefined' ? tripsData : []).find(function(t){return t.name==='2026 독일&이탈리아';})
            || (typeof getCurrentTrip === 'function' && getCurrentTrip() && getCurrentTrip().name === '2026 독일&이탈리아' ? getCurrentTrip() : null);
    if (!trip || !trip._id) { alert('"2026 독일&이탈리아" 트립을 못 찾았어요.'); return; }
    // 품목명 keyword → note 매핑
    var noteMap = [
      {match:/가죽/, note:'질 좋은 가죽 특산지. 로고 없는 클래식.'},
      {match:/마비스|Marvis/i, note:'치약계의 샤넬. 사무실 책상에 두기 좋음.'},
      {match:/포켓 ?커피|Pocket ?Coffee/i, note:'10월부터 마트 풀림. 부피 작아 돌리기 최고.'},
      {match:/사비니|Savini|트러플/i, note:'짜파게티/감튀에 뿌리면 감동. 마성의 조미료.'},
      {match:/암펠만|Ampelmann/i, note:'베를린 한정. 귀여운 굿즈, 은근히 힙함.'},
      {match:/아트북|포스터|엽서/, note:'타이포·레이아웃 미친 베를린 현대 미술.'},
      {match:/세라믹|타일/, note:'레몬·올리브 패턴. 이탈리아 햇살 느낌.'},
      {match:/비알레띠|Bialetti|모카포트/i, note:'주방 인테리어 완성. 클래식 디자인 아이콘.'},
    ];
    var existing = (journeyData||[]).filter(function(d){ return d.trip_id === trip._id && d.type === '기념품'; });
    if (!existing.length) { alert('기념품 항목이 없어요. 먼저 import 하세요.'); return; }
    var ok = 0;
    for (var i = 0; i < existing.length; i++) {
      var item = existing[i];
      var desc = item.description || '';
      // 이미 \n 있으면 skip
      if (desc.indexOf('\n') >= 0) continue;
      var note = '';
      for (var k = 0; k < noteMap.length; k++) {
        if (noteMap[k].match.test(desc)) { note = noteMap[k].note; break; }
      }
      if (!note) continue;
      var newDesc = desc + '\n' + note;
      try {
        await fbUpdate('journey', item._id, { description: newDesc });
        item.description = newDesc;
        ok++;
      } catch(e) { console.error(e); }
    }
    alert(ok + '개 항목에 설명 추가 완료!');
    if (typeof renderJourneySouvenir === 'function') renderJourneySouvenir();
  };

  // 잘못된 기념품 import 정리 + 깔끔하게 재등록
  window.redoSouvenirsImport2026 = async function() {
    var trip = (typeof tripsData !== 'undefined' ? tripsData : []).find(function(t){return t.name==='2026 독일&이탈리아';})
            || (typeof getCurrentTrip === 'function' && getCurrentTrip() && getCurrentTrip().name === '2026 독일&이탈리아' ? getCurrentTrip() : null);
    if (!trip || !trip._id) { alert('"2026 독일&이탈리아" 트립을 못 찾았어요.'); return; }
    if (!confirm('기존 기념품 항목을 모두 삭제하고 깔끔하게 다시 등록합니다. 계속할까요?')) return;
    var existing = (journeyData||[]).filter(function(d){ return d.trip_id === trip._id && d.type === '기념품'; });
    var delOk = 0;
    for (var i = 0; i < existing.length; i++) {
      try { await fbDelete('journey', existing[i]._id); delOk++; } catch(e) { console.error(e); }
    }
    var items = [
      {recipient:'나 & 가족', item:'수제 가죽 가방/지갑/벨트', city:'Pienza', amount:'150'},
      {recipient:'직장 동료', item:'마비스(Marvis) 치약', city:'이탈리아 약국', amount:'5'},
      {recipient:'직장 동료', item:'포켓 커피(Pocket Coffee) 박스', city:'이탈리아 마트', amount:'6'},
      {recipient:'찐친/후배', item:'사비니(Savini) 트러플 소금/오일', city:'Italy', amount:'15'},
      {recipient:'찐친/후배', item:'암펠만 굿즈 (에코백/키링)', city:'Berlin', amount:'15'},
      {recipient:'디자이너 픽', item:'아트북·포스터·엽서', city:'Berlin', amount:'30'},
      {recipient:'디자이너 픽', item:'토스카나 세라믹 (타일/컵/접시)', city:'Pienza', amount:'30'},
      {recipient:'디자이너 픽', item:'비알레띠(Bialetti) 모카포트', city:'Italy', amount:'40'},
    ];
    var addOk = 0;
    for (var j = 0; j < items.length; j++) {
      var s = items[j];
      try {
        await fbAdd('journey', {
          trip_id: trip._id, type: '기념품',
          title: s.recipient, description: s.item, city: s.city,
          amount: s.amount, status: ''
        });
        addOk++;
      } catch(e) { console.error(e); }
    }
    // 상세 가이드는 트립 노트에 append
    var guide = '\n\n---\n\n## 🛍️ 기념품 쇼핑 가이드\n\n' +
      '### 나 & 가족 (오래 쓸 것)\n' +
      '- **토스카나 로컬 가죽 공방 (피엔차)** — 수제 가죽 가방/지갑/벨트 (€50~150)\n' +
      '  - 질 좋은 가죽 특산지. 브랜드 로고 없는 클래식하고 탄탄한 가죽 제품.\n\n' +
      '### 직장 동료 (팀원 10명)\n' +
      '- **마비스(Marvis) 치약** — 클래식 민트/자스민 (€3~5)\n' +
      '  - 치약계의 샤넬. 한국보다 저렴. 사무실 책상에 두기 좋음. 호불호 없음.\n' +
      '- **포켓 커피(Pocket Coffee)** — 에스프레소 든 초콜릿 박스 (€3~6)\n' +
      '  - 10월부터 마트 풀림. 피곤한 오후 직장인들의 빛과 소금. 부피 작아 돌리기 최고.\n\n' +
      '### 찐친 / 후배 (센스 있는 것)\n' +
      '- **사비니(Savini) 트러플** — 트러플 소금·오일 (€8~15)\n' +
      '  - 짜파게티/감튀에 뿌리면 감동하는 마성의 조미료.\n' +
      '- **암펠만(Ampelmännchen)** — 베를린 신호등 캐릭터 굿즈 (€5~15)\n' +
      '  - 베를린에서만. 귀여운 에코백/키링. 은근히 힙함.\n\n' +
      '### 디자이너 픽 (소장용)\n' +
      '- **보로스 컬렉션·독립 서점 (베를린 미테)** — 아트북·전시 포스터·엽서 (다양)\n' +
      '  - 타이포그래피/레이아웃 미친 베를린 현대 미술 서적. 영감 수집용.\n' +
      '- **토스카나 세라믹 (피엔차/시에나)** — 핸드페인팅 타일·컵·접시 (€10~30)\n' +
      '  - 선명한 색감의 레몬/올리브 패턴. 이탈리아 햇살 느낌.\n' +
      '- **비알레띠(Bialetti)** — 모카포트 (오리지널/컬러) (€25~40)\n' +
      '  - 주방 인테리어의 완성. 클래식 디자인 아이콘.';
    var existingNotes = trip.notes || '';
    if (existingNotes.indexOf('## 🛍️ 기념품 쇼핑 가이드') < 0) {
      var newNotes = existingNotes + guide;
      try {
        await fbUpdate('trips', trip._id, { notes: newNotes, notesUpdatedAt: new Date().toISOString() });
        trip.notes = newNotes;
      } catch(e) { console.error(e); }
    }
    alert('기존 ' + delOk + '개 삭제, 새로 ' + addOk + '개 추가 완료. 상세 가이드는 트립 노트에 추가됨.');
    if (typeof loadJourney === 'function') await loadJourney();
  };

