  async function loadDashboard() {
    var now = new Date();
    var MONTHS_EN = ['January','February','March','April','May','June','July','August','September','October','November','December'];
    var DAY_KR = ['일요일','월요일','화요일','수요일','목요일','금요일','토요일'];
    var todayStr = now.toISOString().split('T')[0];

    // 시간대별 인사말
    var hour = now.getHours();
    var greeting = hour < 6 ? '편안한 밤 보내세요.' :
                   hour < 12 ? '좋은 아침이에요. ☀️' :
                   hour < 18 ? '좋은 오후예요.' :
                   '편안한 저녁이에요. 🌙';
    var greetEl = document.getElementById('dash-greeting');
    if (greetEl) greetEl.textContent = greeting;
    // 시간대별 영문 태그라인
    var tagline = hour < 6 ? 'Rest well, recharge.' :
                  hour < 12 ? 'Your day is looking productive.' :
                  hour < 18 ? 'Keep the momentum going.' :
                  'Time to wind down.';
    var tagEl = document.getElementById('dash-brief-tagline');
    if (tagEl) tagEl.textContent = ' — ' + tagline;
    // 브리프 날짜 (친근한 형식)
    var bdEl = document.getElementById('dash-brief-date');
    if (bdEl) bdEl.textContent = now.getFullYear() + '년 ' + (now.getMonth()+1) + '월 ' + now.getDate() + '일 ' + DAY_KR[now.getDay()];
    // Footer
    var ft = document.getElementById('dash-footer');
    if (ft) ft.textContent = MONTHS_EN[now.getMonth()] + ' ' + now.getFullYear() + ' · Curating everyday moments';

    try {
      var [plannerDocs, hubDocs, tripDocs, vaultDocs, sessionDocs, matrixDocs, journeyDocs, refDocs] = await Promise.all([
        fbRead('planner'), fbRead('finance_hub'), fbRead('trips'), fbRead('vaultExpressions'),
        fbRead('englishSessions'), fbRead('matrix'), fbRead('journey'), fbRead('refCards')
      ]);
      var plannerRows = plannerDocs.map(function(d){ return objToRow('planner', d); });
      var hubRows = hubDocs.map(function(d){ return objToRow('finance_hub', d); });

      // 기존 카드들
      renderDashExpr(sessionDocs);
      renderDashWeek(plannerRows, now, todayStr);
      renderDashTravel(tripDocs, todayStr);
      renderDashVacation(matrixDocs);
      renderDashVaultStats(vaultDocs, now);
      renderDashFinance(hubRows);

      // ─── 새 미니 카드들 ───
      renderDashMiniEvents(plannerRows, todayStr);
      renderDashMiniTrip(tripDocs, journeyDocs, todayStr);
      renderDashMiniWorks();
      renderDashFxWidget(tripDocs, journeyDocs);
      renderDashBizSchedule(plannerRows, now);
      renderDashRecentMemos(refDocs);
      renderDashNews();

      // ─── AI 데일리 브리프 (자동, 24h 캐시) ───
      generateDailyBrief(false, { plannerRows: plannerRows, hubRows: hubRows, tripDocs: tripDocs, journeyDocs: journeyDocs });

      // ─── Hero stat 칩 미러링 (기존 카드 값을 hero에 복사) ───
      setTimeout(function() {
        var src1 = document.getElementById('dash-mini-events-count');
        var dst1 = document.getElementById('dash-hero-events-count');
        if (src1 && dst1) dst1.textContent = src1.textContent;
        var src2 = document.getElementById('dash-mini-works-count');
        var dst2 = document.getElementById('dash-hero-works-count');
        if (src2 && dst2) dst2.textContent = src2.textContent;
        var src3 = document.getElementById('dash-vac-remain');
        var dst3 = document.getElementById('dash-hero-vac');
        if (src3 && dst3) dst3.textContent = src3.textContent;
      }, 200);
    } catch(err) { console.error('Dashboard load error:', err); }
  }

  var _dashExprPool = [];
  function renderDashExpr(sessions) {
    var enEl = document.getElementById('dash-expr-en');
    var krEl = document.getElementById('dash-expr-kr');
    var ctxEl = document.getElementById('dash-expr-ctx');
    // Build pool from all sessions' expressions
    _dashExprPool = [];
    (sessions||[]).forEach(function(s) {
      (s.expressions||[]).forEach(function(e) {
        _dashExprPool.push({ english: e.expr||'', korean: e.kr||'', context: e.ex||'', cat: e.cat||'', sessionId: s._id, title: s.title||'' });
      });
    });
    if (!_dashExprPool.length) {
      enEl.textContent = '"영어 수업 리뷰를 추가하면 여기에 표현이 표시됩니다"';
      krEl.textContent = ''; ctxEl.textContent = '';
      return;
    }
    var idx; do { idx = Math.floor(Math.random()*_dashExprPool.length); } while (idx === _dashExprIdx && _dashExprPool.length > 1);
    _dashExprIdx = idx;
    var item = _dashExprPool[idx];
    enEl.innerHTML = formatSentences(item.english, 3);
    krEl.innerHTML = formatSentences(item.korean, 3);
    ctxEl.textContent = (item.cat ? '[' + item.cat + '] ' : '') + (item.context || '');
  }
  function shuffleDashExpr() {
    if (!_dashExprPool.length) return;
    var enEl = document.getElementById('dash-expr-en');
    var krEl = document.getElementById('dash-expr-kr');
    var ctxEl = document.getElementById('dash-expr-ctx');
    var idx; do { idx = Math.floor(Math.random()*_dashExprPool.length); } while (idx === _dashExprIdx && _dashExprPool.length > 1);
    _dashExprIdx = idx;
    var item = _dashExprPool[idx];
    enEl.innerHTML = formatSentences(item.english, 3);
    krEl.innerHTML = formatSentences(item.korean, 3);
    ctxEl.textContent = (item.cat ? '[' + item.cat + '] ' : '') + (item.context || '');
  }

  function renderDashSchedule(rows, todayStr, trips) {
    var el = document.getElementById('dash-today-events');
    var todayEvents = rows.filter(function(r) {
      var start = (r[0]||'').toString(), end = (r[5]||'').toString();
      if (end && end > start) return todayStr >= start && todayStr <= end;
      return start === todayStr;
    });
    // D-day for trips
    var ddays = (trips||[]).filter(function(t){
      return t.start_date && t.start_date > todayStr;
    }).map(function(t){
      var diff = Math.ceil((new Date(t.start_date) - new Date(todayStr))/(86400000));
      return { name: t.name, diff: diff };
    }).sort(function(a,b){ return a.diff - b.diff; }).slice(0,1);

    if (!todayEvents.length && !ddays.length) {
      el.innerHTML = '<p class="text-sm text-[#494454]/60">오늘 일정 없음 — 편안한 하루 되세요</p>';
      return;
    }
    el.innerHTML = todayEvents.slice(0,3).map(function(ev){
      return '<div class="flex items-center gap-4"><div class="w-2 h-10 rounded-full" style="background:#6b38d4"></div><div><h3 class="font-headline font-bold text-[#191c1d]">' + (ev[1]||'') + '</h3><p class="text-xs text-[#494454]">' + (ev[2]||'') + '</p></div></div>';
    }).join('') + ddays.map(function(dd){
      return '<div class="flex items-center gap-4"><div class="w-2 h-10 rounded-full" style="background:#a76500"></div><div><h3 class="font-headline font-bold text-[#191c1d]">' + dd.name + ' D-' + dd.diff + '</h3><p class="text-xs text-[#494454]">Check travel preparation</p></div></div>';
    }).join('');
  }

  var DASH_CAT_STYLE = {
    '업무':   'background:#f8bbd0;color:#c2185b', '연차':'background:#ffedd5;color:#c2410c',
    '개인':   'background:#fef3c7;color:#92400e', '글쓰기':'background:#e0f2fe;color:#0369a1',
    '영어':   'background:#d9f99d;color:#3f6212', '스터디':'background:#ede9fe;color:#6d28d9'
  };

  function renderDashWeek(rows, now, todayStr) {
    var grid = document.getElementById('dash-week-grid');
    var dayOfWeek = now.getDay();
    var monday = new Date(now); monday.setDate(now.getDate() - (dayOfWeek === 0 ? 6 : dayOfWeek - 1));
    var weekDates = [];
    for (var i = 0; i < 7; i++) { var d = new Date(monday); d.setDate(monday.getDate()+i); weekDates.push(d); }
    var DAYS = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'];
    document.getElementById('dash-week-range').textContent = (monday.getMonth()+1) + '/' + monday.getDate() + ' - ' + (weekDates[6].getMonth()+1) + '/' + weekDates[6].getDate();

    grid.innerHTML = weekDates.map(function(d, i){
      var ds = d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0');
      var isToday = ds === todayStr;
      var evts = rows.filter(function(r){ var s=(r[0]||'').toString(),e=(r[5]||'').toString(); if(e&&e>s) return ds>=s&&ds<=e; return s===ds; });
      if (isToday) {
        return '<div class="p-5 rounded-2xl space-y-3 ring-4" style="background:#8455ef;ring-color:rgba(107,56,212,0.1);box-shadow:0 8px 24px rgba(107,56,212,0.2)"><div class="text-center"><p class="text-xs font-bold text-white/80 uppercase tracking-widest">'+DAYS[i]+'</p><p class="text-lg font-headline font-extrabold text-white">'+d.getDate()+'</p></div>' +
          evts.slice(0,2).map(function(ev){ return '<div class="bg-white/20 px-2 py-1 rounded-lg text-[10px] font-bold text-white truncate">'+ev[1]+'</div>'; }).join('') + '</div>';
      }
      return '<div class="bg-white p-5 rounded-2xl space-y-3" style="box-shadow:0px 12px 32px rgba(25,28,29,0.02)"><div class="text-center"><p class="text-xs font-bold text-[#494454] uppercase tracking-widest">'+DAYS[i]+'</p><p class="text-lg font-headline font-extrabold text-[#191c1d]">'+d.getDate()+'</p></div>' +
        evts.slice(0,2).map(function(ev){
          var cs = DASH_CAT_STYLE[(ev[2]||'').trim()] || 'background:#e7e8e9;color:#191c1d';
          return '<div class="px-2 py-1 rounded-lg text-[10px] font-bold truncate" style="'+cs+'">'+ev[1]+'</div>';
        }).join('') + '</div>';
    }).join('');
  }

  // ===== TRIP IMAGE UPLOAD =====
  var _dashUpcomingTrips = [];
  var _tripUploadTarget = null; // 'hero' or 'next'

  function triggerTripUpload(target) {
    _tripUploadTarget = target;
    var input = document.getElementById('dash-trip-file-input');
    input.value = '';
    input.click();
  }

  function handleTripFileDrop(e, target) {
    var file = e.dataTransfer.files[0];
    if (file && file.type.startsWith('image/')) {
      _tripUploadTarget = target;
      handleTripFileSelect(file);
    }
  }

  async function handleTripFileSelect(file) {
    if (!file || !file.type.startsWith('image/')) return;
    if (file.size > 5 * 1024 * 1024) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 5MB 이하 이미지만 가능해요'); return; }
    var tripIdx = _tripUploadTarget === 'next' ? 1 : 0;
    var trip = _dashUpcomingTrips[tripIdx];
    if (!trip || !trip._id) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 여행 정보 없음'); return; }

    showSyncToast('<span class="material-symbols-outlined text-sm mr-1 animate-spin">progress_activity</span> 업로드 중...');
    try {
      var ext = file.name.split('.').pop() || 'jpg';
      var ref = storage.ref('trips/' + trip._id + '/cover.' + ext);
      var snap = await ref.put(file);
      var url = await snap.ref.getDownloadURL();
      await fbUpdate('trips', trip._id, { imageUrl: url });
      trip.imageUrl = url;
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 이미지가 업로드되었어요');
      loadDashboard();
    } catch(err) {
      console.error('[Upload]', err);
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 업로드 실패: ' + err.message);
    }
  }

  // Clipboard paste on hero card
  document.addEventListener('paste', function(e) {
    // Only on dashboard
    var dashPage = document.getElementById('page-dashboard');
    if (!dashPage || dashPage.style.display === 'none') return;
    var items = e.clipboardData && e.clipboardData.items;
    if (!items) return;
    for (var i = 0; i < items.length; i++) {
      if (items[i].type.startsWith('image/')) {
        var file = items[i].getAsFile();
        _tripUploadTarget = 'hero';
        handleTripFileSelect(file);
        break;
      }
    }
  });

  function renderDashTravel(trips, todayStr) {
    var upcoming = (trips||[]).filter(function(t){ return t.start_date && t.start_date >= todayStr; })
      .sort(function(a,b){ return a.start_date.localeCompare(b.start_date); });
    _dashUpcomingTrips = upcoming;
    var nameEl = document.getElementById('dash-travel-name');
    var metaEl = document.getElementById('dash-travel-meta');
    var creditEl = document.getElementById('dash-travel-credit');
    var heroEl = document.getElementById('dash-travel-hero');
    var nextEl = document.getElementById('dash-travel-next');

    // Reset next card to original HTML
    if (nextEl) nextEl.innerHTML = '<span class="material-symbols-outlined text-3xl mb-3" style="color:#544183">flight_takeoff</span><h3 id="dash-travel-next-name" class="text-xl font-headline font-bold leading-tight" style="color:#544183"></h3><p id="dash-travel-next-date" class="mt-1 text-sm" style="color:#4e3b7c"></p>';
    if (nextEl) { nextEl.style.background = '#c9b3fd'; nextEl.style.position = ''; }

    if (upcoming.length === 0) {
      if (nameEl) nameEl.textContent = '다음 여행을 계획해보세요';
      if (metaEl) metaEl.innerHTML = '';
      if (creditEl) creditEl.style.display = 'none';
      return;
    }
    var t = upcoming[0];
    var diff = Math.ceil((new Date(t.start_date) - new Date(todayStr))/86400000);
    if (nameEl) nameEl.textContent = t.name;
    if (metaEl) metaEl.innerHTML = '<span class="flex items-center gap-1"><span class="material-symbols-outlined text-sm">calendar_today</span>' + (t.start_date||'').slice(5) + ' - ' + (t.end_date||'').slice(5) + '</span><span class="bg-white/20 backdrop-blur-md px-3 py-1 rounded-full text-xs font-bold uppercase">D-' + diff + '</span>';
    if (heroEl) {
      if (t.imageUrl) {
        heroEl.style.background = 'url(' + t.imageUrl + ') center/cover no-repeat';
      } else {
        heroEl.style.background = 'linear-gradient(135deg,#6b38d4,#8455ef)';
      }
    }
    if (creditEl) creditEl.style.display = 'none';
    // Next trip
    if (upcoming.length > 1 && nextEl) {
      var t2 = upcoming[1];
      if (t2.imageUrl) {
        nextEl.style.background = 'url(' + t2.imageUrl + ') center/cover no-repeat';
        nextEl.style.position = 'relative';
        nextEl.innerHTML = '<div class="absolute inset-0 bg-black/40 rounded-2xl"></div><div class="relative z-10 mt-auto"><span class="material-symbols-outlined text-3xl mb-3 text-white/80">flight_takeoff</span><h3 class="text-xl font-headline font-bold leading-tight text-white">Next: ' + t2.name + '</h3><p class="mt-1 text-sm text-white/70">' + (t2.start_date||'') + '</p></div>';
      } else {
        var nn = document.getElementById('dash-travel-next-name');
        var nd = document.getElementById('dash-travel-next-date');
        if (nn) nn.textContent = 'Next: ' + t2.name;
        if (nd) nd.textContent = t2.start_date || '';
      }
    }
  }

  async function renderDashVacation(matrixDocs) {
    try {
      var yr = new Date().getFullYear();
      var doc = await db.collection('annualSettings').doc(String(yr)).get();
      var total = (doc.exists && doc.data().vacationTotal !== undefined) ? doc.data().vacationTotal : 17;
      var used = 0;
      (matrixDocs||[]).forEach(function(d){ var lv = (d.leave||'').toString(); var m = lv.match(/^([\d.]+)/); if(m) used += parseFloat(m[1]); });
      var remain = Math.max(0, total - used);
      document.getElementById('dash-vac-remain').textContent = remain.toFixed(remain%1?1:0);
      var pct = total > 0 ? Math.round(((total-used)/total)*100) : 0;
      document.getElementById('dash-vac-bar').style.width = Math.max(0,pct) + '%';
      document.getElementById('dash-vac-label').textContent = 'Used ' + used.toFixed(used%1?1:0) + ' of ' + total;
    } catch(e) {}
  }

  function renderDashVaultStats(docs, now) {
    // Vault 페이지 제거됨 — 호출처 호환을 위한 no-op
  }

  function renderDashFinance(_ignoredHubRows) {
    // Daily Ledger 트랜잭션 (atelier_ledger_transactions, 원 단위) 사용 — 가장 디테일한 실제 데이터
    var now = new Date();
    var thisMonth = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    var txs = [];
    // 1순위: 메모리(_ledgerData.transactions) — Daily Ledger 페이지 진입 시 로드됨
    if (typeof _ledgerData !== 'undefined' && _ledgerData && Array.isArray(_ledgerData.transactions)) {
      txs = _ledgerData.transactions;
    } else {
      // 2순위: localStorage
      try { txs = JSON.parse(localStorage.getItem('atelier_ledger_transactions') || '[]'); } catch(e) {}
    }
    var income=0, expense=0;
    txs.forEach(function(t) {
      var date = (t.date||'').toString();
      if (!date.startsWith(thisMonth)) return;
      if (t.excludeFromGoal === true) return; // 자산이동 제외 (Daily Ledger와 동일 로직)
      var amt = parseFloat(t['금액'] || 0) || 0;
      var major = t['대분류'] || '';
      if (major === '수입') income += amt;
      else if (major !== '저축') expense += amt; // 저축은 내부 이동이라 지출 아님
    });
    // 원 → 만으로 변환 후 포맷 (1억 이상이면 X억, 그 미만이면 X만)
    function fmtKRWFromWon(won) {
      if (!won) return '₩0';
      var manVal = won / 10000;
      var abs = Math.abs(manVal);
      if (abs >= 10000) return '₩' + (manVal / 10000).toFixed(2).replace(/\.?0+$/,'') + '억';
      return '₩' + Math.round(manVal).toLocaleString('ko-KR') + '만';
    }
    var inEl = document.getElementById('dash-income');
    var exEl = document.getElementById('dash-expense');
    var netEl = document.getElementById('dash-net');
    if (inEl) inEl.textContent = fmtKRWFromWon(income);
    if (exEl) exEl.textContent = fmtKRWFromWon(expense);
    var net = income - expense;
    if (netEl) {
      netEl.textContent = (net>=0?'+':'-') + fmtKRWFromWon(Math.abs(net));
      netEl.style.color = net >= 0 ? '#6b38d4' : '#dc2626';
    }
  }

  // ─── 미니 카드: 오늘 일정 (4-col grid 안) ───
  function renderDashMiniEvents(plannerRows, todayStr) {
    var todayEvents = plannerRows.filter(function(r){ return (r[0]||'').toString() === todayStr; });
    todayEvents.sort(function(a,b){ return (a[1]||'').localeCompare(b[1]||''); });
    var cntEl = document.getElementById('dash-mini-events-count');
    var listEl = document.getElementById('dash-mini-events');
    if (cntEl) cntEl.textContent = todayEvents.length;
    if (listEl) {
      if (todayEvents.length === 0) {
        listEl.innerHTML = '<span class="text-slate-400 italic">일정 없음</span>';
      } else {
        listEl.innerHTML = todayEvents.slice(0,3).map(function(r){
          var safe = String(r[1]||'').replace(/</g,'&lt;').slice(0,30);
          return '<div class="truncate">▸ ' + safe + '</div>';
        }).join('') + (todayEvents.length > 3 ? '<div class="text-slate-400">+' + (todayEvents.length-3) + '개</div>' : '');
      }
    }
  }

  // ─── 미니 카드: 다음 여행 D-day + 사전예약 ───
  function renderDashMiniTrip(tripDocs, journeyDocs, todayStr) {
    var trips = (tripDocs||[]).slice().sort(function(a,b){ return (a.start_date||'').localeCompare(b.start_date||''); });
    var next = trips.find(function(t){ return (t.start_date||'') >= todayStr; });
    var nameEl = document.getElementById('dash-mini-trip-name');
    var ddayEl = document.getElementById('dash-mini-trip-dday');
    var extraEl = document.getElementById('dash-mini-trip-extra');
    if (!next) {
      if (nameEl) nameEl.textContent = '예정 여행 없음';
      if (ddayEl) { ddayEl.textContent = '—'; ddayEl.className = 'text-[10px] text-slate-400'; }
      if (extraEl) extraEl.innerHTML = '';
      return;
    }
    if (nameEl) nameEl.textContent = next.name || '—';
    var diffDays = Math.ceil((new Date(next.start_date) - new Date(todayStr)) / 86400000);
    if (ddayEl) ddayEl.textContent = diffDays === 0 ? 'D-Day' : 'D-' + diffDays;
    // 사전 예약 / 결제일 임박 계산
    var tripJourneys = (journeyDocs||[]).filter(function(j){ return j.trip_id === next._id; });
    var prebookCount = tripJourneys.filter(function(j){
      if (j.type !== '일정') return false;
      var combo = ((j.title||'') + ' ' + (j.description||''));
      return j.prebook === true || j.reservation === true || /사전\s*예약|예약\s*필수|예매\s*필수/i.test(combo);
    }).length;
    var unpaidCount = tripJourneys.filter(function(j){
      return (j.type === '숙소' || j.type === '항공편' || j.type === '렌트카') && j.payment_status === '결제 예정';
    }).length;
    if (extraEl) {
      var parts = [];
      if (prebookCount > 0) parts.push('<div>📋 사전예약 ' + prebookCount + '건</div>');
      if (unpaidCount > 0) parts.push('<div>💳 결제예정 ' + unpaidCount + '건</div>');
      extraEl.innerHTML = parts.join('') || '<div class="text-slate-400">준비 완료 ✓</div>';
    }
  }

  // ─── 미니 카드: 작품 진행 (Series Timeline 연동) ───
  function renderDashMiniWorks() {
    if (typeof loadWorks === 'function') loadWorks();
    var works = (typeof _works !== 'undefined' && _works) ? _works.filter(function(w){ return w.status === 'confirmed'; }) : [];
    var todayStr = new Date().toISOString().split('T')[0];
    // 마감 임박: 30일 내 종료
    var deadlineSoon = works.filter(function(w){
      if (!w.publish_end) return false;
      var diff = Math.ceil((new Date(w.publish_end) - new Date(todayStr)) / 86400000);
      return diff >= 0 && diff <= 30;
    });
    // 현재 연재 중
    var ongoing = works.filter(function(w){
      return w.publish_start && w.publish_end && w.publish_start <= todayStr && w.publish_end >= todayStr;
    });
    var cntEl = document.getElementById('dash-mini-works-count');
    var listEl = document.getElementById('dash-mini-works');
    if (cntEl) cntEl.textContent = ongoing.length;
    if (listEl) {
      var parts = [];
      if (deadlineSoon.length) parts.push('<div class="text-rose-500">⏰ 마감임박 ' + deadlineSoon.length + '개</div>');
      if (ongoing.length) {
        ongoing.slice(0,2).forEach(function(w){
          parts.push('<div class="truncate">▸ ' + String(w.title||'').replace(/</g,'&lt;').slice(0,16) + '</div>');
        });
      } else if (deadlineSoon.length === 0) {
        parts.push('<span class="text-slate-400 italic">연재 작품 없음</span>');
      }
      listEl.innerHTML = parts.join('');
    }
  }

  // ─── 환율 위젯: 주요 통화 5개 강제 + 여행 통화 자동 감지 + 어제 대비 변동 ───
  async function renderDashFxWidget(tripDocs, journeyDocs) {
    var listEl = document.getElementById('dash-fx-list');
    var updEl = document.getElementById('dash-fx-updated');
    if (!listEl) return;
    // 주요 통화 5개 무조건 표시 + journey 데이터에서 추가 통화 감지
    var currencies = { 'USD': true, 'EUR': true, 'JPY': true, 'GBP': true, 'CAD': true };
    (journeyDocs||[]).forEach(function(j){
      ['amount','deposit','rental_deposit','notes','description'].forEach(function(field){
        var v = j[field];
        if (!v) return;
        var matches = String(v).match(/(EUR|USD|GBP|JPY|CNY|CHF|AUD|CAD|HKD|SGD|THB|NZD|TWD)/gi);
        if (matches) matches.forEach(function(c){ currencies[c.toUpperCase()] = true; });
      });
    });
    // 정렬 우선순위 (주요 5개 먼저, 그 다음 추가 통화)
    var priority = ['USD','EUR','JPY','GBP','CAD','CNY','CHF','AUD','HKD','SGD','THB','NZD','TWD'];
    var ccyList = priority.filter(function(c){ return currencies[c]; }).slice(0, 7); // 최대 7개

    var html = '';
    for (var i = 0; i < ccyList.length; i++) {
      var ccy = ccyList[i];
      try {
        var todayRate = await _fetchKrwRate(ccy);
        if (!todayRate) continue;
        // 어제 환율 (localStorage 캐시 또는 시뮬레이션)
        var yesterdayKey = 'atelier_fx_yest_' + ccy;
        var yesterdayRate = 0;
        try {
          var cached = JSON.parse(localStorage.getItem(yesterdayKey));
          // 캐시가 24시간 이상 된 경우만 어제 값으로 사용
          if (cached && cached.rate && (Date.now() - cached.fetchedAt > 12*3600000)) {
            yesterdayRate = cached.rate;
          }
        } catch(e){}
        // 오늘 환율을 어제 슬롯에 저장 (다음에 비교용)
        if (!yesterdayRate || (Date.now() - JSON.parse(localStorage.getItem(yesterdayKey)||'{}').fetchedAt > 12*3600000)) {
          localStorage.setItem(yesterdayKey, JSON.stringify({ rate: todayRate, fetchedAt: Date.now() }));
        }
        var diff = yesterdayRate ? (todayRate - yesterdayRate) : 0;
        var diffPct = yesterdayRate ? ((diff / yesterdayRate) * 100).toFixed(2) : '0.00';
        var diffColor = diff > 0 ? 'text-rose-500' : (diff < 0 ? 'text-emerald-500' : 'text-slate-400');
        var diffIcon = diff > 0 ? '▲' : (diff < 0 ? '▼' : '—');
        html += '<div class="flex items-center justify-between gap-2 text-[12px] py-1.5 border-b border-slate-50 last:border-b-0">' +
          '<span class="font-extrabold text-slate-700 w-10">' + ccy + '</span>' +
          '<span class="font-bold text-slate-900 flex-1 text-right">₩' + todayRate.toLocaleString('ko-KR') + '</span>' +
          '<span class="' + diffColor + ' font-bold text-[11px] text-right whitespace-nowrap">' + (yesterdayRate ? diffIcon + (diff>=0?'+':'') + diffPct + '%' : '<span class="text-slate-300 italic">—</span>') + '</span>' +
        '</div>';
      } catch(e) { console.warn('[fx widget]', ccy, e); }
    }
    listEl.innerHTML = html || '<div class="text-[10px] text-slate-400 italic">환율 정보 없음</div>';
    if (updEl) {
      var now = new Date();
      updEl.textContent = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0') + ' 갱신';
    }
  }

  // ─── 회사·업무 일정 (planner 카테고리=업무) ───
  function renderDashBizSchedule(plannerRows, now) {
    var listEl = document.getElementById('dash-biz-list');
    var cntEl = document.getElementById('dash-biz-count');
    if (!listEl) return;
    // 이번 주 ~ 다음 주 (14일 범위)
    var todayStr = now.toISOString().split('T')[0];
    var weekLater = new Date(now); weekLater.setDate(weekLater.getDate() + 14);
    var weekLaterStr = weekLater.toISOString().split('T')[0];
    var bizEvents = plannerRows.filter(function(r){
      var date = (r[0]||'').toString();
      var cat = (r[2]||'').toString();
      if (date < todayStr || date > weekLaterStr) return false;
      // 카테고리 매칭: 업무, 회사, 출장, 야근
      if (!/업무|회사|출장|야근|미팅|meeting|work/i.test(cat) && !/야근|출장|미팅|회의/i.test(r[1]||'')) return false;
      return true;
    });
    bizEvents.sort(function(a,b){ return (a[0]||'').localeCompare(b[0]||''); });
    if (cntEl) cntEl.textContent = bizEvents.length > 0 ? bizEvents.length + '건' : '';
    if (bizEvents.length === 0) {
      listEl.innerHTML = '<div class="text-[10px] text-slate-400 italic">2주 이내 업무 일정 없음 ✓</div>';
      return;
    }
    listEl.innerHTML = bizEvents.slice(0, 6).map(function(r){
      var date = (r[0]||'').toString();
      var title = String(r[1]||'').replace(/</g,'&lt;').slice(0,30);
      var cat = (r[2]||'');
      var dateShort = date.substring(5).replace('-','/');
      var dayDiff = Math.ceil((new Date(date) - new Date(todayStr)) / 86400000);
      var dlbl = dayDiff === 0 ? '오늘' : (dayDiff === 1 ? '내일' : 'D-' + dayDiff);
      var catColor = /야근/i.test(cat+title) ? 'bg-rose-100 text-rose-700' :
                     /출장/i.test(cat+title) ? 'bg-amber-100 text-amber-700' :
                     'bg-sky-100 text-sky-700';
      return '<div class="flex items-center gap-2 py-1 border-b border-slate-50 last:border-b-0">' +
        '<span class="text-[9px] font-bold w-12 ' + catColor + ' px-1.5 py-0.5 rounded text-center">' + dlbl + '</span>' +
        '<span class="flex-1 truncate text-slate-700">' + title + '</span>' +
        '<span class="text-[10px] text-slate-400 font-medium">' + dateShort + '</span>' +
      '</div>';
    }).join('');
  }

  // ─── 뉴스 헤드라인 (국내 경제+정치 + 해외 영어 + 한글 번역) — rss2json + Claude 번역 + 30분 캐시 ───
  async function renderDashNews() {
    var krEl = document.getElementById('dash-news-kr');
    var enEl = document.getElementById('dash-news-en');
    if (!krEl || !enEl) return;

    var cacheKey = 'atelier_news_cache_v2';
    // 30분 캐시
    try {
      var cached = JSON.parse(localStorage.getItem(cacheKey));
      if (cached && cached.fetchedAt && (Date.now() - cached.fetchedAt < 30*60*1000)) {
        _renderNewsList(krEl, cached.kr, 'ko');
        _renderNewsList(enEl, cached.en, 'en');
        return;
      }
    } catch(e){}

    // 한국 경제 + 정치 (한겨레 별도 RSS), 해외 BBC World — rss2json.com CORS 우회
    var econRss = 'https://api.rss2json.com/v1/api.json?rss_url=' + encodeURIComponent('https://www.hani.co.kr/rss/economy/');
    var politRss = 'https://api.rss2json.com/v1/api.json?rss_url=' + encodeURIComponent('https://www.hani.co.kr/rss/politics/');
    var enRss = 'https://api.rss2json.com/v1/api.json?rss_url=' + encodeURIComponent('http://feeds.bbci.co.uk/news/world/rss.xml');

    var krItems = [], enItems = [];
    try {
      var [econRes, politRes, enRes] = await Promise.all([
        fetch(econRss).then(function(r){ return r.json(); }).catch(function(){ return null; }),
        fetch(politRss).then(function(r){ return r.json(); }).catch(function(){ return null; }),
        fetch(enRss).then(function(r){ return r.json(); }).catch(function(){ return null; })
      ]);
      var econ = (econRes && econRes.items) ? econRes.items.slice(0,3).map(function(i){ i.section='경제'; return i; }) : [];
      var polit = (politRes && politRes.items) ? politRes.items.slice(0,3).map(function(i){ i.section='정치'; return i; }) : [];
      // 두 카테고리를 시간순으로 섞고 상위 5개
      krItems = econ.concat(polit).sort(function(a,b){ return new Date(b.pubDate||0) - new Date(a.pubDate||0); }).slice(0, 5);
      enItems = (enRes && enRes.items) ? enRes.items.slice(0, 5) : [];
      // Claude로 영어 뉴스 한글 번역 (API 키 있으면)
      if (enItems.length) await _translateNewsHeadlines(enItems);
      // 캐시
      try { localStorage.setItem(cacheKey, JSON.stringify({ kr: krItems, en: enItems, fetchedAt: Date.now() })); } catch(e){}
    } catch(e) { console.warn('[news]', e); }

    _renderNewsList(krEl, krItems, 'ko');
    _renderNewsList(enEl, enItems, 'en');
  }

  // 영어 헤드라인 한꺼번에 한글 번역 (한 번의 Claude 호출)
  async function _translateNewsHeadlines(items) {
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) return; // 키 없으면 번역 스킵
    var titles = items.map(function(i){ return String(i.title||''); });
    var prompt = '아래 영어 뉴스 헤드라인들을 자연스러운 한국어로 짧게(20자 내) 번역해. JSON 배열로만 응답:\n["번역1","번역2",...]\n\n원문:\n' + JSON.stringify(titles);
    try {
      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-6',
          max_tokens: 500,
          messages: [{ role: 'user', content: prompt }]
        })
      });
      if (!res.ok) return;
      var data = await res.json();
      var text = (data.content && data.content[0] && data.content[0].text || '').trim();
      var m = text.match(/\[[\s\S]*\]/);
      if (!m) return;
      var translations = JSON.parse(m[0]);
      items.forEach(function(it, i){ if (translations[i]) it.translation = translations[i]; });
    } catch(e) { console.warn('[translate news]', e); }
  }

  function _renderNewsList(el, items, lang) {
    if (!el) return;
    if (!items || !items.length) {
      el.innerHTML = '<div class="text-[11px] text-slate-400 italic">뉴스 로드 실패 (네트워크 확인)</div>';
      return;
    }
    el.innerHTML = items.slice(0, 5).map(function(item){
      var rawTitle = String(item.title||'').replace(/<[^>]+>/g, '');
      var title = rawTitle.replace(/</g,'&lt;').slice(0, 90);
      // 짧은 요약 (description에서 첫 문장만)
      var desc = String(item.description||'').replace(/<[^>]+>/g,'').replace(/</g,'&lt;').trim();
      if (desc.length > 100) desc = desc.substring(0, 100).split(/[.。]/)[0] + '...';
      var link = item.link || '#';
      var pubDate = item.pubDate ? new Date(item.pubDate) : null;
      var timeAgo = '';
      if (pubDate && !isNaN(pubDate)) {
        var diffHr = Math.floor((Date.now() - pubDate.getTime()) / 3600000);
        if (diffHr < 1) timeAgo = '방금';
        else if (diffHr < 24) timeAgo = diffHr + '시간 전';
        else timeAgo = Math.floor(diffHr/24) + '일 전';
      }
      if (lang === 'en') {
        // 영어 헤드라인 + 한글 번역 (있으면)
        var trans = item.translation ? '<div class="text-[11px] text-blue-600 mt-0.5 leading-snug">' + String(item.translation).replace(/</g,'&lt;') + '</div>' : '';
        return '<a href="' + link + '" target="_blank" rel="noopener" class="block hover:underline transition-colors py-1 border-b border-blue-100 last:border-b-0">' +
          '<div class="flex items-start gap-1.5">' +
            '<span class="text-blue-400 shrink-0">▸</span>' +
            '<div class="flex-1 min-w-0">' +
              '<div class="text-blue-900 font-medium leading-snug">' + title + '</div>' +
              trans +
            '</div>' +
            (timeAgo ? '<span class="text-[10px] text-blue-400/70 shrink-0 ml-1 mt-0.5">' + timeAgo + '</span>' : '') +
          '</div>' +
        '</a>';
      }
      // 국내 — 카테고리 뱃지 + 요약
      var sectionBadge = item.section ? '<span class="text-[9px] font-bold px-1.5 py-0.5 rounded ' + (item.section === '경제' ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700') + ' shrink-0 mr-1">' + item.section + '</span>' : '';
      return '<a href="' + link + '" target="_blank" rel="noopener" class="block hover:underline transition-colors py-1 border-b border-slate-100 last:border-b-0">' +
        '<div class="flex items-start gap-1.5">' +
          '<div class="flex-1 min-w-0">' +
            '<div class="flex items-center gap-1 flex-wrap">' +
              sectionBadge +
              '<span class="text-slate-800 font-medium leading-snug">' + title + '</span>' +
            '</div>' +
            (desc ? '<div class="text-[11px] text-slate-500 mt-0.5 leading-snug">' + desc + '</div>' : '') +
          '</div>' +
          (timeAgo ? '<span class="text-[10px] text-slate-400 shrink-0 ml-1 mt-0.5">' + timeAgo + '</span>' : '') +
        '</div>' +
      '</a>';
    }).join('');
  }

  // ─── 최근 메모 (refCards) ───
  function renderDashRecentMemos(refDocs) {
    var listEl = document.getElementById('dash-memo-list');
    if (!listEl) return;
    var memos = (refDocs||[]).slice().sort(function(a,b){
      var ta = (a.updatedAt||a.createdAt||'').toString();
      var tb = (b.updatedAt||b.createdAt||'').toString();
      return tb.localeCompare(ta);
    });
    if (memos.length === 0) {
      listEl.innerHTML = '<div class="text-[10px] text-slate-400 italic">메모 없음</div>';
      return;
    }
    listEl.innerHTML = memos.slice(0, 4).map(function(m){
      var title = String(m.title||'(제목 없음)').replace(/</g,'&lt;').slice(0,28);
      var pin = m.pinned ? '<span class="material-symbols-outlined text-amber-500" style="font-size:11px">push_pin</span>' : '';
      return '<div class="flex items-center gap-1.5 truncate"><span class="text-slate-400">▸</span>' + pin + '<span class="truncate text-slate-700">' + title + '</span></div>';
    }).join('');
  }

  // ─── AI 데일리 브리프 (Claude API, 24h 캐시) ───
  async function generateDailyBrief(forceRefresh, prefetched) {
    var contentEl = document.getElementById('dash-brief-content');
    var statusEl = document.getElementById('dash-brief-status');
    if (!contentEl) return;
    // v4 — 파스텔 컬러 사이클 적용, 옛 캐시 무효화
    var todayKey = 'atelier_brief_v4_' + new Date().toISOString().split('T')[0];
    // 캐시 확인 (오늘자)
    if (!forceRefresh) {
      try {
        var cached = JSON.parse(localStorage.getItem(todayKey));
        if (cached && cached.html) {
          contentEl.innerHTML = cached.html;
          if (statusEl) statusEl.textContent = '캐시 · ' + (cached.time||'');
          return;
        }
      } catch(e){}
    }
    // API 키 확인
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) {
      contentEl.innerHTML = '<div class="text-[11px] text-slate-500">⚙️ AI 브리프를 보려면 <button onclick="openApiSettingsModal()" class="underline font-bold text-violet-700">API 키 설정</button>이 필요해요.</div>';
      return;
    }
    // 로딩
    contentEl.innerHTML = '<div class="flex items-center gap-2 text-slate-500"><span class="material-symbols-outlined animate-spin" style="font-size:14px">progress_activity</span>분석 중...</div>';
    if (statusEl) statusEl.textContent = '생성 중';

    // 데이터 수집 (prefetched 있으면 재사용)
    var p = prefetched || {};
    try {
      if (!p.plannerRows) {
        var [pd, jd, td, hd] = await Promise.all([fbRead('planner'), fbRead('journey'), fbRead('trips'), fbRead('finance_hub')]);
        p.plannerRows = pd.map(function(d){ return objToRow('planner', d); });
        p.journeyDocs = jd; p.tripDocs = td;
        p.hubRows = hd.map(function(d){ return objToRow('finance_hub', d); });
      }
      var todayStr = new Date().toISOString().split('T')[0];
      var dayLater = new Date(); dayLater.setDate(dayLater.getDate() + 14);
      var horizonStr = dayLater.toISOString().split('T')[0];

      // 다음 여행
      var nextTrip = (p.tripDocs||[]).slice().sort(function(a,b){return (a.start_date||'').localeCompare(b.start_date||'');})
        .find(function(t){return (t.start_date||'') >= todayStr;});
      var tripSummary = nextTrip ? (nextTrip.name + ' (D-' + Math.ceil((new Date(nextTrip.start_date)-new Date(todayStr))/86400000) + ')') : '없음';

      // 사전 예약 / 결제 예정
      var prebookCount = 0, unpaidCount = 0;
      var prebookList = [];
      (p.journeyDocs||[]).forEach(function(j){
        if (!nextTrip || j.trip_id !== nextTrip._id) return;
        if (j.type === '일정') {
          var combo = ((j.title||'') + ' ' + (j.description||''));
          if (j.prebook === true || j.reservation === true || /사전\s*예약|예약\s*필수/i.test(combo)) {
            prebookCount++;
            if (prebookList.length < 5) prebookList.push((j.title||'').slice(0,30) + ' (' + (j.date||'') + ')');
          }
        }
        if ((j.type === '숙소' || j.type === '항공편' || j.type === '렌트카') && j.payment_status === '결제 예정') unpaidCount++;
      });

      // 이번 주 일정 + 업무
      var thisWeek = (p.plannerRows||[]).filter(function(r){
        return (r[0]||'').toString() >= todayStr && (r[0]||'').toString() <= horizonStr;
      });
      var bizEvents = thisWeek.filter(function(r){
        var combo = (r[2]||'') + ' ' + (r[1]||'');
        return /업무|회사|출장|야근|미팅|회의/i.test(combo);
      });

      // 작품
      if (typeof loadWorks === 'function') loadWorks();
      var works = (typeof _works !== 'undefined' && _works) ? _works.filter(function(w){return w.status==='confirmed';}) : [];
      var deadlineSoon = works.filter(function(w){
        if (!w.publish_end) return false;
        var diff = Math.ceil((new Date(w.publish_end) - new Date(todayStr)) / 86400000);
        return diff >= 0 && diff <= 30;
      });

      // 이번 달 재정
      var income=0, expense=0;
      (p.hubRows||[]).forEach(function(r){
        var amt = parseFloat(r[3])||0;
        if (r[4] === '수입') income += amt;
        else if (r[4] === '지출') expense += amt;
      });
      var balance = income - expense;

      // Claude에 보낼 요약
      var summary = '날짜: ' + todayStr + '\n\n';
      summary += '【다음 여행】 ' + tripSummary + '\n';
      if (prebookCount) summary += '사전 예약 필요: ' + prebookCount + '건 (' + prebookList.join(', ') + ')\n';
      if (unpaidCount) summary += '결제 예정: ' + unpaidCount + '건\n';
      summary += '\n【이번 주 일정】 총 ' + thisWeek.length + '건';
      if (bizEvents.length) summary += ' (업무/야근/출장 ' + bizEvents.length + '건)';
      summary += '\n';
      if (bizEvents.length) {
        summary += bizEvents.slice(0,5).map(function(r){ return '  - ' + r[0] + ' ' + (r[1]||''); }).join('\n') + '\n';
      }
      summary += '\n【작품】 연재 중 ' + works.length + '개';
      if (deadlineSoon.length) summary += ', 30일 내 마감 ' + deadlineSoon.length + '건';
      summary += '\n';
      if (deadlineSoon.length) {
        summary += deadlineSoon.slice(0,3).map(function(w){ return '  - ' + w.title + ' (마감 ' + w.publish_end + ')'; }).join('\n') + '\n';
      }
      summary += '\n【이번 달 재정】 수입 ' + income + '만, 지출 ' + expense + '만, 잔액 ' + balance + '만\n';

      var prompt = '당신은 사용자의 개인 비서입니다. 아래 데이터를 보고 사용자가 오늘/이번 주에 가장 신경 써야 할 항목 4개를 골라 한국어 친근한 톤으로 알려주세요.\n\n' +
        '응답 형식 — 반드시 아래 JSON 배열만. 다른 텍스트(설명/머리말/```json) 절대 금지:\n' +
        '[\n' +
        '  { "icon": "⚡", "title": "내일까지 \'첫사랑 개\' 마감", "tag": "오늘 집중하세요" },\n' +
        '  { "icon": "⏰", "title": "이번 주 일정 36건", "tag": "놓친 건 없는지 확인" },\n' +
        '  { "icon": "✈️", "title": "독일 여행 사전예약 2건 안 됨", "tag": "D-133 점검 필요" },\n' +
        '  { "icon": "💰", "title": "이번 달 잔액 1.38억", "tag": "지출 흐름 점검" }\n' +
        ']\n\n' +
        '규칙:\n' +
        '- 정확히 4개 객체 (적게/많게 금지)\n' +
        '- icon: 단일 이모지 1개만 (가장 어울리는 것 — ⚡⏰💰✈️📋📅🔥💼🎯 등)\n' +
        '- title: 25자 이내, 구체적 (이름·날짜·숫자 포함)\n' +
        '- tag: 15자 이내, 행동 지향 (지시/액션)\n' +
        '- 마크다운/HTML 절대 사용 금지\n' +
        '- 우선순위 높은 것부터\n\n' +
        '데이터:\n' + summary + '\n\nJSON 배열만 응답:';

      var model = localStorage.getItem('atelier_anthropic_model') || 'claude-sonnet-4-6';
      // brief는 항상 빠른 sonnet 사용
      if (model.indexOf('opus') >= 0) model = 'claude-sonnet-4-6';

      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
          'content-type': 'application/json'
        },
        body: JSON.stringify({
          model: model,
          max_tokens: 600,
          messages: [{ role: 'user', content: prompt }]
        })
      });
      if (!res.ok) throw new Error('HTTP ' + res.status);
      var data = await res.json();
      var text = (data.content && data.content[0] && data.content[0].text || '').trim();
      // JSON 배열 파싱 (Claude가 가끔 ```json``` 래핑하니 정리)
      var items = [];
      try {
        var jsonText = text;
        var fenceMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
        if (fenceMatch) jsonText = fenceMatch[1].trim();
        // 배열만 추출
        var firstBracket = jsonText.indexOf('[');
        var lastBracket = jsonText.lastIndexOf(']');
        if (firstBracket !== -1 && lastBracket !== -1) {
          jsonText = jsonText.substring(firstBracket, lastBracket + 1);
        }
        items = JSON.parse(jsonText);
        if (!Array.isArray(items)) throw new Error('not an array');
      } catch(parseErr) {
        // Fallback: 줄 단위 텍스트로 파싱 (옛 방식)
        console.warn('[Brief] JSON parse failed, fallback to line mode:', parseErr.message);
        var lines = text.split('\n').filter(function(l){ return l.trim() && !l.trim().match(/^[\[\]\{\}`]/); });
        items = lines.slice(0, 4).map(function(l) {
          var line = l.trim().replace(/<[^>]+>/g, '').replace(/^[-•·\*]\s*/, '').trim();
          var emojiMatch = line.match(/^([\u{1F300}-\u{1F9FF}\u{2600}-\u{27BF}\u{1F600}-\u{1F64F}\u{1F680}-\u{1F6FF}]+)\s*/u);
          var emoji = emojiMatch ? emojiMatch[1] : '📌';
          var rest = emojiMatch ? line.substring(emojiMatch[0].length) : line;
          var parts = rest.split(/\s+[—–]\s+/);
          return { icon: emoji, title: (parts[0]||'').trim(), tag: (parts.slice(1).join(' — ')||'').trim() };
        });
      }
      // 4개 카드 그리드 렌더 — 각 카드 다른 파스텔 컬러 (순서별 사이클)
      var BRIEF_CARD_PALETTE = [
        { bg: 'linear-gradient(135deg,#f5f3ff 0%,#ede9fe 100%)', iconBg: '#ddd6fe', iconColor: '#7c3aed', border: '#e9d5ff', titleColor: '#3b0764', tagColor: '#6b21a8' },
        { bg: 'linear-gradient(135deg,#fff7ed 0%,#ffedd5 100%)', iconBg: '#fed7aa', iconColor: '#ea580c', border: '#fdba74', titleColor: '#7c2d12', tagColor: '#9a3412' },
        { bg: 'linear-gradient(135deg,#f0fdf4 0%,#dcfce7 100%)', iconBg: '#bbf7d0', iconColor: '#15803d', border: '#86efac', titleColor: '#14532d', tagColor: '#166534' },
        { bg: 'linear-gradient(135deg,#eff6ff 0%,#dbeafe 100%)', iconBg: '#bfdbfe', iconColor: '#2563eb', border: '#93c5fd', titleColor: '#1e3a8a', tagColor: '#1e40af' }
      ];
      var html = '<div class="grid grid-cols-1 sm:grid-cols-2 gap-3">';
      items.slice(0, 4).forEach(function(item, idx) {
        var icon = (item.icon || '📌').toString();
        var title = (item.title || '').toString();
        var tag = (item.tag || item.tagline || '').toString();
        if (!title && !tag) return;
        var p = BRIEF_CARD_PALETTE[idx % 4];
        html += '<div style="background:' + p.bg + ';border-radius:14px;padding:14px 16px;display:flex;align-items:center;gap:12px;border:1px solid ' + p.border + ';">';
        html += '<div style="flex-shrink:0;width:38px;height:38px;border-radius:10px;background:' + p.iconBg + ';display:flex;align-items:center;justify-content:center;font-size:18px;line-height:1;">' + icon + '</div>';
        html += '<div style="flex:1;min-width:0;">';
        html += '<p style="font-weight:700;color:' + p.titleColor + ';font-size:13.5px;line-height:1.35;margin:0;">' + title + '</p>';
        if (tag) html += '<p style="font-size:11.5px;color:' + p.tagColor + ';line-height:1.35;margin-top:2px;opacity:0.85;">' + tag + '</p>';
        html += '</div></div>';
      });
      html += '</div>';
      contentEl.innerHTML = html;
      var now = new Date();
      var timeStr = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
      try { localStorage.setItem(todayKey, JSON.stringify({ html: html, time: timeStr })); } catch(e){}
      if (statusEl) statusEl.textContent = timeStr + ' 생성';
    } catch(e) {
      console.error('[Daily Brief]', e);
      contentEl.innerHTML = '<div class="text-[11px] text-rose-600">⚠️ 브리프 생성 실패: ' + (e.message||'알 수 없는 오류') + '. <button onclick="generateDailyBrief(true)" class="underline font-bold ml-1">재시도</button></div>';
      if (statusEl) statusEl.textContent = '실패';
    }
  }
  window.generateDailyBrief = generateDailyBrief;

  // ═══════════════════════════════════════════════════════
  // 일정 임포트 (Outlook .ics / GTM .xlsx / .csv) — AI 자동 매핑
  // ═══════════════════════════════════════════════════════
  var _importFile = null;
  var _importParsedEvents = []; // [{date, end_date, title, category, notes}]

  window.openImportModal = function() {
    var modal = document.getElementById('import-modal');
    if (!modal) return;
    _importFile = null; _importParsedEvents = [];
    document.getElementById('import-file-name').textContent = '';
    document.getElementById('import-file-size').textContent = '';
    document.getElementById('import-drop-placeholder').classList.remove('hidden');
    document.getElementById('import-file-info').classList.add('hidden');
    document.getElementById('import-preview').classList.add('hidden');
    document.getElementById('import-status').classList.add('hidden');
    document.getElementById('import-analyze-btn').disabled = true;
    document.getElementById('import-analyze-label').textContent = '파일을 먼저 올려주세요';
    document.getElementById('import-analyze-btn').classList.remove('hidden');
    document.getElementById('import-apply-btn').classList.add('hidden');
    document.getElementById('import-file-input').value = '';
    modal.style.cssText = 'display:flex!important';
  };
  window.closeImportModal = function() {
    var modal = document.getElementById('import-modal');
    if (modal) modal.style.cssText = 'display:none!important';
  };
  window.handleImportDrop = function(event) {
    event.preventDefault();
    var dz = document.getElementById('import-drop-zone');
    if (dz) dz.classList.remove('border-sky-400','bg-sky-50');
    var file = event.dataTransfer && event.dataTransfer.files && event.dataTransfer.files[0];
    if (file) _setImportFile(file);
  };
  window.handleImportFile = function(event) {
    var file = event.target.files && event.target.files[0];
    if (file) _setImportFile(file);
  };
  function _setImportFile(file) {
    _importFile = file;
    document.getElementById('import-file-name').textContent = file.name;
    document.getElementById('import-file-size').textContent = (file.size/1024).toFixed(1) + ' KB';
    document.getElementById('import-drop-placeholder').classList.add('hidden');
    document.getElementById('import-file-info').classList.remove('hidden');
    document.getElementById('import-file-info').className = 'flex flex-col items-center gap-1';
    document.getElementById('import-analyze-btn').disabled = false;
    document.getElementById('import-analyze-label').textContent = '분석 + 매핑하기';
    document.getElementById('import-preview').classList.add('hidden');
  }

  window.analyzeImportFile = async function() {
    if (!_importFile) return;
    var btn = document.getElementById('import-analyze-btn');
    var status = document.getElementById('import-status');
    var lbl = document.getElementById('import-analyze-label');
    btn.disabled = true;
    lbl.innerHTML = '<span class="material-symbols-outlined animate-spin" style="font-size:14px">progress_activity</span> 분석 중...';
    status.className = 'px-4 py-3 rounded-xl text-xs bg-sky-50 text-sky-800';
    status.textContent = '파일 파싱 중...';

    try {
      var ext = (_importFile.name||'').toLowerCase().split('.').pop();
      var events = [];
      if (ext === 'ics') {
        events = await _parseIcs(_importFile);
        status.textContent = '✓ Outlook 표준 형식 — ' + events.length + '건 추출됨';
      } else if (ext === 'csv' || ext === 'xlsx' || ext === 'xls') {
        var rows = await _parseSheet(_importFile);
        if (!rows || !rows.length) throw new Error('엑셀에서 데이터를 찾을 수 없어요');
        status.textContent = '엑셀 ' + rows.length + '행 발견 — AI로 컬럼 매핑 중...';
        events = await _mapSheetWithAI(rows);
        status.textContent = '✓ AI 매핑 완료 — ' + events.length + '건 추출됨';
      } else {
        throw new Error('지원하지 않는 파일 형식 (.ics / .xlsx / .csv만 가능)');
      }
      if (!events.length) throw new Error('일정을 찾을 수 없어요. 파일 형식 확인 필요.');
      // 카테고리 기본값
      var defaultBiz = document.getElementById('import-default-business').checked;
      if (defaultBiz) events.forEach(function(e){ if (!e.category) e.category = '업무'; });
      _importParsedEvents = events;
      _renderImportPreview(events);
      // 버튼 전환: 분석하기 → 적용하기
      btn.classList.add('hidden');
      var applyBtn = document.getElementById('import-apply-btn');
      applyBtn.classList.remove('hidden');
      document.getElementById('import-apply-label').textContent = events.length + '건 일정 추가';
    } catch(e) {
      console.error('[import]', e);
      status.className = 'px-4 py-3 rounded-xl text-xs bg-rose-50 text-rose-700';
      status.textContent = '⚠️ ' + (e.message || '알 수 없는 오류');
      btn.disabled = false;
      lbl.textContent = '재시도';
    }
  };

  // .ics 파싱 (RFC 5545 간단 구현)
  async function _parseIcs(file) {
    var text = await file.text();
    var events = [];
    var blocks = text.split(/BEGIN:VEVENT/i).slice(1);
    blocks.forEach(function(block) {
      var endIdx = block.search(/END:VEVENT/i);
      if (endIdx < 0) return;
      var content = block.substring(0, endIdx);
      // line continuation: 다음 줄이 공백/탭으로 시작하면 합침
      content = content.replace(/\r?\n[ \t]/g, '');
      var get = function(field) {
        var re = new RegExp('^' + field + '(?:;[^:]*)?:(.+)$', 'm');
        var m = content.match(re);
        return m ? m[1].trim() : '';
      };
      var summary = get('SUMMARY');
      var dtstart = get('DTSTART');
      var dtend = get('DTEND');
      var desc = get('DESCRIPTION');
      var loc = get('LOCATION');
      var date = _icsDateToISO(dtstart);
      var endDate = _icsDateToISO(dtend);
      // 종료가 시작과 같거나 +1 day이면 종일 → 종료일 비움
      if (endDate === date) endDate = '';
      if (!date && !summary) return;
      var notes = [desc, loc ? '📍 ' + loc : ''].filter(Boolean).join(' · ');
      // 카테고리 키워드 감지
      var cat = '';
      var combo = (summary + ' ' + desc).toLowerCase();
      if (/회의|미팅|meeting/i.test(combo)) cat = '업무';
      else if (/야근/i.test(combo)) cat = '업무';
      else if (/출장|business\s*trip/i.test(combo)) cat = '업무';
      else if (/휴가|연차|vacation|leave/i.test(combo)) cat = '연차';
      events.push({ date: date, end_date: endDate, title: summary || '(제목 없음)', category: cat, notes: notes });
    });
    return events;
  }
  function _icsDateToISO(s) {
    if (!s) return '';
    // YYYYMMDD 또는 YYYYMMDDTHHMMSS
    var m = s.match(/^(\d{4})(\d{2})(\d{2})/);
    if (m) return m[1] + '-' + m[2] + '-' + m[3];
    return '';
  }

  // 엑셀/CSV 파싱 (SheetJS)
  async function _parseSheet(file) {
    if (typeof XLSX === 'undefined') throw new Error('SheetJS 라이브러리 로드 실패');
    var buf = await file.arrayBuffer();
    var wb = XLSX.read(buf, { type: 'array', cellDates: true });
    var sheet = wb.Sheets[wb.SheetNames[0]];
    return XLSX.utils.sheet_to_json(sheet, { defval: '', raw: false });
  }

  // Claude AI로 엑셀 컬럼 자동 매핑 → 일정 배열로 변환
  async function _mapSheetWithAI(rows) {
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) {
      // AI 없으면 단순 휴리스틱 매핑
      return _heuristicMapSheet(rows);
    }
    // 처음 3행 + 컬럼명만 추출해서 Claude에게 보냄
    var sample = rows.slice(0, 5);
    var columns = Object.keys(rows[0]||{});
    var prompt = '아래는 회사 GTM(Go-To-Market) 엑셀에서 추출한 데이터입니다. 각 행을 캘린더 일정으로 변환할 수 있게 컬럼 의미를 파악하고, 다음 JSON 배열로만 응답하세요 (다른 설명 X):\n\n' +
      '[\n' +
      '  {"date": "YYYY-MM-DD", "end_date": "YYYY-MM-DD or empty", "title": "일정 제목", "category": "업무/미팅/마일스톤/출장 중 하나", "notes": "추가 정보"},\n' +
      '  ...\n' +
      ']\n\n' +
      '규칙:\n' +
      '- date: 시작일 (필수). 컬럼명 \'시작일/Start/날짜/Date/일자\' 등에서 파악\n' +
      '- end_date: 종료일 (있으면). 시작과 같으면 빈 문자열\n' +
      '- title: 일정 제목 (필수). \'제목/이벤트/Activity/Task\' 등\n' +
      '- category: 키워드로 \'업무/미팅/마일스톤/출장\' 자동 분류\n' +
      '- notes: 담당자/부서/메모 같은 추가 정보 한 줄로\n' +
      '- 날짜 없는 행은 제외\n\n' +
      '컬럼: ' + columns.join(' | ') + '\n\n' +
      '데이터 (처음 5행):\n' + JSON.stringify(sample, null, 2) + '\n\n' +
      '전체 ' + rows.length + '행 변환:\n' + JSON.stringify(rows, null, 2);

    var model = localStorage.getItem('atelier_anthropic_model') || 'claude-sonnet-4-6';
    if (model.indexOf('opus') >= 0) model = 'claude-sonnet-4-6'; // sonnet으로 강제 (저렴)
    var res = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'x-api-key': apiKey,
        'anthropic-version': '2023-06-01',
        'anthropic-dangerous-direct-browser-access': 'true',
        'content-type': 'application/json'
      },
      body: JSON.stringify({
        model: model,
        max_tokens: 4000,
        messages: [{ role: 'user', content: prompt }]
      })
    });
    if (!res.ok) throw new Error('AI 매핑 실패 (HTTP ' + res.status + ')');
    var data = await res.json();
    var text = (data.content && data.content[0] && data.content[0].text || '').trim();
    var jm = text.match(/\[[\s\S]*\]/);
    if (!jm) throw new Error('AI 응답 파싱 실패');
    var events = JSON.parse(jm[0]);
    return events.filter(function(e){ return e.date && e.title; });
  }

  // 휴리스틱 매핑 (API 키 없을 때 fallback)
  function _heuristicMapSheet(rows) {
    if (!rows.length) return [];
    var keys = Object.keys(rows[0]);
    var dateKey = keys.find(function(k){ return /시작|날짜|date|일자/i.test(k); }) || keys[0];
    var endKey = keys.find(function(k){ return /종료|end/i.test(k); });
    var titleKey = keys.find(function(k){ return /제목|이벤트|activity|task|title|일정/i.test(k); }) || keys[1];
    var noteKey = keys.find(function(k){ return /메모|note|비고|설명/i.test(k); });
    return rows.map(function(r){
      var d = r[dateKey];
      // 날짜 변환 시도
      var isoDate = '';
      if (d instanceof Date) isoDate = d.toISOString().split('T')[0];
      else if (typeof d === 'string') {
        var m = d.match(/(\d{4})[-./](\d{1,2})[-./](\d{1,2})/);
        if (m) isoDate = m[1] + '-' + String(m[2]).padStart(2,'0') + '-' + String(m[3]).padStart(2,'0');
      }
      return {
        date: isoDate,
        end_date: '',
        title: String(r[titleKey]||'(제목 없음)'),
        category: '',
        notes: noteKey ? String(r[noteKey]||'') : ''
      };
    }).filter(function(e){ return e.date && e.title; });
  }

  function _renderImportPreview(events) {
    var listEl = document.getElementById('import-preview-list');
    var cntEl = document.getElementById('import-preview-count');
    var prevEl = document.getElementById('import-preview');
    if (cntEl) cntEl.textContent = events.length;
    if (listEl) {
      listEl.innerHTML = events.slice(0, 100).map(function(e, i){
        var catColor = e.category === '업무' ? 'bg-sky-100 text-sky-700' :
                       e.category === '미팅' ? 'bg-indigo-100 text-indigo-700' :
                       e.category === '출장' ? 'bg-amber-100 text-amber-700' :
                       e.category === '마일스톤' ? 'bg-emerald-100 text-emerald-700' :
                       'bg-slate-100 text-slate-600';
        var dateRange = e.date + (e.end_date && e.end_date !== e.date ? '~' + e.end_date : '');
        return '<div class="flex items-center gap-2 px-3 py-2 border-b border-slate-100 last:border-b-0 text-[11px]">' +
          '<span class="text-[10px] font-bold text-slate-400 w-24 shrink-0">' + dateRange + '</span>' +
          (e.category ? '<span class="text-[9px] font-bold px-1.5 py-0.5 rounded ' + catColor + ' shrink-0">' + e.category + '</span>' : '') +
          '<span class="flex-1 truncate text-slate-700 font-medium">' + String(e.title).replace(/</g,'&lt;') + '</span>' +
          (e.notes ? '<span class="text-[9px] text-slate-400 truncate max-w-[120px]">' + String(e.notes).replace(/</g,'&lt;') + '</span>' : '') +
        '</div>';
      }).join('') + (events.length > 100 ? '<div class="px-3 py-2 text-[10px] text-slate-400 italic text-center">+ ' + (events.length-100) + '건 더</div>' : '');
    }
    if (prevEl) prevEl.classList.remove('hidden');
  }

  window.applyImport = async function() {
    if (!_importParsedEvents.length) return;
    var btn = document.getElementById('import-apply-btn');
    var status = document.getElementById('import-status');
    btn.disabled = true;
    document.getElementById('import-apply-label').innerHTML = '<span class="material-symbols-outlined animate-spin" style="font-size:14px">progress_activity</span> 저장 중...';
    status.className = 'px-4 py-3 rounded-xl text-xs bg-sky-50 text-sky-800';
    status.textContent = '0/' + _importParsedEvents.length + ' 저장 중...';
    var ok = 0, skip = 0, fail = 0;
    // 기존 planner에서 같은 (date, title) 조합 추출 (중복 방지)
    var existingKeys = {};
    (plannerData||[]).forEach(function(r){
      if (r[0] && r[1]) existingKeys[r[0] + '|' + r[1]] = true;
    });
    for (var i = 0; i < _importParsedEvents.length; i++) {
      var e = _importParsedEvents[i];
      var key = e.date + '|' + e.title;
      if (existingKeys[key]) { skip++; continue; }
      var row = [
        e.date,           // 0: 시작일
        e.title,          // 1: 제목
        e.category || '', // 2: 카테고리
        '',               // 3:
        e.notes || '',    // 4: 메모
        e.end_date || '', // 5: 종료일
        '',               // 6:
      ];
      try {
        var obj = rowToObj('planner', row);
        var saved = await fbAdd('planner', obj);
        plannerData.push(row.concat([saved._id]));
        ok++;
        if (i % 5 === 0) status.textContent = (i+1) + '/' + _importParsedEvents.length + ' 저장 중...';
      } catch(err) { console.error('[import save]', err); fail++; }
    }
    status.className = 'px-4 py-3 rounded-xl text-xs bg-emerald-50 text-emerald-800';
    status.textContent = '✅ 추가 ' + ok + '건' + (skip ? ', 중복 스킵 ' + skip + '건' : '') + (fail ? ', 실패 ' + fail + '건' : '');
    // 캘린더 갱신
    if (typeof renderCalendar === 'function') renderCalendar();
    if (typeof loadDashboard === 'function') loadDashboard();
    setTimeout(function(){
      closeImportModal();
      if (typeof showSyncToast === 'function') showSyncToast('📥 ' + ok + '건 일정 임포트 완료');
    }, 1500);
  };

  // ═══════════════════════════════════════════════════════
  // AI 여행 추천 — 과거 여행 데이터 분석
  // ═══════════════════════════════════════════════════════
  window.openTravelRecommendModal = function() {
    var modal = document.getElementById('travel-recommend-modal');
    if (!modal) return;
    modal.style.cssText = 'display:flex!important';
    generateTravelRecommend(false);
  };
  window.closeTravelRecommendModal = function() {
    var modal = document.getElementById('travel-recommend-modal');
    if (modal) modal.style.cssText = 'display:none!important';
  };

  // ═══════════════════════════════════════════════════════
  // AI 자연어 검색 (Cmd+K)
  // ═══════════════════════════════════════════════════════
  window.openAiSearchModal = function() {
    var modal = document.getElementById('ai-search-modal');
    if (!modal) return;
    modal.style.cssText = 'display:flex!important';
    setTimeout(function(){ var inp = document.getElementById('ai-search-input'); if (inp) inp.focus(); }, 50);
  };
  window.closeAiSearchModal = function() {
    var modal = document.getElementById('ai-search-modal');
    if (modal) modal.style.cssText = 'display:none!important';
  };
  window._aiSearchExample = function(q) {
    var inp = document.getElementById('ai-search-input');
    if (inp) { inp.value = q; inp.focus(); _runAiSearch(q); }
  };

  async function _runAiSearch(query) {
    var resultsEl = document.getElementById('ai-search-results');
    if (!resultsEl) return;
    if (!query || query.length < 2) return;
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) {
      resultsEl.innerHTML = '<div class="p-6 text-sm text-amber-700 bg-amber-50">⚙️ AI 검색은 <button onclick="openApiSettingsModal()" class="underline font-bold">API 키 설정</button>이 필요해요.</div>';
      return;
    }
    resultsEl.innerHTML = '<div class="p-6 flex items-center gap-2 text-slate-500"><span class="material-symbols-outlined animate-spin" style="font-size:16px">progress_activity</span>검색 중...</div>';
    try {
      // 모든 데이터 컬렉션을 컴팩트하게 요약
      var [planner, journey, trips, hub, refs, sessions] = await Promise.all([
        fbRead('planner'), fbRead('journey'), fbRead('trips'),
        fbRead('finance_hub'), fbRead('refCards'), fbRead('englishSessions')
      ]);
      // 데이터 인덱스 (최근 1년치)
      var oneYrAgo = new Date(); oneYrAgo.setFullYear(oneYrAgo.getFullYear() - 1);
      var oneYrStr = oneYrAgo.toISOString().split('T')[0];
      var ctx = {
        planner: (planner||[]).filter(function(p){ return (p.date||p.start_date||'') >= oneYrStr; }).slice(0,200).map(function(p){
          return { date: p.date||p.start_date, end: p.end_date, title: p.title||'', cat: p.category||'', notes: (p.notes||'').slice(0,40) };
        }),
        journey: (journey||[]).slice(0,150).map(function(j){
          return { trip_id: j.trip_id, type: j.type, date: j.date, title: j.title||'', city: j.city||'', desc: (j.description||'').slice(0,40), amount: j.amount||'', payment_status: j.payment_status||'' };
        }),
        trips: (trips||[]).map(function(t){ return { id:t._id, name:t.name, start:t.start_date, end:t.end_date }; }),
        hub: (hub||[]).slice(0,100).map(function(h){ return { date: h.date, desc: (h.description||'').slice(0,30), trip: h.trip||'', cat: h.category||'', amt: h.amount, type: h.type }; }),
        memos: (refs||[]).slice(0,30).map(function(r){ return { title: r.title||'', body: (r.body||'').slice(0,80) }; }),
        works: (typeof _works !== 'undefined' && _works) ? _works.map(function(w){ return { title:w.title, series:w.series_name, start:w.publish_start, end:w.publish_end, status:w.status }; }) : []
      };
      var todayStr = new Date().toISOString().split('T')[0];
      var prompt = '당신은 사용자의 The Atelier 데이터를 검색하는 비서입니다. 사용자 질문에 답해주세요.\n\n' +
        '오늘: ' + todayStr + '\n\n' +
        '【데이터】\n' + JSON.stringify(ctx) + '\n\n' +
        '【사용자 질문】\n' + query + '\n\n' +
        '응답 형식:\n' +
        '- 데이터를 기반으로 정확히 답함. 데이터에 없으면 "정보 없음"이라 함.\n' +
        '- HTML 사용 가능: <strong> <ul><li> <a href="javascript:navigate(\'planner\')">텍스트</a>\n' +
        '- 짧고 구체적 (3-5줄)\n' +
        '- 관련 일정/항목 발견 시 날짜·제목 같이\n' +
        '- 마크다운 X, 일반 텍스트로\n\n응답:';
      var model = localStorage.getItem('atelier_anthropic_model') || 'claude-sonnet-4-6';
      if (model.indexOf('opus') >= 0) model = 'claude-sonnet-4-6';
      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true', 'content-type': 'application/json' },
        body: JSON.stringify({ model: model, max_tokens: 800, messages: [{ role: 'user', content: prompt }] })
      });
      if (!res.ok) throw new Error('AI 호출 실패 (' + res.status + ')');
      var data = await res.json();
      var text = (data.content && data.content[0] && data.content[0].text || '').trim();
      resultsEl.innerHTML = '<div class="p-5 text-[13px] text-slate-800 leading-relaxed" style="font-family:\'Pretendard\',sans-serif">' + text + '</div>';
    } catch(e) {
      console.error('[ai search]', e);
      resultsEl.innerHTML = '<div class="p-5 text-sm text-rose-700">⚠️ ' + (e.message||'검색 실패') + '</div>';
    }
  }

  // ═══════════════════════════════════════════════════════
  // 웹소설 시장 조사 / 트렌드 분석
  // ═══════════════════════════════════════════════════════
  var _trendPlatform = '포스타입';
  var _trendMode = 'auto';
  var _trendImageBase64 = null;
  var _trendImageType = 'image/jpeg';
  var _trendLastResult = '';

  window.openTrendResearchModal = function() {
    var modal = document.getElementById('trend-research-modal');
    if (!modal) return;
    modal.style.cssText = 'display:flex!important';
    _setTrendPlatform('포스타입');
    _setTrendMode('auto');
    // Ctrl+V로 이미지 붙여넣기
    document.addEventListener('paste', _trendPasteHandler);
  };
  window.closeTrendResearchModal = function() {
    var modal = document.getElementById('trend-research-modal');
    if (modal) modal.style.cssText = 'display:none!important';
    document.removeEventListener('paste', _trendPasteHandler);
  };

  function _trendPasteHandler(e) {
    if (_trendMode !== 'analyze-text') return;  // 통합된 모드에서만 이미지 paste 처리
    var items = e.clipboardData && e.clipboardData.items;
    if (!items) return;
    for (var i = 0; i < items.length; i++) {
      if (items[i].type.startsWith('image/')) {
        e.preventDefault();
        var file = items[i].getAsFile();
        if (file) _trendLoadImage(file);
        return;
      }
    }
  }

  window._setTrendPlatform = function(p) {
    _trendPlatform = p;
    document.querySelectorAll('.trend-platform-tab').forEach(function(btn){
      var active = btn.getAttribute('data-trend-platform') === p;
      if (active) {
        btn.className = 'trend-platform-tab px-3 py-2 rounded-t-lg text-xs font-bold text-orange-700 bg-orange-50 border-b-2 border-orange-500 transition-colors whitespace-nowrap';
      } else {
        btn.className = 'trend-platform-tab px-3 py-2 rounded-t-lg text-xs font-bold text-slate-500 hover:text-orange-700 hover:bg-orange-50 transition-colors whitespace-nowrap';
      }
    });
    _updateTrendUI();
  };

  window._setTrendMode = function(m) {
    _trendMode = m;
    document.querySelectorAll('.trend-mode-tab').forEach(function(btn){
      var active = btn.getAttribute('data-trend-mode') === m;
      if (active) {
        btn.className = 'trend-mode-tab px-3 py-1.5 rounded-lg text-[11px] font-bold bg-orange-100 text-orange-700 ring-1 ring-orange-300 transition-all';
      } else {
        btn.className = 'trend-mode-tab px-3 py-1.5 rounded-lg text-[11px] font-bold text-slate-500 hover:bg-orange-50 hover:text-orange-600 transition-all';
      }
    });
    _updateTrendUI();
  };

  function _updateTrendUI() {
    var inp = document.getElementById('trend-input');
    var lbl = document.getElementById('trend-input-label');
    var imgZone = document.getElementById('trend-image-zone');
    var runLbl = document.getElementById('trend-run-label');
    var runBtn = document.getElementById('trend-run-btn');
    var counter = document.getElementById('trend-input-counter');
    if (!inp) return;
    var placeholders = {
      auto: '자동으로 수집된 데이터를 사용합니다. 입력 불필요.',
      'analyze-text': '인기작 정보를 텍스트로 붙여넣거나 아래 영역에 스크린샷 업로드. 둘 다 가능.\n\n텍스트 예:\n=== 작품 1 ===\n제목: 그놈의 첫사랑\n별점: 9.7 · 조회 1.2M\n소개: ...\n태그: 까칠남주, 츤데레\n\n=== 작품 2 ===\n...',
      character: _trendPlatform === '포스타입' ? '2차창작 캐릭터/페어를 적어주세요.\n예: "트와이스 미사나", "BTS 정뷔", "원피스 ZoSan"' : '주인공 캐릭터 설정/장르를 적어주세요.\n예: "재벌가 까칠한 후계자 남주 + 평범한 여주, 사내 비밀 연애"'
    };
    var labels = {
      auto: '자동 수집 데이터 (주 1회 GitHub Actions)',
      'analyze-text': '인기작 데이터 (텍스트 + 스크린샷 가능)',
      character: '캐릭터·페어·장르'
    };
    var runLabels = {
      auto: '다시 불러오기',
      'analyze-text': '인기작 패턴 분석',
      character: '캐릭터 트렌드 분석'
    };
    inp.placeholder = placeholders[_trendMode] || '입력...';
    if (lbl) lbl.textContent = labels[_trendMode] || '입력';
    if (runLbl) runLbl.textContent = runLabels[_trendMode] || 'AI 분석';
    // 이미지 업로드 영역: analyze-text 모드에서도 표시 (옵션)
    if (imgZone) imgZone.className = _trendMode === 'analyze-text' ? 'mt-3 shrink-0' : 'hidden mt-3 shrink-0';
    // 카운터
    inp.oninput = function(){
      var cnt = document.getElementById('trend-input-counter');
      if (cnt) cnt.textContent = (inp.value||'').length + '자';
    };

    // 자동 모드: 입력 컬럼 전체 숨기고 결과 영역을 풀와이드로
    var grid = document.getElementById('trend-grid');
    var inputCol = document.getElementById('trend-input-col');
    var out = document.getElementById('trend-output');
    var copyBtn = document.getElementById('trend-copy-btn');
    if (_trendMode === 'auto') {
      if (inputCol) inputCol.style.display = 'none';
      if (grid) grid.style.gridTemplateColumns = '1fr';
      _loadAutoTrend();
    } else {
      if (inputCol) inputCol.style.display = '';
      if (grid) grid.style.gridTemplateColumns = '';
      // 다른 탭으로 전환 시 출력 클리어 (자동 트렌드 결과가 보이지 않게)
      if (out) out.innerHTML = '<div class="text-slate-400 italic">왼쪽에 입력하고 \'AI 분석\'을 눌러주세요</div>';
      if (copyBtn) copyBtn.classList.add('hidden');
      _trendLastResult = '';
    }
  }

  // 자동 트렌드 JSON 로드 + 렌더링 (특정 날짜 지정 가능)
  var _autoTrendDates = [];
  var _autoTrendSelectedDate = null;

  window._loadAutoTrend = async function(targetDate) {
    var out = document.getElementById('trend-output');
    if (!out) return;
    out.innerHTML = '<div class="text-slate-400 italic">자동 수집 데이터 불러오는 중…</div>';

    // 1. 히스토리 인덱스 로드 (실패해도 무시 — latest는 fallback으로 시도)
    if (_autoTrendDates.length === 0) {
      try {
        var idxResp = await fetch('data/trends/postype/index.json?_=' + Date.now());
        if (idxResp.ok) {
          var idx = await idxResp.json();
          _autoTrendDates = idx.dates || [];
        }
      } catch (e) { console.warn('index.json fetch failed', e); }
    }

    // 2. 선택된 날짜 결정 (인자 > 마지막 선택 > 최신)
    var date = targetDate || _autoTrendSelectedDate || (_autoTrendDates[0] || null);
    _autoTrendSelectedDate = date;

    // 3. 해당 JSON 로드 (date 있으면 그 날짜, 없으면 latest)
    var url = date ? ('data/trends/postype/' + date + '.json') : 'data/trends/postype/latest.json';
    try {
      var resp = await fetch(url + '?_=' + Date.now());
      if (!resp.ok) {
        if (resp.status === 404) {
          out.innerHTML = '<div class="p-4 bg-amber-50 border border-amber-200 rounded-xl text-[13px] text-slate-700">' +
            '<p class="font-bold mb-2">📭 아직 수집된 데이터가 없어요</p>' +
            '<p class="mb-2">GitHub Actions가 매주 일요일 09:00 KST에 자동 실행됩니다.</p>' +
            '<p class="text-[12px] text-slate-500">즉시 실행하려면 GitHub repo → Actions → "postype 트렌드 자동 분석" → Run workflow</p>' +
            '</div>';
          return;
        }
        throw new Error('HTTP ' + resp.status);
      }
      var data = await resp.json();
      _renderAutoTrend(data);
    } catch (e) {
      console.error('[auto-trend] load failed', e);
      out.innerHTML = '<div class="p-4 bg-rose-50 border border-rose-200 rounded-xl text-[13px] text-rose-700">로드 실패: ' + (e.message || e) + '</div>';
    }
  };

  window._selectAutoTrendDate = function(d) {
    _autoTrendSelectedDate = d;
    _loadAutoTrend(d);
  };

  function _renderAutoTrend(data) {
    var out = document.getElementById('trend-output');
    if (!out) return;
    var a = data.analysis || {};
    if (a.error) {
      out.innerHTML = '<div class="p-4 bg-rose-50 border border-rose-200 rounded-xl text-[13px] text-rose-700">AI 분석 실패: ' + a.error + '</div>';
      return;
    }

    // 인사이트 텍스트를 main + body로 분리 + 예시 highlight (' '로 감싼 부분)
    function formatInsight(text) {
      if (!text) return '';
      var dashIdx = text.indexOf('—');
      var main = dashIdx > 0 ? text.substring(0, dashIdx).trim() : text;
      var body = dashIdx > 0 ? text.substring(dashIdx + 1).trim() : '';
      // 단일 따옴표로 감싼 예시들을 하이라이트
      var bodyHl = body.replace(/'([^']{1,80})'/g, '<span class="inline-block px-1.5 py-0.5 mx-0.5 my-0.5 rounded-md bg-emerald-50 border border-emerald-100 text-emerald-800 font-medium text-[12.5px]">"$1"</span>');
      var html = '<div class="font-bold text-[14px] text-slate-900 leading-snug mb-1.5">' + main + '</div>';
      if (body) html += '<div class="text-[13px] text-slate-600 leading-relaxed">' + bodyHl + '</div>';
      return html;
    }

    function sectionCard(opts) {
      // opts: { icon, title, count, gradientFrom, gradientTo, borderColor, body }
      return '<div class="rounded-2xl bg-white border border-slate-200 overflow-hidden shadow-[0_1px_3px_rgba(0,0,0,0.03)]">' +
        '<div class="px-5 py-3 border-b" style="background:linear-gradient(90deg,' + opts.gradientFrom + ',' + opts.gradientTo + ');border-color:' + opts.borderColor + ';">' +
          '<h3 class="text-[14px] font-black flex items-center gap-2" style="color:' + opts.titleColor + ';">' +
            '<span style="font-size:16px">' + opts.icon + '</span>' + opts.title +
            (opts.count !== undefined ? '<span class="text-[11px] font-bold px-2 py-0.5 rounded-full" style="background:rgba(255,255,255,0.6);color:' + opts.titleColor + ';">' + opts.count + '</span>' : '') +
          '</h3>' +
        '</div>' +
        '<div class="p-5">' + opts.body + '</div>' +
      '</div>';
    }

    var html = '<div class="space-y-4 pb-4">';

    // 히스토리 셀렉터 (날짜가 2개 이상이면 표시)
    if (_autoTrendDates && _autoTrendDates.length > 1) {
      html += '<div class="flex items-center gap-2 flex-wrap p-3 rounded-xl bg-slate-50 border border-slate-200">';
      html += '<span class="text-[11px] font-bold uppercase tracking-wider" style="color:#64748b;">📅 주간 히스토리</span>';
      _autoTrendDates.slice(0, 12).forEach(function(d) {
        var active = (d === data.date);
        html += '<button onclick="_selectAutoTrendDate(\'' + d + '\')" class="px-2.5 py-1 rounded-lg text-[11px] font-bold transition-all" style="' +
          (active ? 'background:#ea580c;color:white;' : 'background:white;color:#475569;border:1px solid #e2e8f0;') +
          '">' + d.substring(5) + '</button>';
      });
      if (_autoTrendDates.length > 12) {
        html += '<span class="text-[10px] text-slate-400">+' + (_autoTrendDates.length - 12) + ' more</span>';
      }
      html += '</div>';
    }

    // 헤더 카드
    html += '<div class="rounded-2xl p-5" style="background:linear-gradient(135deg,#fff7ed 0%,#fce7f3 100%);border:1px solid #fed7aa;">';
    html += '<div class="flex items-start gap-3 mb-2.5">';
    html += '<div style="font-size:24px;line-height:1">📅</div>';
    html += '<div class="flex-1 min-w-0">';
    html += '<div class="text-[11px] font-black uppercase tracking-wider" style="color:#c2410c;">' + (data.date || 'N/A') + ' · "' + (data.query || 'N/A') + '"</div>';
    html += '<div class="text-[10.5px] mt-0.5" style="color:#94a3b8;">' + (data.stats ? data.stats.successful + '/' + data.stats.totalScraped + ' 작품 분석 · ' + (data.stats.paidCount || 0) + ' 유료 · ' + (data.stats.adultCount || 0) + ' 19+' : '') + '</div>';
    html += '</div></div>';
    if (a.summary) html += '<p class="text-[14px] leading-relaxed font-medium" style="color:#1e293b;">' + a.summary + '</p>';
    html += '</div>';

    // 1️⃣ 실행 가능한 인사이트 (가장 큰 카드)
    if (a.actionableInsights && a.actionableInsights.length) {
      var insightsBody = '<ol class="space-y-4">';
      a.actionableInsights.forEach(function(s, i) {
        insightsBody += '<li class="flex gap-3 pb-4' + (i < a.actionableInsights.length - 1 ? ' border-b border-slate-100' : '') + '">' +
          '<div class="flex items-center justify-center rounded-full text-white font-black text-[13px] shrink-0" style="width:28px;height:28px;background:linear-gradient(135deg,#10b981,#059669);">' + (i + 1) + '</div>' +
          '<div class="flex-1 min-w-0">' + formatInsight(s) + '</div>' +
        '</li>';
      });
      insightsBody += '</ol>';
      html += sectionCard({
        icon: '💡', title: '실행 가능한 인사이트', count: a.actionableInsights.length,
        gradientFrom: '#ecfdf5', gradientTo: '#d1fae5',
        borderColor: '#a7f3d0', titleColor: '#065f46',
        body: insightsBody
      });
    }

    // 📝 제목 패턴
    if (a.titlePatterns && a.titlePatterns.length) {
      var tp = '<div class="space-y-3">';
      a.titlePatterns.forEach(function(p) {
        tp += '<div class="rounded-xl p-3.5 border" style="background:#faf5ff;border-color:#e9d5ff;">';
        tp += '<div class="flex items-baseline justify-between gap-2 mb-2">';
        tp += '<span class="font-bold text-[13.5px]" style="color:#581c87;">' + (p.pattern || '') + '</span>';
        if (p.count) tp += '<span class="text-[10px] font-bold px-2 py-0.5 rounded-full" style="background:#e9d5ff;color:#6b21a8;">' + p.count + '개</span>';
        tp += '</div>';
        if (p.examples && p.examples.length) {
          tp += '<div class="space-y-1">';
          p.examples.slice(0, 4).forEach(function(e) {
            tp += '<div class="text-[12.5px] pl-3 border-l-2" style="color:#475569;border-color:#c4b5fd;">"' + e + '"</div>';
          });
          tp += '</div>';
        }
        tp += '</div>';
      });
      tp += '</div>';
      html += sectionCard({
        icon: '📝', title: '잘 되는 제목 패턴',
        gradientFrom: '#faf5ff', gradientTo: '#f3e8ff',
        borderColor: '#e9d5ff', titleColor: '#581c87',
        body: tp
      });
    }

    // 🎣 시놉시스 훅
    if (a.synopsisHooks && a.synopsisHooks.length) {
      var sh = '<div class="space-y-2.5">';
      a.synopsisHooks.forEach(function(h) {
        sh += '<div class="flex items-start gap-3 p-2.5 rounded-lg" style="background:#fff7ed;">';
        sh += '<div class="flex-1 min-w-0">';
        sh += '<div class="font-bold text-[13.5px]" style="color:#9a3412;">' + (h.hook || '') + '</div>';
        if (h.note) sh += '<div class="text-[12px] mt-0.5" style="color:#64748b;">' + h.note + '</div>';
        sh += '</div>';
        if (h.frequency) sh += '<span class="text-[10.5px] font-bold px-2 py-0.5 rounded-full whitespace-nowrap" style="background:#fed7aa;color:#9a3412;">' + h.frequency + '</span>';
        sh += '</div>';
      });
      sh += '</div>';
      html += sectionCard({
        icon: '🎣', title: '인기 시놉시스 훅',
        gradientFrom: '#fff7ed', gradientTo: '#ffedd5',
        borderColor: '#fed7aa', titleColor: '#9a3412',
        body: sh
      });
    }

    // 👥 인기 페어/그룹
    if (a.popularPairings && a.popularPairings.length) {
      var pp = '<div class="space-y-2">';
      a.popularPairings.forEach(function(p) {
        pp += '<div class="p-2.5 rounded-lg" style="background:#eff6ff;">';
        pp += '<div class="font-bold text-[13.5px]" style="color:#1e40af;">' + (p.pairing || '') + '</div>';
        if (p.evidence) pp += '<div class="text-[12px] mt-0.5" style="color:#475569;">' + p.evidence + '</div>';
        pp += '</div>';
      });
      pp += '</div>';
      html += sectionCard({
        icon: '👥', title: '인기 페어/그룹',
        gradientFrom: '#eff6ff', gradientTo: '#dbeafe',
        borderColor: '#bfdbfe', titleColor: '#1e40af',
        body: pp
      });
    }

    // 🎭 캐릭터 유형
    if (a.characterArchetypes && a.characterArchetypes.length) {
      var ca = '<div class="space-y-2">';
      a.characterArchetypes.forEach(function(c) {
        ca += '<div class="p-2.5 rounded-lg" style="background:#fdf4ff;">';
        ca += '<div class="font-bold text-[13.5px]" style="color:#86198f;">' + (c.archetype || '') + '</div>';
        if (c.examples) ca += '<div class="text-[12px] mt-0.5" style="color:#64748b;">' + c.examples + '</div>';
        ca += '</div>';
      });
      ca += '</div>';
      html += sectionCard({
        icon: '🎭', title: '캐릭터 유형 패턴',
        gradientFrom: '#fdf4ff', gradientTo: '#fae8ff',
        borderColor: '#f5d0fe', titleColor: '#86198f',
        body: ca
      });
    }

    // 💰 수익화 + 🏷️ 태그 분포 (2단 그리드)
    var sideBySide = '';
    if (a.monetization) {
      var m = a.monetization;
      var moneyBody = '<div class="flex gap-3 mb-2">';
      moneyBody += '<div class="flex-1 p-3 rounded-lg text-center" style="background:#fefce8;"><div class="text-[10px] font-bold uppercase" style="color:#854d0e;">유료</div><div class="text-[20px] font-black mt-1" style="color:#713f12;">' + (m.paidRatio || '?') + '</div></div>';
      moneyBody += '<div class="flex-1 p-3 rounded-lg text-center" style="background:#f0fdf4;"><div class="text-[10px] font-bold uppercase" style="color:#166534;">무료</div><div class="text-[20px] font-black mt-1" style="color:#14532d;">' + (m.freeRatio || '?') + '</div></div>';
      moneyBody += '</div>';
      if (m.note) moneyBody += '<div class="text-[12px] mt-2" style="color:#64748b;">' + m.note + '</div>';
      sideBySide += sectionCard({
        icon: '💰', title: '유료/무료 분포',
        gradientFrom: '#fefce8', gradientTo: '#fef9c3',
        borderColor: '#fde68a', titleColor: '#854d0e',
        body: moneyBody
      });
    }
    if (a.tagDistribution && a.tagDistribution.length) {
      var td = '<div class="flex flex-wrap gap-1.5">';
      a.tagDistribution.slice(0, 18).forEach(function(t) {
        td += '<span class="inline-flex items-center gap-1 px-2.5 py-1 rounded-full text-[11.5px] font-semibold" style="background:#fef3c7;color:#854d0e;">' + (t.tag || '') + (t.count ? '<span style="color:#a16207;font-weight:400;">·' + t.count + '</span>' : '') + '</span>';
      });
      td += '</div>';
      sideBySide += sectionCard({
        icon: '🏷️', title: '태그 분포',
        gradientFrom: '#fffbeb', gradientTo: '#fef3c7',
        borderColor: '#fde68a', titleColor: '#92400e',
        body: td
      });
    }
    if (sideBySide) html += '<div class="grid grid-cols-1 md:grid-cols-2 gap-4">' + sideBySide + '</div>';

    // ⭐ 인기 작가
    if (a.topAuthors && a.topAuthors.length) {
      var ta = '<div class="space-y-2">';
      a.topAuthors.forEach(function(au) {
        ta += '<div class="flex items-baseline justify-between gap-2 p-2 rounded-lg" style="background:#f8fafc;">';
        ta += '<span class="font-bold text-[13px]" style="color:#1e293b;">' + (au.author || '') + '</span>';
        var meta = [];
        if (au.works) meta.push(au.works + '작');
        if (au.totalViews) meta.push('조회 ' + au.totalViews.toLocaleString('ko-KR'));
        if (au.note) meta.push(au.note);
        if (meta.length) ta += '<span class="text-[11px]" style="color:#64748b;">' + meta.join(' · ') + '</span>';
        ta += '</div>';
      });
      ta += '</div>';
      html += sectionCard({
        icon: '⭐', title: '인기 작가',
        gradientFrom: '#f8fafc', gradientTo: '#f1f5f9',
        borderColor: '#e2e8f0', titleColor: '#334155',
        body: ta
      });
    }

    // ⚠️ 주의사항
    if (a.warnings && a.warnings.length) {
      var w = '<ul class="text-[12px] space-y-1 pl-4 list-disc" style="color:#64748b;">';
      a.warnings.forEach(function(s) { w += '<li>' + s + '</li>'; });
      w += '</ul>';
      html += '<div class="rounded-xl p-3.5 border" style="background:#fef2f2;border-color:#fecaca;">' +
        '<div class="text-[12px] font-black uppercase tracking-wider mb-1.5" style="color:#991b1b;">⚠️ 주의사항</div>' + w + '</div>';
    }

    // 메타정보
    var metaInfo = data.analysisMeta || {};
    html += '<div class="pt-2 text-[10.5px] text-center" style="color:#94a3b8;">';
    html += '생성: ' + (metaInfo.generatedAt || '?').substring(0, 16).replace('T', ' ') + ' · 모델: ' + (metaInfo.model || '?');
    html += ' · <a href="' + (data.searchUrl || '#') + '" target="_blank" style="color:#ea580c;text-decoration:underline;">원본 검색 페이지 ↗</a>';
    html += '</div>';

    html += '</div>'; // .space-y-4

    out.innerHTML = html;
  }

  // run 버튼이 auto 모드일 땐 reload로 동작
  var __origRunTrend = null;

  window._trendOnImageSelect = function(event) {
    var file = event.target.files && event.target.files[0];
    if (file) _trendLoadImage(file);
  };

  function _trendLoadImage(file) {
    _trendImageType = file.type || 'image/jpeg';
    var reader = new FileReader();
    reader.onload = function(e) {
      _trendImageBase64 = (e.target.result || '').split(',')[1];
      var nameEl = document.getElementById('trend-image-name');
      if (nameEl) nameEl.textContent = '✓ ' + file.name + ' (' + (file.size/1024).toFixed(0) + 'KB)';
    };
    reader.readAsDataURL(file);
  }

  window._runTrendResearch = async function() {
    var inp = document.getElementById('trend-input');
    var out = document.getElementById('trend-output');
    var btn = document.getElementById('trend-run-btn');
    if (!out) return;
    // 자동 모드: AI 분석 안 부르고 JSON 다시 로드만
    if (_trendMode === 'auto') {
      _loadAutoTrend();
      return;
    }
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) {
      out.innerHTML = '<div class="text-amber-700 p-3 bg-amber-50 rounded-lg">⚙️ <button onclick="openApiSettingsModal()" class="underline font-bold">API 키 설정</button>이 필요해요.</div>';
      return;
    }
    var userText = (inp.value||'').trim();
    // 통합된 직접 분석 모드: 텍스트 OR 이미지 OR 둘 다
    if (_trendMode === 'analyze-text' && userText.length < 30 && !_trendImageBase64) {
      out.innerHTML = '<div class="text-amber-700 p-3 bg-amber-50 rounded-lg">📝 텍스트(30자 이상) 또는 스크린샷을 입력해주세요.</div>';
      return;
    }

    out.innerHTML = '<div class="flex items-center gap-2 text-slate-500"><span class="material-symbols-outlined animate-spin" style="font-size:16px">progress_activity</span>분석 중...</div>';
    if (btn) btn.disabled = true;

    // 모드별 프롬프트
    var prompts = {
      'analyze-text': '플랫폼: ' + _trendPlatform + '\n\n' +
        '아래는 ' + _trendPlatform + '의 인기작 정보입니다. ' +
        (_trendImageBase64 ? '첨부된 스크린샷과 ' : '') +
        '텍스트 데이터를 종합 분석해서 공통 패턴을 도출해주세요. 한국어 응답.\n\n' +
        (userText ? '【사용자 입력】\n' + userText + '\n\n' : '') +
        '응답 형식 (HTML, 마크다운 X):\n' +
        '<h3 style="color:#ea580c;font-weight:800">🔑 공통 키워드 / 태그</h3>\n<ul>빈도순</ul>\n' +
        '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">📖 시놉시스/제목 공통 패턴</h3>\n<ul>구조/소재/도입부 패턴 (예시 인용 필수)</ul>\n' +
        '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">👤 캐릭터 특징</h3>\n<ul>남주/여주(또는 페어) 자주 나오는 설정</ul>\n' +
        '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">⭐ 성공 요인 추정</h3>\n<ul>왜 이 작품들이 인기인가</ul>\n' +
        '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">💎 차별화 제안</h3>\n<ul>이 패턴을 알고 다르게 가는 방법 3개 (구체적 액션)</ul>',
      character: '플랫폼: ' + _trendPlatform + '\n\n' +
        (_trendPlatform === '포스타입' ?
          '아래 2차 창작 페어/캐릭터의 인기 트로프를 분석해주세요. 한국어 응답.\n\n【대상】 ' + userText + '\n\n' +
          '응답 형식 (HTML, 마크다운 X):\n' +
          '<h3 style="color:#ea580c;font-weight:800">💖 이 페어의 인기 트로프</h3>\n<ul>자주 보이는 관계 설정 (소꿉친구, 적대→연인, ABO 등)</ul>\n' +
          '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">🎭 캐릭터 해석 패턴</h3>\n<ul>"공/수" 또는 "Top/Bottom" 분배, 성격 해석 트렌드</ul>\n' +
          '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">📝 인기 장르/소재</h3>\n<ul>학원물/판타지/현대/사극 등 + 자주 쓰이는 클리셰</ul>\n' +
          '<h3 style="color:#ea580c;font-weight:800;margin-top:12px">⭐ 차별화 제안</h3>\n<ul>같은 페어 다른 작품 대비 새로운 방향 3개</ul>'
        :
          '아래 캐릭터 설정/장르가 ' + _trendPlatform + '에서 통할지 분석해주세요.\n\n【설정】 ' + userText + '\n\n' +
          '응답 형식 (HTML):\n<h3>📈 현재 시장 적합성</h3>\n<h3>🔥 비슷한 인기작</h3>\n<h3>⚠️ 진부할 수 있는 요소</h3>\n<h3>💎 강화 포인트</h3>'
        )
    };

    try {
      var model = localStorage.getItem('atelier_anthropic_model') || 'claude-opus-4-7';
      var content;
      // 통합 직접 분석: 이미지가 있으면 vision API에 함께 전송
      if (_trendMode === 'analyze-text' && _trendImageBase64) {
        content = [
          { type: 'image', source: { type: 'base64', media_type: _trendImageType, data: _trendImageBase64 } },
          { type: 'text', text: prompts[_trendMode] }
        ];
      } else {
        content = prompts[_trendMode] || prompts['analyze-text'];
      }
      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true', 'content-type': 'application/json' },
        body: JSON.stringify({ model: model, max_tokens: 2500, messages: [{ role: 'user', content: content }] })
      });
      if (!res.ok) throw new Error('AI 호출 실패 (' + res.status + ')');
      var data = await res.json();
      var resultText = (data.content && data.content[0] && data.content[0].text || '').trim();
      _trendLastResult = resultText;
      out.innerHTML = '<div style="font-family:\'Pretendard\',sans-serif;line-height:1.7;color:#27313f">' + resultText + '</div>';
      var copyBtn = document.getElementById('trend-copy-btn');
      if (copyBtn) copyBtn.classList.remove('hidden');
    } catch(e) {
      console.error('[trend research]', e);
      out.innerHTML = '<div class="text-rose-700 p-3 bg-rose-50 rounded-lg">⚠️ ' + (e.message||'분석 실패') + '</div>';
    } finally {
      if (btn) btn.disabled = false;
    }
  };

  window._copyTrendResult = async function() {
    if (!_trendLastResult) return;
    try {
      var plain = _trendLastResult.replace(/<[^>]+>/g,'').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&');
      await navigator.clipboard.writeText(plain);
      if (typeof showSyncToast === 'function') showSyncToast('📋 복사됨');
    } catch(e) { console.warn('clipboard:', e); }
  };

  // ═══════════════════════════════════════════════════════
  // 부업 수익 예측 (AI 분석)
  // ═══════════════════════════════════════════════════════
  window.generateIncomeForecast = async function(forceRefresh) {
    var ytdEl = document.getElementById('forecast-ytd');
    var ytdTrendEl = document.getElementById('forecast-ytd-trend');
    var nextQEl = document.getElementById('forecast-next-q');
    var nextQDetailEl = document.getElementById('forecast-next-q-detail');
    var yearEl = document.getElementById('forecast-year-end');
    var yearDetailEl = document.getElementById('forecast-year-end-detail');
    var insightsEl = document.getElementById('forecast-insights');
    if (!insightsEl) return;

    // 캐시 (12시간)
    var cacheKey = 'atelier_income_forecast_v1';
    if (!forceRefresh) {
      try {
        var cached = JSON.parse(localStorage.getItem(cacheKey));
        if (cached && cached.at && (Date.now() - cached.at < 12*3600000)) {
          if (ytdEl) ytdEl.textContent = cached.ytd;
          if (ytdTrendEl) ytdTrendEl.textContent = cached.ytdTrend;
          if (nextQEl) nextQEl.textContent = cached.nextQ;
          if (nextQDetailEl) nextQDetailEl.textContent = cached.nextQDetail;
          if (yearEl) yearEl.textContent = cached.year;
          if (yearDetailEl) yearDetailEl.textContent = cached.yearDetail;
          if (insightsEl) insightsEl.innerHTML = cached.insights;
          return;
        }
      } catch(e){}
    }

    insightsEl.innerHTML = '<div class="text-slate-400 italic flex items-center gap-2"><span class="material-symbols-outlined animate-spin" style="font-size:14px">progress_activity</span>분석 중...</div>';

    // 모든 연도 시리즈 데이터 수집
    var now = new Date();
    var thisYr = now.getFullYear();
    var lastYr = thisYr - 1;
    var thisMonth = now.getMonth(); // 0-indexed

    function getYrSeries(yr) {
      try {
        var key = 'atelier_series_' + yr;
        return JSON.parse(localStorage.getItem(key)) || [];
      } catch(e) { return []; }
    }
    var seriesThisYr = getYrSeries(thisYr);
    var seriesLastYr = getYrSeries(lastYr);

    // 월별 수익 합산
    function totalByMonth(series) {
      var monthly = new Array(12).fill(0);
      series.forEach(function(s){
        for (var m = 0; m < 12; m++) {
          if (s.monthly && s.monthly[m]) monthly[m] += (s.monthly[m].rev||0);
        }
      });
      return monthly;
    }
    var thisYrMonthly = totalByMonth(seriesThisYr);
    var lastYrMonthly = totalByMonth(seriesLastYr);

    // YTD (올해 누적)
    var ytdAmt = 0;
    for (var m = 0; m <= thisMonth; m++) ytdAmt += thisYrMonthly[m];
    var lastYrSamePeriod = 0;
    for (var m2 = 0; m2 <= thisMonth; m2++) lastYrSamePeriod += lastYrMonthly[m2];
    var ytdGrowthPct = lastYrSamePeriod > 0 ? Math.round((ytdAmt - lastYrSamePeriod) / lastYrSamePeriod * 100) : 0;

    // 다음 분기 예측: 다음 3개월의 작년 동기 + 트렌드 보정
    var nextQAmt = 0;
    for (var nq = 1; nq <= 3; nq++) {
      var mIdx = thisMonth + nq;
      if (mIdx > 11) break;
      // 작년 같은 달 + 트렌드(%) 적용
      var lastYrM = lastYrMonthly[mIdx] || 0;
      var trended = Math.round(lastYrM * (1 + ytdGrowthPct/100));
      nextQAmt += trended;
    }

    // 연말 예상 (현재까지 + 남은 달 트렌드 보정 예측)
    var yearEndAmt = ytdAmt;
    for (var rm = thisMonth+1; rm < 12; rm++) {
      var lastYrM2 = lastYrMonthly[rm] || 0;
      yearEndAmt += Math.round(lastYrM2 * (1 + ytdGrowthPct/100));
    }

    // 단위 포맷 (시리즈 데이터는 만원 단위)
    function fmt(amt) {
      if (!amt) return '₩0';
      var abs = Math.abs(amt);
      if (abs >= 10000) return '₩' + (amt / 10000).toFixed(2).replace(/\.?0+$/,'') + '억';
      return '₩' + Math.round(amt).toLocaleString('ko-KR') + '만';
    }

    var ytdStr = fmt(ytdAmt);
    var ytdTrendStr = '전년 동기 ' + (ytdGrowthPct >= 0 ? '+' : '') + ytdGrowthPct + '% (' + fmt(lastYrSamePeriod) + ')';
    var nextQStr = fmt(nextQAmt);
    var nextQDetailStr = (thisMonth+2 <= 11 ? '다음 3개월 (' + (thisMonth+2) + '~' + (thisMonth+4) + '월)' : '연내 잔여');
    var yearStr = fmt(yearEndAmt);
    var yearDetailStr = thisYr + '년 예상 총수익';

    if (ytdEl) ytdEl.textContent = ytdStr;
    if (ytdTrendEl) { ytdTrendEl.textContent = ytdTrendStr; ytdTrendEl.style.color = ytdGrowthPct >= 0 ? '#10b981' : '#dc2626'; }
    if (nextQEl) nextQEl.textContent = nextQStr;
    if (nextQDetailEl) nextQDetailEl.textContent = nextQDetailStr;
    if (yearEl) yearEl.textContent = yearStr;
    if (yearDetailEl) yearDetailEl.textContent = yearDetailStr;

    // AI 인사이트 (Claude로 분석 코멘트)
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) {
      insightsEl.innerHTML = '<div class="text-amber-700">⚙️ AI 인사이트는 <button onclick="openApiSettingsModal()" class="underline font-bold">API 키 설정</button>이 필요해요.</div>';
      return;
    }

    try {
      // 시리즈별 디테일 데이터 수집
      var seriesDetail = seriesThisYr.map(function(s){
        var totalRev = 0, monthsActive = 0;
        for (var m = 0; m <= thisMonth; m++) {
          if (s.monthly && s.monthly[m] && s.monthly[m].rev) { totalRev += s.monthly[m].rev; monthsActive++; }
        }
        return { name: s.name, total: totalRev, avg: monthsActive ? Math.round(totalRev/monthsActive) : 0 };
      }).filter(function(s){return s.total > 0;}).sort(function(a,b){return b.total-a.total;});

      var worksData = (typeof _works !== 'undefined' && _works) ? _works.filter(function(w){return w.status==='confirmed';}).map(function(w){
        return { title: w.title, series: w.series_name, end: w.publish_end };
      }) : [];

      var prompt = '당신은 부업 작가의 재무 분석가입니다. 아래 데이터를 보고 200자 내 인사이트를 한국어로 작성해주세요.\n\n' +
        '【' + thisYr + '년 YTD】 ' + ytdStr + ' (' + (thisMonth+1) + '개월)\n' +
        '【전년 동기】 ' + fmt(lastYrSamePeriod) + ' → 성장률 ' + ytdGrowthPct + '%\n' +
        '【다음 분기 예측】 ' + nextQStr + '\n' +
        '【연말 예상】 ' + yearStr + '\n\n' +
        '【시리즈별 (월평균)】\n' + seriesDetail.map(function(s){return '- ' + s.name + ': 누적 ' + fmt(s.total) + ', 월 ' + fmt(s.avg);}).join('\n') + '\n\n' +
        '【연재 작품】\n' + worksData.map(function(w){return '- ' + w.title + ' (' + w.series + ', 종료 ' + w.end + ')';}).join('\n') + '\n\n' +
        '응답 형식 (HTML, 마크다운 X):\n' +
        '<h4 style="color:#7c3aed;font-weight:800;margin-bottom:6px">💡 인사이트</h4>\n<ul style="padding-left:18px;list-style:disc">\n  <li>핵심 트렌드 (1-2문장)</li>\n  <li>주의 사항 (있으면)</li>\n  <li>실행 가능한 액션 (1-2개)</li>\n</ul>\n\n구체적이고 친근한 톤. 액션은 시리즈명·기간 포함해서 구체적으로.';

      var model = localStorage.getItem('atelier_anthropic_model') || 'claude-sonnet-4-6';
      if (model.indexOf('opus') >= 0) model = 'claude-opus-4-7';
      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true', 'content-type': 'application/json' },
        body: JSON.stringify({ model: model, max_tokens: 800, messages: [{ role: 'user', content: prompt }] })
      });
      if (!res.ok) throw new Error('AI 호출 실패');
      var data = await res.json();
      var insightsText = (data.content && data.content[0] && data.content[0].text || '').trim();
      insightsEl.innerHTML = insightsText;
      // 캐시
      try { localStorage.setItem(cacheKey, JSON.stringify({
        ytd: ytdStr, ytdTrend: ytdTrendStr, nextQ: nextQStr, nextQDetail: nextQDetailStr,
        year: yearStr, yearDetail: yearDetailStr, insights: insightsText, at: Date.now()
      })); } catch(e){}
    } catch(e) {
      console.error('[forecast]', e);
      insightsEl.innerHTML = '<div class="text-rose-700">⚠️ ' + (e.message||'분석 실패') + ' <button onclick="generateIncomeForecast(true)" class="underline font-bold ml-1">재시도</button></div>';
    }
  };

  // Enter로 검색 실행 + Esc로 닫기
  document.addEventListener('DOMContentLoaded', function(){
    var inp = document.getElementById('ai-search-input');
    if (inp) {
      inp.addEventListener('keydown', function(e){
        if (e.key === 'Enter') { e.preventDefault(); _runAiSearch(inp.value.trim()); }
        else if (e.key === 'Escape') { e.preventDefault(); closeAiSearchModal(); }
      });
    }
    // Cmd+K 단축키 — AI 검색 모달 열기 (기존 input focus 대신)
    document.addEventListener('keydown', function(e){
      if ((e.metaKey || e.ctrlKey) && e.key === 'k' && !e.shiftKey) {
        // 입력 중인 input이 있으면 무시
        var ae = document.activeElement;
        if (ae && (ae.tagName === 'INPUT' || ae.tagName === 'TEXTAREA') && ae.id !== 'global-search-input') return;
        e.preventDefault();
        openAiSearchModal();
      }
      if (e.key === 'Escape') {
        var sm = document.getElementById('ai-search-modal');
        if (sm && sm.style.display !== 'none' && getComputedStyle(sm).display !== 'none') closeAiSearchModal();
      }
    });
  });

  window.generateTravelRecommend = async function(forceRefresh) {
    var contentEl = document.getElementById('travel-recommend-content');
    var summaryEl = document.getElementById('travel-recommend-summary');
    if (!contentEl) return;
    // 캐시 (24h)
    var cacheKey = 'atelier_travel_recommend_v1';
    if (!forceRefresh) {
      try {
        var cached = JSON.parse(localStorage.getItem(cacheKey));
        if (cached && cached.html && (Date.now() - cached.at < 24*3600000)) {
          contentEl.innerHTML = cached.html;
          if (summaryEl && cached.summary) { summaryEl.innerHTML = cached.summary; summaryEl.classList.remove('hidden'); }
          return;
        }
      } catch(e){}
    }
    // API 키
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) {
      contentEl.innerHTML = '<div class="text-sm text-slate-600 p-4 bg-amber-50 rounded-xl">⚙️ AI 추천을 보려면 <button onclick="openApiSettingsModal()" class="underline font-bold text-violet-700">API 키 설정</button>이 필요해요.</div>';
      return;
    }
    contentEl.innerHTML = '<div class="flex items-center gap-2 text-slate-500"><span class="material-symbols-outlined animate-spin" style="font-size:16px">progress_activity</span>과거 여행 패턴 분석 중...</div>';
    if (summaryEl) summaryEl.classList.add('hidden');

    try {
      // 모든 트립 + 도시 + journey 데이터 수집
      var [trips, allCities, allJourney, allHub] = await Promise.all([
        fbRead('trips'), fbRead('trip_cities'), fbRead('journey'), fbRead('finance_hub')
      ]);
      // 트립별 요약 (이름, 기간, 도시들, 예산)
      var tripSummaries = trips.map(function(t){
        var cities = allCities.filter(function(c){return c.trip_id === t._id;}).map(function(c){return c.name;});
        var journeys = allJourney.filter(function(j){return j.trip_id === t._id;});
        var totalAmt = 0;
        journeys.forEach(function(j){ totalAmt += parseFloat(String(j.amount||'').replace(/[^0-9.]/g,''))||0; });
        // hub에서 trip별 총액
        var hubAmt = 0;
        (allHub||[]).forEach(function(h){
          if ((h.trip||'') === t.name && (h.type||'') === '지출') hubAmt += parseFloat(h.amount||0)||0;
        });
        return {
          name: t.name,
          start: t.start_date,
          end: t.end_date,
          cities: cities,
          spend_man: Math.round(hubAmt) || Math.round(totalAmt/10000)
        };
      });

      // 메모(refCards)에서 여행 취향 힌트 추출 (트립노트 같은 거)
      var refDocs = await fbRead('refCards').catch(function(){return [];});
      var preferences = [];
      (refDocs||[]).forEach(function(r){
        var content = (r.title||'') + ' ' + (r.body||'');
        if (/디자인|미술|museum|gallery|건축/i.test(content)) preferences.push('미술관/박물관');
        if (/카페|coffee|커피/i.test(content)) preferences.push('카페');
        if (/음식|미식|음식점|restaurant/i.test(content)) preferences.push('미식');
      });
      preferences = [...new Set(preferences)];

      // 분석 summary 표시
      var pastTrips = tripSummaries.filter(function(t){return (t.start||'') < new Date().toISOString().split('T')[0];});
      var futureTrips = tripSummaries.filter(function(t){return (t.start||'') >= new Date().toISOString().split('T')[0];});
      var allCitiesFlat = [];
      tripSummaries.forEach(function(t){ allCitiesFlat = allCitiesFlat.concat(t.cities||[]); });
      var summaryHtml = '<strong>📊 분석 데이터:</strong> 총 ' + trips.length + '개 여행 (지난 ' + pastTrips.length + ' / 예정 ' + futureTrips.length + '), 방문 도시 ' + new Set(allCitiesFlat).size + '곳';
      if (preferences.length) summaryHtml += ' · 취향: ' + preferences.join(', ');
      if (summaryEl) { summaryEl.innerHTML = summaryHtml; summaryEl.classList.remove('hidden'); }

      // Claude 프롬프트
      var prompt = '당신은 여행 큐레이터입니다. 사용자의 과거 여행 데이터를 분석해서 다음 추천 여행지 3개를 제안하세요.\n\n' +
        '【과거 여행】\n' +
        tripSummaries.map(function(t){
          return '- ' + t.name + ' (' + t.start + '~' + t.end + ', 도시: ' + (t.cities||[]).join('/') + ', 예산: 약 ' + t.spend_man + '만원)';
        }).join('\n') +
        '\n\n【사용자 취향】 ' + (preferences.join(', ') || '디자인·건축·미식') + '\n\n' +
        '응답 형식 — JSON 배열, 다른 설명 금지:\n' +
        '[\n' +
        '  {\n' +
        '    "destination": "도시 또는 지역명 (예: 포르투갈 리스본)",\n' +
        '    "season": "추천 시기 (예: 2027년 4월)",\n' +
        '    "duration": "예상 기간 (예: 8박 10일)",\n' +
        '    "budget": "예상 예산 (예: 350만원)",\n' +
        '    "reason": "왜 추천 — 사용자 패턴과 연결 (60자 내)",\n' +
        '    "highlights": ["가야할 곳1", "가야할 곳2", "가야할 곳3"]\n' +
        '  }\n' +
        '] (총 3개)\n\n' +
        '규칙:\n' +
        '- 과거 가본 도시 제외 (재방문 추천 X)\n' +
        '- 비슷한 분위기/취향 매칭\n' +
        '- 시기는 사용자가 보통 여행 가는 월(과거 패턴) 고려\n' +
        '- 예산도 과거 평균 ±20% 범위로 추천';

      var model = localStorage.getItem('atelier_anthropic_model') || 'claude-sonnet-4-6';
      if (model.indexOf('opus') >= 0) model = 'claude-opus-4-7'; // 추천은 opus가 더 좋음

      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'x-api-key': apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
          'content-type': 'application/json'
        },
        body: JSON.stringify({ model: model, max_tokens: 2000, messages: [{ role: 'user', content: prompt }] })
      });
      if (!res.ok) throw new Error('AI 호출 실패 (HTTP ' + res.status + ')');
      var data = await res.json();
      var text = (data.content && data.content[0] && data.content[0].text || '').trim();
      var jm = text.match(/\[[\s\S]*\]/);
      if (!jm) throw new Error('AI 응답 파싱 실패');
      var recs = JSON.parse(jm[0]);

      // 카드로 렌더
      var html = recs.map(function(r, i){
        var grad = ['#fce7f3,#fbcfe8', '#ede9fe,#ddd6fe', '#dbeafe,#bfdbfe'][i] || '#f1f5f9,#e2e8f0';
        var iconColor = ['#ec4899','#a855f7','#3b82f6'][i] || '#64748b';
        var highlights = (r.highlights||[]).map(function(h){ return '<span class="inline-flex items-center gap-0.5 text-[11px] px-2 py-0.5 bg-white/70 rounded-full font-medium text-slate-700">📍 ' + String(h).replace(/</g,'&lt;') + '</span>'; }).join(' ');
        return '<div class="rounded-2xl p-4 border" style="background:linear-gradient(135deg,' + grad + ');border-color:' + iconColor + '33">' +
          '<div class="flex items-start justify-between mb-2">' +
            '<div>' +
              '<div class="flex items-center gap-1.5 mb-1">' +
                '<span class="material-symbols-outlined" style="font-size:18px;color:' + iconColor + '">flight_takeoff</span>' +
                '<h4 class="text-base font-extrabold text-slate-900">' + (r.destination||'—').replace(/</g,'&lt;') + '</h4>' +
              '</div>' +
              '<div class="flex items-center gap-3 text-[11px] text-slate-600 font-medium">' +
                '<span>📅 ' + (r.season||'').replace(/</g,'&lt;') + '</span>' +
                '<span>⏱ ' + (r.duration||'').replace(/</g,'&lt;') + '</span>' +
                '<span>💰 ' + (r.budget||'').replace(/</g,'&lt;') + '</span>' +
              '</div>' +
            '</div>' +
            '<span class="text-[10px] font-black text-white px-2 py-0.5 rounded-full" style="background:' + iconColor + '">#' + (i+1) + '</span>' +
          '</div>' +
          '<p class="text-[12px] text-slate-700 leading-relaxed mb-2">' + (r.reason||'').replace(/</g,'&lt;') + '</p>' +
          (highlights ? '<div class="flex flex-wrap gap-1">' + highlights + '</div>' : '') +
        '</div>';
      }).join('');
      contentEl.innerHTML = html;
      try { localStorage.setItem(cacheKey, JSON.stringify({ html: html, summary: summaryHtml, at: Date.now() })); } catch(e){}
    } catch(e) {
      console.error('[travel recommend]', e);
      contentEl.innerHTML = '<div class="text-sm text-rose-700 p-4 bg-rose-50 rounded-xl">⚠️ ' + (e.message||'추천 생성 실패') + ' <button onclick="generateTravelRecommend(true)" class="underline font-bold ml-1">재시도</button></div>';
    }
  };

  let dashMilestones = []; // 캐시

  function renderDashboardMilestones(rows, now) {
    const monthStr = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    dashMilestones = rows.filter(function(r){ return (r[0]||'').toString().startsWith(monthStr); });

    const container = document.getElementById('dash-milestones');
    if (dashMilestones.length === 0) {
      container.innerHTML = '<p class="text-sm text-slate-400 py-2">이번 달 목표가 없어요<br/><span class="text-xs">+ 버튼으로 추가해봐!</span></p>';
    } else {
      var done = dashMilestones.filter(function(r){ return r[2]==='완료'; }).length;
      var pct = Math.round((done/dashMilestones.length)*100);
      container.innerHTML =
        '<div class="flex items-center gap-2 mb-3">' +
        '<div class="flex-1 h-1.5 bg-slate-100 rounded-full overflow-hidden"><div class="h-full gradient-primary rounded-full" style="width:'+pct+'%"></div></div>' +
        '<span class="text-[10px] font-black text-indigo-600">'+done+'/'+dashMilestones.length+'</span></div>' +
        dashMilestones.map(function(r) {
          var statusCls = MILESTONE_STATUS[r[2]] || MILESTONE_STATUS['예정'];
          var id = r[3]||''; // _id is at index 3
          return '<div class="flex items-center gap-2 group py-1">' +
            '<button data-mid="'+id+'" onclick="toggleDashGoal(this.dataset.mid)" class="w-4 h-4 rounded-full border-2 flex items-center justify-center shrink-0 transition-all '+(r[2]==='완료'?'bg-teal-500 border-teal-500 text-white':'border-slate-300 hover:border-indigo-400')+'">'+(r[2]==='완료'?'<span class="material-symbols-outlined" style="font-size:10px">check</span>':'')+
            '</button>' +
            '<span class="text-xs font-semibold text-slate-700 flex-1 '+(r[2]==='완료'?'line-through text-slate-400':'')+'">'+(r[1]||'')+'</span>' +
            '<div class="flex gap-1 opacity-0 group-hover:opacity-100 transition-all shrink-0">' +
            '<button data-mid="'+id+'" onclick="openDashGoalModal(this.dataset.mid)" class="p-0.5 hover:bg-indigo-100 rounded text-slate-300 hover:text-indigo-600"><span class="material-symbols-outlined text-xs">edit</span></button>' +
            '<button data-mid="'+id+'" onclick="deleteDashGoal(this.dataset.mid)" class="p-0.5 hover:bg-rose-100 rounded text-slate-300 hover:text-rose-500"><span class="material-symbols-outlined text-xs">delete</span></button>' +
            '</div></div>';
        }).join('');
    }

    // Banner
    if (dashMilestones.length > 0) {
      const featured = dashMilestones.find(function(r){ return r[2]==='진행 중'; }) || dashMilestones[0];
      const months = ['1월','2월','3월','4월','5월','6월','7월','8월','9월','10월','11월','12월'];
      document.getElementById('dash-milestone-month').textContent = months[now.getMonth()];
      document.getElementById('dash-milestone-title').textContent = featured[1] || '—';
      document.getElementById('dash-milestone-desc').textContent =
        dashMilestones.length + '개 목표 중 ' + dashMilestones.filter(function(r){return r[2]==='완료';}).length + '개 완료';
    }
  }

  // Dashboard Goal CRUD
  var editingDashGoalId = null;

  function openDashGoalModal(id) {
    editingDashGoalId = id || null;
    // Reuse planner goal modal
    document.getElementById('goal-modal-title').textContent = editingDashGoalId ? '목표 수정' : '목표 추가';
    if (editingDashGoalId) {
      var g = dashMilestones.find(function(r){ return r[3] === editingDashGoalId; });
      document.getElementById('goal-text').value = g ? (g[1]||'') : '';
      document.getElementById('goal-status').value = g ? (g[2]||'진행 중') : '진행 중';
    } else {
      document.getElementById('goal-text').value = '';
      document.getElementById('goal-status').value = '진행 중';
    }
    // Override save button to use dash save
    document.getElementById('goal-save-btn').setAttribute('onclick', 'saveDashGoalEntry()');
    document.getElementById('goal-modal').style.cssText = 'display:flex!important';
  }

  async function saveDashGoalEntry() {
    var btn = document.getElementById('goal-save-btn');
    btn.textContent = '저장 중...'; btn.disabled = true;
    var now = new Date();
    var monthStr = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    var obj = {
      month: monthStr,
      goal: document.getElementById('goal-text').value.trim(),
      status: document.getElementById('goal-status').value,
    };
    if (!obj.goal) { alert('목표 내용을 입력해줘!'); btn.textContent='저장'; btn.disabled=false; return; }
    try {
      if (editingDashGoalId) {
        await fbUpdate('milestones', editingDashGoalId, obj);
      } else {
        await fbAdd('milestones', obj);
      }
      // Reload dashboard
      closeGoalModal();
      loadDashboard();
    } catch(err) { alert('저장에 실패했어요.'); }
    finally {
      btn.textContent = '저장';
      btn.disabled = false;
      btn.setAttribute('onclick', 'saveGoalEntry()');
    }
  }

  async function deleteDashGoal(id) {
    try {
      await fbDelete('milestones', id);
      loadDashboard();
    } catch(err) { alert('삭제에 실패했어요.'); }
  }

  async function toggleDashGoal(id) {
    var g = dashMilestones.find(function(r){ return r[3] === id; });
    if (!g) return;
    var next = g[2] === '완료' ? '진행 중' : '완료';
    try {
      await fbUpdate('milestones', id, {status: next});
      loadDashboard();
    } catch(err) { console.error(err); }
  }

  function renderDashboardJourney(rows, now) {
    const upcoming = rows.filter(function(r){
      return r[2]==='여행' || (r[1]||'').includes('여행') || (r[1]||'').includes('여행');
    }).filter(function(r){
      return new Date(r[0]) >= now;
    }).sort(function(a,b){ return new Date(a[0])-new Date(b[0]); });

    if (upcoming.length > 0) {
      document.getElementById('dash-journey-title').textContent = upcoming[0][1] || '—';
      document.getElementById('dash-journey-events').innerHTML = upcoming.slice(0,3).map(function(r){
        return '<div class="flex items-center gap-3">' +
          '<div class="w-2 h-2 rounded-full bg-indigo-400 shrink-0"></div>' +
          '<div><p class="text-sm font-semibold text-slate-700">' + (r[1]||'') + '</p>' +
          '<p class="text-[10px] text-slate-400">' + (r[0]||'') + '</p></div>' +
          '</div>';
      }).join('');
    }
  }



  // Sheets: Date | Description | Trip | Category | Amount | Currency
  let financeData = [];
  let financeFiltered = [];
  let editingFinanceIndex = null;
  let currentFinanceTrip = 'all';

  const FIN_CAT_ICONS = {'입금':'savings','이동':'flight','숙소':'bed','식비':'restaurant','여가':'attractions','쇼핑':'shopping_bag','티켓':'confirmation_number','보험':'shield','통신':'sim_card','환전':'currency_exchange','렌트':'directions_car','교통':'directions_subway','기타':'more_horiz'};
  const FIN_CAT_COLORS = {'입금':'text-emerald-600','이동':'text-indigo-600','숙소':'text-blue-600','식비':'text-purple-600','여가':'text-teal-600','쇼핑':'text-rose-500','티켓':'text-amber-600','보험':'text-cyan-600','통신':'text-violet-600','환전':'text-orange-600','렌트':'text-pink-600','교통':'text-lime-600','기타':'text-slate-500'};
