  // 하드코딩 defaults는 마이그레이션 후 더 이상 노출하지 않음 (Firestore에 실제 문서로 존재)
  var _financeDefaultsMigrated = false;
  function getFinanceDefaults() {
    if (_financeDefaultsMigrated) return [];
    // 마이그레이션 전(또는 실패) 폴백: 기존 동작 유지 — 삭제 묘비/편집 적용된 defaults 반환
    var fbKeys = {};
    financeData.forEach(function(r){ fbKeys[(r[0]||'')+'|'+(r[1]||'')+'|'+(r[4]||'')] = true; });
    var dels = JSON.parse(localStorage.getItem('atelier_finance_dels')||'[]');
    var delSet = {}; dels.forEach(function(k){ delSet[k]=true; });
    var edits = JSON.parse(localStorage.getItem('atelier_finance_edits')||'{}');

    function mapRow(d, trip) {
      var key = d[0]+'|'+d[1]+'|'+d[3];
      var key2 = d[0]+'|'+d[1]+'|'+String(d[3]);
      if (fbKeys[key] || fbKeys[key2] || delSet[key] || delSet[key2]) return null;
      var row = [d[0], d[1], trip, d[2], d[3], 'KRW', '', '__default__'];
      if (edits[key]) { var e=edits[key]; row[0]=e.date; row[1]=e.desc; row[3]=e.cat; row[4]=e.amt; }
      return row;
    }
    var d1 = FINANCE_DEFAULTS.map(function(d){ return mapRow(d, FINANCE_SEED_TRIP); }).filter(Boolean);
    var d2 = FINANCE_DEFAULTS2.map(function(d){ return mapRow(d, FINANCE_SEED_TRIP2); }).filter(Boolean);
    return d1.concat(d2);
  }

  // 하드코딩 defaults를 Firestore에 실제 문서로 옮기는 1회성 마이그레이션
  // - 이미 묘비(dels)에 있는 항목은 건너뜀 (사용자가 삭제한 항목 존중)
  // - 이미 Firestore에 같은 키(date|desc|amount)가 있으면 건너뜀 (중복 방지)
  // - 완료 후 appSettings/financeLocalState.defaultsMigrated = true 마킹 → 다른 기기에서 재실행 안 됨
  async function migrateFinanceDefaultsToFirebase(existingDocs) {
    try {
      var stateDoc = await db.collection('appSettings').doc('financeLocalState').get();
      var state = stateDoc.exists ? stateDoc.data() : {};
      if (state.defaultsMigrated === true) {
        _financeDefaultsMigrated = true;
        console.log('[Finance Migration] 이미 완료됨, 스킵');
        return false;
      }

      var dels = Array.isArray(state.dels) ? state.dels : JSON.parse(localStorage.getItem('atelier_finance_dels')||'[]');
      var delSet = {}; dels.forEach(function(k){ delSet[k]=true; });
      var edits = (state.edits && typeof state.edits === 'object') ? state.edits : JSON.parse(localStorage.getItem('atelier_finance_edits')||'{}');

      var existingKeys = {};
      (existingDocs || []).forEach(function(d) {
        var row = objToRow('finance', d);
        var k = (row[0]||'')+'|'+(row[1]||'')+'|'+(row[4]||'');
        var k2 = (row[0]||'')+'|'+(row[1]||'')+'|'+String(row[4]||'');
        existingKeys[k] = true;
        existingKeys[k2] = true;
      });

      var allDefaults = [];
      FINANCE_DEFAULTS.forEach(function(d) { allDefaults.push({ d: d, trip: FINANCE_SEED_TRIP }); });
      FINANCE_DEFAULTS2.forEach(function(d) { allDefaults.push({ d: d, trip: FINANCE_SEED_TRIP2 }); });

      var migrated = 0, skippedDel = 0, skippedDup = 0;
      for (var i = 0; i < allDefaults.length; i++) {
        var entry = allDefaults[i];
        var d = entry.d;
        var key1 = d[0]+'|'+d[1]+'|'+d[3];
        var key2 = d[0]+'|'+d[1]+'|'+String(d[3]);
        if (delSet[key1] || delSet[key2]) { skippedDel++; continue; }
        if (existingKeys[key1] || existingKeys[key2]) { skippedDup++; continue; }
        var row = [d[0], d[1], entry.trip, d[2], d[3], 'KRW', ''];
        if (edits[key1]) { var e = edits[key1]; row[0] = e.date; row[1] = e.desc; row[3] = e.cat; row[4] = e.amt; }
        try {
          await fbAdd('finance', rowToObj('finance', row));
          migrated++;
        } catch(err) {
          console.error('[Finance Migration] 행 마이그레이션 실패:', d, err);
        }
      }

      await db.collection('appSettings').doc('financeLocalState').set({
        defaultsMigrated: true,
        defaultsMigratedAt: new Date().toISOString(),
        defaultsMigratedCount: migrated
      }, { merge: true });

      _financeDefaultsMigrated = true;
      console.log('[Finance Migration] 완료: 추가됨=' + migrated + ', 삭제묘비스킵=' + skippedDel + ', 중복스킵=' + skippedDup);
      return migrated > 0;
    } catch(e) {
      console.error('[Finance Migration] 오류 (폴백 동작 유지):', e);
      return false;
    }
  }

  // journey ↔ finance 설명 포맷 v2 일괄 재동기화 (도시/체크인-아웃/탑승일 포함)
  async function migrateJourneyFinanceDescriptions() {
    try {
      var stateDoc = await db.collection('appSettings').doc('financeLocalState').get();
      var state = stateDoc.exists ? stateDoc.data() : {};
      if (state.journeyFinanceDescV2 === true) return false;

      var results = await Promise.all([fbRead('trips'), fbRead('journey')]);
      var tripDocs = results[0], journeyDocs = results[1];
      var tripMap = {};
      tripDocs.forEach(function(t) { tripMap[t._id] = t.name; });

      var updated = 0;
      for (var i = 0; i < journeyDocs.length; i++) {
        var item = journeyDocs[i];
        if (!item.finance_id) continue;
        var amt = parseFloat(String(item.amount||'').replace(/[^0-9.]/g,''));
        if (!amt || amt === 0) continue;
        var tripName = tripMap[item.trip_id] || '';
        if (!tripName) continue;
        var financeObj = _journeyToFinanceObj(item, tripName);
        try {
          await fbUpdate('finance', item.finance_id, financeObj);
          updated++;
        } catch(e) {
          console.error('[Journey Finance Re-sync]', item._id, e);
        }
      }

      await db.collection('appSettings').doc('financeLocalState').set({
        journeyFinanceDescV2: true,
        journeyFinanceDescV2At: new Date().toISOString(),
        journeyFinanceDescV2Count: updated
      }, { merge: true });

      console.log('[Journey Finance Re-sync] 완료: ' + updated + '건 재동기화');
      return updated > 0;
    } catch(e) {
      console.error('[Journey Finance Re-sync] 오류:', e);
      return false;
    }
  }

  var financeTrips = [];
  function getDefaultFinanceTrip(trips) {
    if (!trips || !trips.length) return 'all';
    var today = new Date().toISOString().split('T')[0];
    // 1: ongoing trip
    var ongoing = trips.filter(function(t){ return t.start_date && t.end_date && t.start_date <= today && t.end_date >= today; });
    if (ongoing.length) return ongoing[0].name;
    // 2: closest upcoming
    var upcoming = trips.filter(function(t){ return t.start_date && t.start_date > today; })
      .sort(function(a,b){ return a.start_date.localeCompare(b.start_date); });
    if (upcoming.length) return upcoming[0].name;
    // 3: most recent past
    var past = trips.filter(function(t){ return t.end_date && t.end_date < today; })
      .sort(function(a,b){ return b.end_date.localeCompare(a.end_date); });
    if (past.length) return past[0].name;
    return 'all';
  }

  // Finance dels/edits Firebase 동기화 (다기기 공유)
  async function loadFinanceLocalStateFromFirebase() {
    try {
      var doc = await db.collection('appSettings').doc('financeLocalState').get();
      if (doc.exists) {
        var d = doc.data();
        if (Array.isArray(d.dels)) localStorage.setItem('atelier_finance_dels', JSON.stringify(d.dels));
        if (d.edits && typeof d.edits === 'object') localStorage.setItem('atelier_finance_edits', JSON.stringify(d.edits));
      }
    } catch(e) { console.error('[FinanceLocal] Firebase load 실패:', e); }
  }
  async function saveFinanceLocalStateToFirebase() {
    try {
      var dels = JSON.parse(localStorage.getItem('atelier_finance_dels')||'[]');
      var edits = JSON.parse(localStorage.getItem('atelier_finance_edits')||'{}');
      await db.collection('appSettings').doc('financeLocalState').set({
        dels: dels, edits: edits, updatedAt: new Date().toISOString()
      }, { merge: true });
    } catch(e) { console.error('[FinanceLocal] Firebase save 실패:', e); }
  }

  async function loadFinance() {
    document.getElementById('finance-loading').style.display = 'flex';
    document.getElementById('finance-table-wrap').style.display = 'none';
    document.getElementById('finance-empty').style.display = 'none';
    try {
      // 삭제/수정 목록 Firebase에서 먼저 로드 (다기기 동기화)
      await loadFinanceLocalStateFromFirebase();
      var [initialDocs, tripDocs] = await Promise.all([fbRead('finance'), fbRead('trips')]);
      financeTrips = tripDocs;

      // 1회성 마이그레이션: 하드코딩 defaults를 Firestore에 실제 문서로 옮김
      // 이후엔 getFinanceDefaults()가 []를 반환하므로 삭제하면 진짜 삭제됨
      var didMigrate = await migrateFinanceDefaultsToFirebase(initialDocs);
      // journey 항목들의 finance 설명을 새 포맷(도시/체크인-아웃/탑승일 포함)으로 일괄 재동기화
      var didResync = await migrateJourneyFinanceDescriptions();
      var docs = (didMigrate || didResync) ? await fbRead('finance') : initialDocs;

      financeData = docs.map(function(d){ return objToRow('finance', d).concat([d._id]); });
      console.log('[Finance Load] Firestore docs=' + financeData.length + (didMigrate ? ' (마이그레이션 후 재로드)' : ''));
      var defaults = getFinanceDefaults();
      if (defaults.length) console.log('[Finance Load] Defaults added=' + defaults.length + ' (마이그레이션 폴백)');
      financeData = financeData.concat(defaults);
      financeData.sort(function(a,b){ return (a[0]||'').localeCompare(b[0]||''); });
      document.getElementById('finance-loading').style.display = 'none';
      buildFinanceTripFilters();
      // Auto-select closest upcoming trip
      var defaultTrip = getDefaultFinanceTrip(financeTrips);
      filterFinanceByTrip(defaultTrip);
    } catch(err) {
      document.getElementById('finance-loading').innerHTML = '<span class="text-rose-400 text-sm">데이터를 불러올 수 없어요.</span>';
    }
  }

  function buildFinanceTripFilters() {
    renderFinanceDdOptions();
  }

  function renderFinanceDdOptions() {
    var optEl = document.getElementById('finance-dd-options');
    if (!optEl) return;
    var sorted = _tripSortForDropdown(financeTrips);
    var isAll = currentFinanceTrip === 'all';
    var html = '<button onclick="selectFinanceTripDd(\'all\')" class="trip-dd-opt' + (isAll ? ' active' : '') + '"><span>전체</span></button>';
    html += sorted.map(function(t) {
      var isActive = currentFinanceTrip === t.name;
      return '<button onclick="selectFinanceTripDd(\'' + t.name.replace(/'/g,"\\'") + '\')" class="trip-dd-opt' + (isActive ? ' active' : '') + '"><span class="truncate">' + t.name + '</span></button>';
    }).join('');
    optEl.innerHTML = html;
    // Update label
    var label = document.getElementById('finance-dd-label');
    if (label) label.textContent = isAll ? '전체' : currentFinanceTrip;
  }

  function toggleFinanceDropdown() { _toggleDropdown('finance-dd-panel','finance-dd-chevron',_ddState,'finance'); }

  function selectFinanceTripDd(trip) {
    _toggleDropdown('finance-dd-panel','finance-dd-chevron',_ddState,'finance');
    filterFinanceByTrip(trip);
  }

  function filterFinanceByTrip(trip) {
    currentFinanceTrip = trip;
    financeFiltered = trip==='all' ? financeData : financeData.filter(function(r){ return r[2]===trip; });

    renderFinanceDdOptions();
    renderFinanceTable();
    updateFinanceStats();
    document.getElementById('finance-table-wrap').style.display = financeFiltered.length===0?'none':'block';
    document.getElementById('finance-empty').style.display = financeFiltered.length===0?'flex':'none';
  }

  function renderFinanceTable() {
    var tbody = document.getElementById('finance-tbody');
    tbody.innerHTML = '';
    // 잔액: 시간순(오름차순) + 원본 순서 유지로 계산
    var indexed = financeFiltered.map(function(row, i){ return {row:row, origIdx:i}; });
    indexed.sort(function(a,b){
      var dc = (a.row[0]||'').localeCompare(b.row[0]||'');
      return dc !== 0 ? dc : a.origIdx - b.origIdx;
    });
    var balMap = new Map();
    var running = 0;
    indexed.forEach(function(item){
      var c = item.row[3]||'기타';
      var a = parseFloat(item.row[4])||0;
      if (c==='입금') running += a; else running -= a;
      balMap.set(item.row, running);
    });
    console.log('[Balance] 계산완료: 최종잔액=' + running + ', 항목수=' + indexed.length);
    // 입력 행 맨 위
    appendFinanceInputRow(tbody);
    // 역순 표시 (최신→오래된, 같은 날짜 내에서는 원본 역순)
    var reversed = financeFiltered.map(function(row, i){ return {row:row, origIdx:i}; });
    reversed.sort(function(a,b){
      var dc = (b.row[0]||'').localeCompare(a.row[0]||'');
      return dc !== 0 ? dc : b.origIdx - a.origIdx;
    });
    reversed = reversed.map(function(item){ return item.row; });
    reversed.forEach(function(row) {
      var realIdx = financeData.indexOf(row);
      var cat = row[3]||'기타';
      var icon = FIN_CAT_ICONS[cat]||'more_horiz';
      var color = FIN_CAT_COLORS[cat]||'text-slate-500';
      var amt = parseFloat(row[4])||0;
      var bal = balMap.get(row)||0;
      var balColor = bal >= 0 ? 'text-indigo-600' : 'text-rose-600';
      var isDeposit = cat === '입금';
      var tr = document.createElement('tr');
      tr.className = 'hover:bg-indigo-50/30 transition-colors group';
      tr.dataset.finIdx = realIdx;
      var amtHtml = isDeposit
        ? '<span class="font-bold text-indigo-600">+₩' + amt.toLocaleString('ko-KR') + '</span>'
        : '<span class="font-bold text-rose-600">-₩' + amt.toLocaleString('ko-KR') + '</span>';
      tr.innerHTML =
        '<td class="px-6 py-3 text-slate-500 text-sm cursor-pointer" onclick="clickEditFinance('+realIdx+',0,this)">' + (row[0]||'—') + '</td>' +
        '<td class="px-6 py-3 cursor-pointer" onclick="clickEditFinance('+realIdx+',1,this)"><p class="font-semibold text-slate-800 text-sm">' + (row[1]||'—') + '</p></td>' +
        '<td class="px-6 py-3 cursor-pointer" onclick="clickEditFinance('+realIdx+',2,this)"><span class="flex items-center gap-1.5 text-xs font-bold ' + color + '"><span class="material-symbols-outlined text-sm">' + icon + '</span>' + cat + '</span></td>' +
        '<td class="px-6 py-3 text-right cursor-pointer" onclick="clickEditFinance('+realIdx+',3,this)">' + amtHtml + '</td>' +
        '<td class="px-6 py-3 text-right text-xs font-semibold ' + balColor + '">₩' + Math.round(bal).toLocaleString('ko-KR') + '</td>' +
        '<td class="px-6 py-3 text-center"><button onclick="deleteFinanceAny('+realIdx+')" class="p-1 hover:bg-rose-100 rounded-lg text-slate-300 hover:text-rose-500 transition-colors opacity-0 group-hover:opacity-100"><span class="material-symbols-outlined text-sm">delete</span></button></td>';
      tbody.appendChild(tr);
    });
    document.getElementById('finance-status').textContent = financeFiltered.length + '개 항목';
  }

  function clickEditFinance(idx, col, td) {
    var row = financeData[idx]; if (!row) return;
    var tr = td.closest('tr');
    var cat = row[3]||'기타'; var amt = parseFloat(row[4])||0; var isDeposit = cat === '입금';
    var ic = 'border border-slate-200 rounded px-1.5 py-1 text-xs outline-none focus:ring-1 focus:ring-indigo-200 w-full';
    var catOpts = ['입금','이동','숙소','렌트','티켓','환전','보험','통신','식비','교통','여가','쇼핑','기타'].map(function(c){ return '<option value="'+c+'"'+(c===cat?' selected':'')+'>'+c+'</option>'; }).join('');
    tr.className = 'bg-indigo-50/40';
    var amtCls = isDeposit ? 'text-indigo-600' : 'text-rose-600';
    var amtPlaceholder = isDeposit ? '입금' : '출금';
    tr.innerHTML =
      '<td class="px-4 py-2"><input data-fec="0" type="date" value="'+(row[0]||'')+'" class="'+ic+'"/></td>' +
      '<td class="px-4 py-2"><input data-fec="1" type="text" value="'+(row[1]||'')+'" class="'+ic+'"/></td>' +
      '<td class="px-4 py-2"><select data-fec="2" class="'+ic+' bg-white" onchange="(function(s){var amt=s.closest(\'tr\').querySelector(\'[data-fec=\\\'3\\\']\');if(s.value===\'입금\'){amt.classList.add(\'text-indigo-600\');amt.classList.remove(\'text-rose-600\');amt.placeholder=\'입금\';}else{amt.classList.add(\'text-rose-600\');amt.classList.remove(\'text-indigo-600\');amt.placeholder=\'출금\';}})(this)">'+catOpts+'</select></td>' +
      '<td class="px-4 py-2 text-right"><input data-fec="3" type="text" value="'+amt.toLocaleString('ko-KR')+'" placeholder="'+amtPlaceholder+'" inputmode="numeric" oninput="finAmtFmt(this)" class="'+ic+' text-right '+amtCls+'"/></td>' +
      '<td class="px-4 py-2"></td>' +
      '<td class="px-4 py-2 text-center"><div class="flex gap-1 justify-center">' +
        '<button onclick="saveClickEdit('+idx+')" class="p-1 bg-indigo-100 hover:bg-indigo-200 rounded-lg text-indigo-600"><span class="material-symbols-outlined text-sm">check</span></button>' +
        '<button onclick="filterFinanceByTrip(currentFinanceTrip)" class="p-1 bg-slate-100 hover:bg-slate-200 rounded-lg text-slate-500"><span class="material-symbols-outlined text-sm">close</span></button>' +
      '</div></td>';
    initInlineDatePickers(tr);
    var input = tr.querySelector('[data-fec="'+col+'"]');
    if (input) { input.focus(); if (input.select) input.select(); }
    tr.querySelectorAll('input,select').forEach(function(el){
      el.addEventListener('keydown', function(e){
        if (e.key === 'Enter') { e.preventDefault(); saveClickEdit(idx); }
        if (e.key === 'Escape') { e.preventDefault(); filterFinanceByTrip(currentFinanceTrip); }
      });
    });
  }

  async function saveClickEdit(idx) {
    var tr = document.querySelector('tr[data-fin-idx="'+idx+'"]');
    if (!tr) { tr = document.querySelector('tr.bg-indigo-50\\/40'); }
    if (!tr) { filterFinanceByTrip(currentFinanceTrip); return; }
    var date = (tr.querySelector('[data-fec="0"]')||{}).value||'';
    var desc = (tr.querySelector('[data-fec="1"]')||{}).value||'';
    var cat = (tr.querySelector('[data-fec="2"]')||{}).value||'기타';
    var amt = parseFloat(((tr.querySelector('[data-fec="3"]')||{}).value||'').replace(/[^0-9]/g,'')) || 0;
    if (!amt) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 금액을 입력해주세요'); return; }
    var row = financeData[idx]; if (!row) return;
    var id = row[7];
    var trip = row[2] || '';
    console.log('[Finance Edit] idx=' + idx + ', id=' + id + ', date=' + date + ', desc=' + desc + ', cat=' + cat + ', amt=' + amt);

    // __default__ 항목은 Firestore에 없으므로 새로 생성
    if (id === '__default__') {
      try {
        var newRow = [date, desc, trip, cat, String(amt), 'KRW', ''];
        var saved = await fbAdd('finance', rowToObj('finance', newRow));
        // 기존 default 행 제거하고 새 행으로 교체
        financeData[idx] = newRow.concat([saved._id]);
        buildFinanceTripFilters(); filterFinanceByTrip(currentFinanceTrip);
        showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 저장 완료');
      } catch(e) { console.error('[Finance Edit] Create error:', e); showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 저장 실패: ' + e.message); }
      return;
    }

    try {
      await fbUpdate('finance', id, { date:date, description:desc, category:cat, amount:String(amt) });
      row[0]=date; row[1]=desc; row[3]=cat; row[4]=String(amt);
      buildFinanceTripFilters(); filterFinanceByTrip(currentFinanceTrip);
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 수정 완료');
    } catch(e) { console.error('[Finance Edit] Update error:', e); showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 저장 실패: ' + e.message); }
  }

  function appendFinanceInputRow(tbody) {
    var ic = 'border border-slate-200 rounded px-2 py-1.5 text-xs outline-none focus:ring-1 focus:ring-indigo-200';
    var catOpts = ['입금','이동','숙소','렌트','티켓','환전','보험','통신','식비','교통','여가','쇼핑','기타'].map(function(c){ return '<option value="'+c+'">'+c+'</option>'; }).join('');
    var tripVal = currentFinanceTrip!=='all' ? currentFinanceTrip : (financeTrips.length?financeTrips[0].name:'');
    var tr = document.createElement('tr');
    tr.id = 'fin-input-row';
    tr.className = 'bg-indigo-50/30';
    tr.innerHTML =
      '<td class="px-4 py-2"><input id="fir-date" type="date" value="'+new Date().toISOString().split('T')[0]+'" class="'+ic+'" style="width:120px"/></td>' +
      '<td class="px-4 py-2"><input id="fir-desc" type="text" placeholder="내용 입력..." class="'+ic+' w-full"/></td>' +
      '<td class="px-4 py-2"><select id="fir-cat" class="'+ic+' bg-white" style="width:90px" onchange="(function(s){var amt=document.getElementById(\'fir-amount\');if(s.value===\'입금\'){amt.classList.add(\'text-indigo-600\');amt.classList.remove(\'text-rose-600\');amt.placeholder=\'입금\';}else{amt.classList.add(\'text-rose-600\');amt.classList.remove(\'text-indigo-600\');amt.placeholder=\'출금\';}})(this)">' + catOpts + '</select></td>' +
      '<td class="px-4 py-2 text-right"><input id="fir-amount" type="text" placeholder="출금" inputmode="numeric" class="'+ic+' text-right text-rose-600" style="width:120px" oninput="finAmtFmt(this)"/></td>' +
      '<td class="px-4 py-2 text-right text-xs text-slate-300">—</td>' +
      '<td class="px-4 py-2 text-center">' +
        '<input type="hidden" id="fir-trip" value="'+tripVal+'"/>' +
        '<button onclick="submitFinanceInputRow()" class="p-1.5 bg-indigo-100 hover:bg-indigo-200 rounded-lg text-indigo-600 transition-colors"><span class="material-symbols-outlined" style="font-size:16px">add</span></button>' +
      '</td>';
    tbody.appendChild(tr);
    initInlineDatePickers(tr);
    ['fir-date','fir-desc','fir-amount'].forEach(function(id){
      var el = tr.querySelector('#'+id);
      if(el) el.addEventListener('keydown', function(e){
        if(e.key==='Enter') { e.preventDefault(); submitFinanceInputRow(); }
        if(e.key==='Escape') { e.preventDefault(); el.value=''; el.blur(); }
      });
    });
  }

  function finAmtFmt(el) {
    var pos = el.selectionStart, oldLen = el.value.length;
    var raw = el.value.replace(/[^\d]/g, '');
    if (!raw) { el.value = ''; return; }
    el.value = parseInt(raw).toLocaleString('ko-KR');
    var newPos = pos + (el.value.length - oldLen);
    el.setSelectionRange(Math.max(0,newPos), Math.max(0,newPos));
  }

  async function submitFinanceInputRow() {
    var date = document.getElementById('fir-date').value;
    var desc = document.getElementById('fir-desc').value.trim();
    var cat = document.getElementById('fir-cat').value;
    var amt = parseFloat((document.getElementById('fir-amount').value||'').replace(/[^0-9]/g,'')) || 0;
    var trip = document.getElementById('fir-trip').value;
    if (!date) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 날짜를 입력해주세요'); return; }
    if (!amt) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 금액을 입력해주세요'); return; }
    if (!desc) desc = cat === '입금' ? '입금' : cat;
    var row = [date, desc, trip, cat, String(amt), 'KRW', ''];
    console.log('[Finance] Saving:', { date:date, desc:desc, trip:trip, cat:cat, amt:amt });
    try {
      var saved = await fbAdd('finance', rowToObj('finance', row));
      financeData.push(row.concat([saved._id]));
      financeData.sort(function(a,b){ return (a[0]||'').localeCompare(b[0]||''); });
      buildFinanceTripFilters();
      filterFinanceByTrip(currentFinanceTrip);
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 저장 완료');
    } catch(err) { console.error('[Finance] Save error:', err); showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 저장 실패: ' + err.message); }
  }

  function updateFinanceStats() {
    // 출금/입금 합계
    var expenseTotal = financeFiltered.reduce(function(s,r){ return s+(r[3]!=='입금'?(parseFloat(r[4])||0):0); }, 0);
    var depositTotal = financeFiltered.reduce(function(s,r){ return s+(r[3]==='입금'?(parseFloat(r[4])||0):0); }, 0);
    var balance = depositTotal - expenseTotal;
    console.log('[Finance Stats] 입금=' + depositTotal + ', 출금=' + expenseTotal + ', 잔액=' + balance);
    var depEl = document.getElementById('finance-main-deposit');
    if (depEl) depEl.textContent = '₩' + Math.round(depositTotal).toLocaleString('ko-KR');
    document.getElementById('finance-main-spent').textContent = '₩' + Math.round(expenseTotal).toLocaleString('ko-KR');
    var balEl = document.getElementById('finance-main-balance');
    if (balEl) {
      balEl.textContent = (balance < 0 ? '-' : '') + '₩' + Math.round(Math.abs(balance)).toLocaleString('ko-KR');
      balEl.style.color = balance < 0 ? '#fecaca' : '#fff';
    }
    document.getElementById('finance-main-label').textContent = '총 지출';
    document.getElementById('finance-item-count').textContent = financeFiltered.length;
    var tripLabelEl = document.getElementById('finance-trip-label');
    if (tripLabelEl) tripLabelEl.textContent = currentFinanceTrip==='all'?'전체':currentFinanceTrip;

    // 카드 제목 + 이미지 배경
    var todayStr = new Date().toISOString().split('T')[0];
    var displayTrip = null;
    if (currentFinanceTrip !== 'all') {
      displayTrip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
    }
    if (!displayTrip) {
      var upcoming = financeTrips.filter(function(t){ return t.start_date && t.start_date >= todayStr; })
        .sort(function(a,b){ return a.start_date.localeCompare(b.start_date); });
      displayTrip = upcoming.length > 0 ? upcoming[0] : (financeTrips.length > 0 ? financeTrips[financeTrips.length-1] : null);
    }
    document.getElementById('finance-main-name').textContent = displayTrip ? displayTrip.name : '여행을 추가해봐!';
    var badgeEl = document.getElementById('finance-trip-badge');
    if (badgeEl) badgeEl.textContent = currentFinanceTrip !== 'all' ? '선택된 여행' : '다가오는 여행';
    // 배경 이미지 로드
    var bgImg = document.getElementById('finance-trip-bg');
    if (bgImg && displayTrip && typeof google !== 'undefined' && google.maps && google.maps.places) {
      var svc = new google.maps.places.PlacesService(document.createElement('div'));
      var cityQuery = typeof normalizeCityQuery === 'function' ? normalizeCityQuery(displayTrip.name.split(/[&,]/)[0].trim()) : displayTrip.name;
      svc.findPlaceFromQuery({query: cityQuery + ' city landmark', fields:['photos']}, function(res,st){
        if(st==='OK'&&res&&res[0]&&res[0].photos&&res[0].photos[0]){bgImg.src=res[0].photos[0].getUrl({maxWidth:600});bgImg.style.display='block';}
      });
    }

    // Category breakdown
    var cats = {};
    financeFiltered.forEach(function(r){ if(r[3]==='입금') return; var c=r[3]||'기타'; cats[c]=(cats[c]||0)+(parseFloat(r[4])||0); });
    var maxCat = Math.max(...Object.values(cats), 1);
    var bdEl = document.getElementById('finance-category-breakdown');
    if(bdEl) bdEl.innerHTML = Object.entries(cats).sort(function(a,b){return b[1]-a[1];}).map(function(e){
      var bg = FIN_CAT_BG[e[0]]||'bg-slate-50 text-slate-600 border-slate-200';
      var pct = Math.round((e[1]/maxCat)*100);
      return '<div class="flex items-center gap-3 bg-white border border-slate-100 rounded-xl px-4 py-2.5 shadow-sm">' +
        '<span class="material-symbols-outlined text-sm ' + (FIN_CAT_COLORS[e[0]]||'text-slate-500') + '">' + (FIN_CAT_ICONS[e[0]]||'more_horiz') + '</span>' +
        '<span class="text-xs font-bold text-slate-700">' + e[0] + '</span>' +
        '<div class="w-16 h-1.5 bg-slate-100 rounded-full overflow-hidden"><div class="h-full gradient-primary rounded-full" style="width:'+pct+'%"></div></div>' +
        '<span class="text-xs font-black text-slate-600">₩'+Math.round(e[1]).toLocaleString('ko-KR')+'</span>' +
        '</div>';
    }).join('');

    renderTripBudget();
  }

  // ===== 트립 예산 (4 그룹) =====
  const BUDGET_GROUPS = {
    '항공권': { cats: ['항공','이동'], icon: 'flight', color: '#6366f1' },
    '숙소':   { cats: ['숙소'],         icon: 'bed',    color: '#3b82f6' },
    '투어':   { cats: ['여가','티켓','쇼핑','렌트'], icon: 'attractions', color: '#14b8a6' },
    '생활비': { cats: ['식비','교통','통신','보험','환전','기타'], icon: 'restaurant', color: '#f97316' },
  };
  const BUDGET_FIELDS = { '항공권': 'flight', '숙소': 'accom', '투어': 'tour', '생활비': 'living' };

  function _categoryToGroup(cat) {
    for (var g in BUDGET_GROUPS) {
      if (BUDGET_GROUPS[g].cats.indexOf(cat) >= 0) return g;
    }
    return '생활비';
  }

  function renderTripBudget() {
    // 도시별 숙소 분석도 동시에 갱신 (트립 선택/변경 시)
    if (typeof renderTripLodgingBreakdown === 'function') setTimeout(renderTripLodgingBreakdown, 0);
    var section = document.getElementById('finance-budget-section');
    if (!section) return;
    if (currentFinanceTrip === 'all') { section.style.display = 'none'; return; }
    var trip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
    if (!trip) { section.style.display = 'none'; return; }
    section.style.display = '';

    var budget = trip.budget || {};
    var hasBudget = Object.keys(BUDGET_FIELDS).some(function(g){ return parseFloat(budget[BUDGET_FIELDS[g]])||0 > 0; });

    document.getElementById('finance-budget-edit-label').textContent = hasBudget ? '수정' : '예산 설정';

    // Compute spent per group
    var spent = { '항공권':0, '숙소':0, '투어':0, '생활비':0 };
    financeFiltered.forEach(function(r) {
      if (r[3] === '입금') return;
      var g = _categoryToGroup(r[3] || '기타');
      spent[g] += (parseFloat(r[4]) || 0);
    });

    var totalBudget = Object.values(BUDGET_FIELDS).reduce(function(s,f){ return s + (parseFloat(budget[f])||0); }, 0);
    var totalSpent = Object.values(spent).reduce(function(s,v){ return s+v; }, 0);

    var statusEl = document.getElementById('finance-budget-status');
    if (statusEl) {
      if (!hasBudget) statusEl.textContent = '아직 예산이 설정되지 않았어요';
      else statusEl.textContent = trip.name + ' · 총 예산 ₩' + Math.round(totalBudget).toLocaleString('ko-KR');
    }

    var bodyEl = document.getElementById('finance-budget-body');
    if (!hasBudget) {
      bodyEl.innerHTML = '<div class="text-center py-8">' +
        '<span class="material-symbols-outlined text-4xl text-slate-200 mb-3 block">savings</span>' +
        '<p class="text-sm text-slate-500 mb-4">예산을 설정하면 카테고리별 사용 현황을 한눈에 볼 수 있어요</p>' +
        '<button onclick="openBudgetModal()" class="px-5 py-2.5 rounded-xl bg-indigo-600 text-white font-bold text-sm hover:bg-indigo-700 transition-colors">예산 설정하기</button>' +
        '</div>';
      return;
    }

    var totalRemaining = totalBudget - totalSpent;
    var totalPct = totalBudget > 0 ? Math.min(100, (totalSpent / totalBudget) * 100) : 0;
    var totalOverPct = totalBudget > 0 && totalSpent > totalBudget ? Math.min(100, ((totalSpent - totalBudget) / totalBudget) * 100) : 0;

    var html = '<div class="mb-6 pb-6 border-b border-slate-100">' +
      '<div class="flex justify-between items-baseline mb-2">' +
        '<span class="text-xs font-bold uppercase tracking-widest text-slate-500">전체</span>' +
        '<div class="text-right">' +
          '<span class="text-2xl font-extrabold ' + (totalRemaining >= 0 ? 'text-slate-800' : 'text-red-500') + '">₩' + Math.round(Math.abs(totalRemaining)).toLocaleString('ko-KR') + '</span>' +
          '<span class="text-xs text-slate-400 ml-2">' + (totalRemaining >= 0 ? '남음' : '초과') + '</span>' +
        '</div>' +
      '</div>' +
      '<div class="flex justify-between text-xs text-slate-500 mb-2">' +
        '<span>지출 ₩' + Math.round(totalSpent).toLocaleString('ko-KR') + '</span>' +
        '<span>예산 ₩' + Math.round(totalBudget).toLocaleString('ko-KR') + '</span>' +
      '</div>' +
      '<div class="h-3 bg-slate-100 rounded-full overflow-hidden relative">' +
        '<div class="h-full transition-all" style="width:' + totalPct + '%;background:' + (totalSpent > totalBudget ? '#ef4444' : 'linear-gradient(90deg,#6366f1,#8b5cf6)') + '"></div>' +
      '</div>' +
    '</div>';

    html += '<div class="grid grid-cols-2 gap-3 md:gap-4">';
    Object.keys(BUDGET_GROUPS).forEach(function(g) {
      var cfg = BUDGET_GROUPS[g];
      var b = parseFloat(budget[BUDGET_FIELDS[g]]) || 0;
      var s = spent[g] || 0;
      var rem = b - s;
      var pct = b > 0 ? Math.min(100, (s / b) * 100) : 0;
      var over = s > b && b > 0;
      var barColor = over ? '#ef4444' : cfg.color;

      html += '<div class="border border-slate-100 rounded-xl p-4">' +
        '<div class="flex items-center justify-between mb-2">' +
          '<div class="flex items-center gap-2">' +
            '<span class="material-symbols-outlined text-base" style="color:' + cfg.color + '">' + cfg.icon + '</span>' +
            '<span class="text-sm font-bold text-slate-700">' + g + '</span>' +
          '</div>' +
          '<span class="text-xs font-bold ' + (rem >= 0 ? 'text-slate-500' : 'text-red-500') + '">' +
            (rem >= 0 ? '₩' + Math.round(rem).toLocaleString('ko-KR') + ' 남음' : '₩' + Math.round(-rem).toLocaleString('ko-KR') + ' 초과') +
          '</span>' +
        '</div>' +
        '<div class="flex justify-between text-[11px] text-slate-400 mb-1.5">' +
          '<span>₩' + Math.round(s).toLocaleString('ko-KR') + '</span>' +
          '<span>/ ₩' + Math.round(b).toLocaleString('ko-KR') + '</span>' +
        '</div>' +
        '<div class="h-2 bg-slate-100 rounded-full overflow-hidden">' +
          '<div class="h-full transition-all" style="width:' + pct + '%;background:' + barColor + '"></div>' +
        '</div>' +
      '</div>';
    });
    html += '</div>';

    bodyEl.innerHTML = html;
  }

  // ===== 도시별 숙소 예산 분석 =====
  // 트립 예산 모달의 "숙소 1일치" × 도시별 숙박 일수 = 도시별 예산 가이드
  // 사용자가 도시별로 1일치 override 설정 가능 (trip.budget.accomPerDayByCity)
  // 실제 사용은 journey type='숙소' 항목 + finance 거래에서 매칭
  var _flbEditCity = null; // 인라인 편집 중인 도시명

  function _flbSafeCity(city) {
    return (city || '').replace(/[^a-zA-Z0-9가-힣]/g, '_');
  }

  function ldgStartEditCityBudget(city) {
    _flbEditCity = city;
    renderTripLodgingBreakdown();
    setTimeout(function() {
      var input = document.getElementById('flb-edit-input-' + _flbSafeCity(city));
      if (input) { input.focus(); input.select(); }
    }, 50);
  }

  function ldgCancelEditCityBudget() {
    _flbEditCity = null;
    renderTripLodgingBreakdown();
  }

  async function ldgSaveCityBudget(city) {
    var trip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
    if (!trip) return;
    var input = document.getElementById('flb-edit-input-' + _flbSafeCity(city));
    if (!input) return;
    var raw = (input.value || '').replace(/[^0-9]/g, '');
    if (!trip.budget) trip.budget = {};
    if (!trip.budget.accomPerDayByCity) trip.budget.accomPerDayByCity = {};
    if (raw === '' || raw === '0') {
      // 빈 값 → override 제거 (전체 1일치로 폴백)
      delete trip.budget.accomPerDayByCity[city];
    } else {
      trip.budget.accomPerDayByCity[city] = parseInt(raw, 10);
    }
    _flbEditCity = null;
    try {
      await fbUpdate('trips', trip._id, { budget: trip.budget });
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> ' + city + ' 1일치 예산 저장됨');
    } catch(e) {
      console.error('[CityBudget] save:', e);
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 저장 실패');
    }
    renderTripLodgingBreakdown();
  }

  // 도시 일정 강제 새로고침: trip_cities + journey 재조회 후 재렌더
  async function ldgSyncFromItinerary() {
    var section = document.getElementById('finance-lodging-section');
    var statusEl = document.getElementById('finance-lodging-status');
    if (statusEl) statusEl.textContent = '동기화 중…';
    try {
      // 1) trip_cities 강제 재조회 (citiesData 캐시 무효화)
      if (currentFinanceTrip !== 'all') {
        var trip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
        if (trip) {
          var allCities = await fbRead('trip_cities');
          var freshCities = allCities.filter(function(c){ return c.trip_id === trip._id; });
          // 전역 citiesData 가 동일 트립일 때만 동기화
          if (typeof citiesData !== 'undefined' && typeof currentTripId !== 'undefined' && currentTripId === trip._id) {
            citiesData.length = 0;
            freshCities.forEach(function(c){ citiesData.push(c); });
          }
        }
      }
      // 2) journey 재조회
      var fresh = await fbRead('journey');
      if (typeof journeyData !== 'undefined') {
        journeyData.length = 0;
        fresh.forEach(function(j){ journeyData.push(j); });
      }
      await renderTripLodgingBreakdown();
      if (typeof showSyncToast === 'function') showSyncToast('도시 일정 동기화 완료');
    } catch(e) {
      console.error('[ldgSyncFromItinerary]', e);
      if (statusEl) statusEl.textContent = '동기화 실패';
    }
  }
  if (typeof window !== 'undefined') window.ldgSyncFromItinerary = ldgSyncFromItinerary;

  async function renderTripLodgingBreakdown() {
    var section = document.getElementById('finance-lodging-section');
    var bodyEl = document.getElementById('finance-lodging-body');
    var statusEl = document.getElementById('finance-lodging-status');
    if (!section || !bodyEl) return;
    if (currentFinanceTrip === 'all') { section.style.display = 'none'; return; }
    var trip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
    if (!trip) { section.style.display = 'none'; return; }

    // journey 데이터 로드 (없으면 fbRead)
    var jData = [];
    try {
      if (typeof journeyData !== 'undefined' && journeyData && journeyData.length) {
        jData = journeyData;
      } else {
        jData = await fbRead('journey');
      }
    } catch(e) { console.error('[LodgingBreakdown] journey load:', e); }

    // trip_cities 로드: Voyage Path 도시 일정이 우선 소스
    var tripCities = [];
    try {
      if (typeof citiesData !== 'undefined' && citiesData && citiesData.length &&
          typeof currentTripId !== 'undefined' && currentTripId === trip._id) {
        tripCities = citiesData.slice();
      } else {
        var allCities = await fbRead('trip_cities');
        tripCities = allCities.filter(function(c){ return c.trip_id === trip._id; });
      }
      tripCities.sort(function(a,b){
        var ak = (a.start_date || '') + '|' + String(a.order||0).padStart(4,'0');
        var bk = (b.start_date || '') + '|' + String(b.order||0).padStart(4,'0');
        return ak.localeCompare(bk);
      });
    } catch(e) { console.error('[LodgingBreakdown] trip_cities load:', e); }

    // 이 트립의 숙소들
    var lodgings = jData.filter(function(j) {
      return j.trip_id === trip._id && j.type === '숙소';
    });

    if (lodgings.length === 0 && tripCities.length === 0) {
      section.style.display = '';
      bodyEl.innerHTML = '<div class="text-center py-6 text-xs text-slate-400">아직 도시/숙소가 등록되지 않았어요. Travel 페이지에서 추가하세요.</div>';
      if (statusEl) statusEl.textContent = '';
      return;
    }

    section.style.display = '';

    // 1일치 숙소 예산 (저장 구조: accomPerDay=1일치, accom=총액)
    // 구버전 데이터 호환: accomPerDay 없으면 accom / days로 추정
    var perNightBudget = 0;
    if (trip.budget) {
      if (trip.budget.accomPerDay) perNightBudget = parseFloat(trip.budget.accomPerDay) || 0;
      else if (trip.budget.accom && trip.budget.days) perNightBudget = parseFloat(trip.budget.accom) / parseFloat(trip.budget.days);
    }

    // 숙소 도시별 그룹화 (대소문자 / 공백 / 콤마 뒤 국가/주 정규화로 매칭 향상)
    // 예: "Frankfurt am Main, 독일" ↔ "Frankfurt am Main" 매칭 가능
    var normCity = function(s){
      return (s||'').split(',')[0].trim().toLowerCase().replace(/\s+/g,' ');
    };
    var byCity = {}; // { normName: { display, items: [] } }
    lodgings.forEach(function(lo) {
      var raw = (lo.city || '미지정').trim();
      var key = normCity(raw);
      if (!byCity[key]) byCity[key] = { display: raw, items: [] };
      byCity[key].items.push(lo);
    });

    // 도시별 1일치 override
    var perDayByCity = (trip.budget && trip.budget.accomPerDayByCity) || {};

    // 도시 row 빌더 (도시명 + 매칭된 숙소들 + 일정 야수)
    function buildRow(displayCity, items, plannedNights, source) {
      var totalNights = 0;
      var totalSpent = 0;
      var dateRange = '';
      var minDate = null, maxDate = null;
      items.forEach(function(lo) {
        var ci = lo.date ? new Date(lo.date + 'T00:00:00') : null;
        var co = lo.checkout_date ? new Date(lo.checkout_date + 'T00:00:00') : null;
        if (ci && co) {
          var nights = Math.max(Math.round((co - ci) / 86400000), 1);
          totalNights += nights;
        } else if (items.length) {
          totalNights += 1;
        }
        if (ci) {
          if (!minDate || ci < minDate) minDate = ci;
          if (!maxDate || (co || ci) > maxDate) maxDate = co || ci;
        }
        var amt = parseFloat(String(lo.amount||'').replace(/[^0-9.]/g,''));
        if (!isNaN(amt)) totalSpent += amt;
      });
      if (minDate && maxDate) {
        var fmt = function(d) { return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0'); };
        dateRange = fmt(minDate) + ' ~ ' + fmt(maxDate);
      }
      // 예산 계산 기준: 일정 야수 우선, 없으면 실제 숙소 야수
      var budgetNights = (plannedNights != null && plannedNights > 0) ? plannedNights : totalNights;
      var hasCityOverride = perDayByCity[displayCity] !== undefined;
      var perNight = hasCityOverride ? perDayByCity[displayCity] : perNightBudget;
      var cityBudget = perNight * budgetNights;
      var remaining = cityBudget - totalSpent;
      var pct = cityBudget > 0 ? Math.min(100, totalSpent / cityBudget * 100) : 0;
      var isOver = totalSpent > cityBudget && cityBudget > 0;
      var noBudget = cityBudget === 0;
      return {
        city: displayCity,
        items: items,
        nights: totalNights,
        plannedNights: plannedNights,
        budgetNights: budgetNights,
        spent: totalSpent,
        budget: cityBudget,
        perNight: perNight,
        hasCityOverride: hasCityOverride,
        remaining: remaining,
        pct: pct,
        isOver: isOver,
        noBudget: noBudget,
        dateRange: dateRange,
        source: source // 'itinerary' | 'orphan'
      };
    }

    // 숙소가 등록된 도시들만 카드로 생성 (일정 정보는 매칭해서 보조 표시)
    // 일정 도시 빠른 조회용 인덱스
    var itineraryByKey = {};
    tripCities.forEach(function(c) {
      itineraryByKey[normCity(c.name)] = c;
    });

    var cityRows = Object.keys(byCity).map(function(key) {
      var grp = byCity[key];
      var itin = itineraryByKey[key];
      var plannedNights = itin ? (parseInt(itin.nights, 10) || 0) : 0;
      return buildRow(grp.display, grp.items, plannedNights, itin ? 'itinerary' : 'orphan');
    });

    // 일정 순서대로 정렬 (일정에 있는 도시 우선, 그 안에서는 일정 순; 일정 외는 마지막)
    var itinOrder = {};
    tripCities.forEach(function(c, i){ itinOrder[normCity(c.name)] = i; });
    cityRows.sort(function(a, b) {
      var ai = itinOrder[normCity(a.city)];
      var bi = itinOrder[normCity(b.city)];
      if (ai != null && bi != null) return ai - bi;
      if (ai != null) return -1;
      if (bi != null) return 1;
      // 둘 다 일정 외 → 첫 체크인 날짜 순
      var ad = a.items[0] && a.items[0].date ? a.items[0].date : '9999';
      var bd = b.items[0] && b.items[0].date ? b.items[0].date : '9999';
      return ad.localeCompare(bd);
    });

    var totalNights = cityRows.reduce(function(s,r){ return s + r.budgetNights; }, 0);
    var totalSpent = cityRows.reduce(function(s,r){ return s + r.spent; }, 0);
    var totalBudget = cityRows.reduce(function(s,r){ return s + r.budget; }, 0);
    var totalRem = totalBudget - totalSpent;

    if (statusEl) {
      var orphanCount = cityRows.filter(function(r){return r.source === 'orphan';}).length;
      var orphanTxt = orphanCount > 0 ? ' · ⚠️ ' + orphanCount + ' 정리 필요' : '';
      statusEl.textContent = '총 ' + totalNights + '박 · 1일치 ' + (perNightBudget ? '₩' + Math.round(perNightBudget).toLocaleString('ko-KR') : '미설정') + orphanTxt;
    }

    var html = '<div class="space-y-3">';
    cityRows.forEach(function(r) {
      var titleParts = r.items.length ? r.items.map(function(lo){ return lo.title || '(이름없음)'; }).join(', ') : '';
      var isOrphan = r.source === 'orphan';
      var noLodging = r.items.length === 0;
      var barColor = r.isOver ? '#ef4444' : (r.noBudget ? '#94a3b8' : (isOrphan ? '#f59e0b' : '#3b82f6'));
      var remColor = r.isOver ? 'text-red-500' : (r.remaining > 0 ? 'text-emerald-600' : 'text-slate-500');
      var remLabel = r.noBudget ? '예산 미설정' : (r.remaining >= 0 ? '₩' + Math.round(r.remaining).toLocaleString('ko-KR') + ' 남음' : '₩' + Math.round(-r.remaining).toLocaleString('ko-KR') + ' 초과');
      var safeCity = _flbSafeCity(r.city);
      var cityEsc = r.city.replace(/'/g, "\\'");
      var perNightDisplay = r.perNight ? '₩' + Math.round(r.perNight).toLocaleString('ko-KR') : '미설정';
      var overrideBadge = r.hasCityOverride ? '<span class="text-[9px] font-bold text-purple-600 ml-1" title="이 도시 1일치 별도 설정됨">★</span>' : '';

      // 박수 표시: 일정 야수 vs 실제 야수 불일치 시 둘 다 노출
      var nightsBadge;
      if (isOrphan) {
        nightsBadge = '<span class="text-[10px] font-bold px-2 py-0.5 rounded-full bg-amber-50 text-amber-700" title="Voyage Path 일정에 없는 도시">⚠ 일정 외 ' + r.nights + '박</span>';
      } else if (r.plannedNights && r.nights && r.plannedNights !== r.nights) {
        nightsBadge = '<span class="text-[10px] font-bold px-2 py-0.5 rounded-full bg-orange-50 text-orange-700" title="일정 '+r.plannedNights+'박 / 실제 숙소 '+r.nights+'박 — 불일치">📅 ' + r.plannedNights + '박 / 🏨 ' + r.nights + '박</span>';
      } else if (r.plannedNights && !r.nights) {
        nightsBadge = '<span class="text-[10px] font-bold px-2 py-0.5 rounded-full bg-slate-100 text-slate-500" title="일정 '+r.plannedNights+'박 · 숙소 미등록">📅 ' + r.plannedNights + '박 · 숙소 ―</span>';
      } else {
        nightsBadge = '<span class="text-[10px] font-bold px-2 py-0.5 rounded-full bg-blue-50 text-blue-700">' + r.budgetNights + '박</span>';
      }

      var cardBorderClass = isOrphan ? 'border-amber-200 bg-amber-50/30' : (noLodging ? 'border-dashed border-slate-200' : 'border-slate-200');

      html += '<div class="border ' + cardBorderClass + ' rounded-xl p-4 hover:border-blue-300 transition-colors">' +
        '<div class="flex items-start justify-between mb-2 gap-3">' +
          '<div class="flex-1 min-w-0">' +
            '<div class="flex items-center gap-2 mb-1 flex-wrap">' +
              '<span class="text-sm font-bold text-slate-900">' + r.city + '</span>' +
              nightsBadge +
              (r.dateRange ? '<span class="text-[10px] text-slate-400 font-medium">' + r.dateRange + '</span>' : '') +
            '</div>' +
            (titleParts ? '<p class="text-[11px] text-slate-500 truncate" title="' + titleParts + '">' + titleParts + '</p>'
                        : '<p class="text-[11px] text-slate-400 italic">아직 숙소 미등록 — Travel 페이지에서 추가하세요</p>') +
          '</div>' +
          '<div class="text-right shrink-0">' +
            '<div class="text-sm font-bold ' + remColor + '">' + remLabel + '</div>' +
          '</div>' +
        '</div>' +
        '<div class="flex justify-between items-center text-[11px] text-slate-500 mb-1.5">' +
          '<span>지출 ₩' + Math.round(r.spent).toLocaleString('ko-KR') + '</span>';

      // 1일치 편집 UI (인라인) 또는 표시
      if (_flbEditCity === r.city) {
        var curVal = r.perNight || '';
        html += '<span class="flex items-center gap-1">' +
          '<span class="text-[10px] text-slate-400">1일치</span>' +
          '<input type="text" id="flb-edit-input-' + safeCity + '" value="' + curVal + '" placeholder="160000" class="w-24 text-[10px] px-1.5 py-0.5 border border-blue-300 rounded outline-none focus:ring-1 focus:ring-blue-300 text-right" onkeydown="if(event.key===\'Enter\'){event.preventDefault();ldgSaveCityBudget(\'' + cityEsc + '\');}else if(event.key===\'Escape\'){ldgCancelEditCityBudget();}"/>' +
          '<button onclick="ldgSaveCityBudget(\'' + cityEsc + '\')" class="p-0.5 rounded bg-blue-600 text-white hover:bg-blue-700" title="저장 (Enter)"><span class="material-symbols-outlined" style="font-size:12px">check</span></button>' +
          '<button onclick="ldgCancelEditCityBudget()" class="p-0.5 rounded hover:bg-slate-100 text-slate-400" title="취소 (Esc)"><span class="material-symbols-outlined" style="font-size:12px">close</span></button>' +
        '</span>';
      } else {
        html += '<span class="cursor-pointer hover:bg-blue-50/40 px-1 py-0.5 rounded" onclick="ldgStartEditCityBudget(\'' + cityEsc + '\')" title="클릭하여 이 도시 1일치 예산 수정">' +
          '예산 ' + (r.noBudget ? '—' : '₩' + Math.round(r.budget).toLocaleString('ko-KR')) +
          (r.perNight ? ' <span class="text-slate-400">(' + perNightDisplay + '×' + r.budgetNights + overrideBadge + ' <span class="text-[9px] text-slate-300">✏️</span>)</span>' : '') +
        '</span>';
      }

      html += '</div>' +
        '<div class="h-2 bg-slate-100 rounded-full overflow-hidden">' +
          '<div class="h-full transition-all" style="width:' + r.pct + '%;background:' + barColor + '"></div>' +
        '</div>' +
      '</div>';
    });
    html += '</div>';

    // 총합
    var totalBarPct = totalBudget > 0 ? Math.min(100, totalSpent / totalBudget * 100) : 0;
    var totalRemColor = totalRem >= 0 ? 'text-emerald-600' : 'text-red-500';
    html += '<div class="mt-4 pt-4 border-t border-slate-100">' +
      '<div class="flex justify-between items-baseline mb-2">' +
        '<span class="text-xs font-bold uppercase tracking-widest text-slate-500">전체 ' + totalNights + '박</span>' +
        '<div class="text-right">' +
          '<span class="text-lg font-extrabold ' + totalRemColor + '">' + (totalRem >= 0 ? '₩' : '-₩') + Math.round(Math.abs(totalRem)).toLocaleString('ko-KR') + '</span>' +
          '<span class="text-xs text-slate-400 ml-2">' + (totalRem >= 0 ? '남음' : '초과') + '</span>' +
        '</div>' +
      '</div>' +
      '<div class="flex justify-between text-xs text-slate-500 mb-2">' +
        '<span>지출 ₩' + Math.round(totalSpent).toLocaleString('ko-KR') + '</span>' +
        '<span>예산 ₩' + Math.round(totalBudget).toLocaleString('ko-KR') + '</span>' +
      '</div>' +
      '<div class="h-2 bg-slate-100 rounded-full overflow-hidden">' +
        '<div class="h-full transition-all" style="width:' + totalBarPct + '%;background:' + (totalSpent > totalBudget ? '#ef4444' : '#3b82f6') + '"></div>' +
      '</div>' +
    '</div>';

    bodyEl.innerHTML = html;
  }

  // ===== 예산 모달 =====
  function _parseAmt(str) { return parseFloat((str||'').replace(/,/g,'')) || 0; }
  function _fmtAmt(n) { return n ? n.toLocaleString('ko-KR') : ''; }

  function getTripDays(trip) {
    if (!trip || !trip.start_date || !trip.end_date) return 1;
    var start = new Date(trip.start_date + 'T00:00:00');
    var end = new Date(trip.end_date + 'T00:00:00');
    var days = Math.round((end - start) / 86400000) + 1;
    return days > 0 ? days : 1;
  }

  var _budgetEditingDays = 1;

  function openBudgetModal() {
    if (currentFinanceTrip === 'all') return;
    var trip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
    if (!trip) return;
    var b = trip.budget || {};
    _budgetEditingDays = getTripDays(trip);
    document.getElementById('budget-modal-title').textContent = trip.name + ' 예산';
    document.getElementById('budget-days-display').textContent = _budgetEditingDays + '일';
    document.getElementById('budget-flight').value = _fmtAmt(parseFloat(b.flight)||0);
    document.getElementById('budget-accom-per-day').value = _fmtAmt(parseFloat(b.accomPerDay)||0);
    document.getElementById('budget-tour-per-day').value = _fmtAmt(parseFloat(b.tourPerDay)||0);
    document.getElementById('budget-living-per-day').value = _fmtAmt(parseFloat(b.livingPerDay)||0);
    updateBudgetTotal();
    document.getElementById('budget-modal').style.cssText = 'display:flex!important';
  }

  function closeBudgetModal() {
    document.getElementById('budget-modal').style.cssText = 'display:none!important';
  }

  function updateBudgetTotal() {
    var days = _budgetEditingDays;
    var flight = _parseAmt(document.getElementById('budget-flight').value);
    var accomPerDay = _parseAmt(document.getElementById('budget-accom-per-day').value);
    var tourPerDay = _parseAmt(document.getElementById('budget-tour-per-day').value);
    var livingPerDay = _parseAmt(document.getElementById('budget-living-per-day').value);
    var accomTotal = accomPerDay * days;
    var tourTotal = tourPerDay * days;
    var livingTotal = livingPerDay * days;
    document.getElementById('budget-accom-total').textContent = '₩' + accomTotal.toLocaleString('ko-KR');
    document.getElementById('budget-tour-total').textContent = '₩' + tourTotal.toLocaleString('ko-KR');
    document.getElementById('budget-living-total').textContent = '₩' + livingTotal.toLocaleString('ko-KR');
    var total = flight + accomTotal + tourTotal + livingTotal;
    document.getElementById('budget-total-display').textContent = '₩' + total.toLocaleString('ko-KR');
  }

  async function saveBudget() {
    if (currentFinanceTrip === 'all') return;
    var trip = financeTrips.find(function(t){ return t.name === currentFinanceTrip; });
    if (!trip) return;
    var days = _budgetEditingDays;
    var flight = _parseAmt(document.getElementById('budget-flight').value);
    var accomPerDay = _parseAmt(document.getElementById('budget-accom-per-day').value);
    var tourPerDay = _parseAmt(document.getElementById('budget-tour-per-day').value);
    var livingPerDay = _parseAmt(document.getElementById('budget-living-per-day').value);
    var budget = {
      flight: flight,
      accom: accomPerDay * days,
      tour: tourPerDay * days,
      living: livingPerDay * days,
      accomPerDay: accomPerDay,
      tourPerDay: tourPerDay,
      livingPerDay: livingPerDay,
      days: days,
    };
    var btn = document.getElementById('budget-save-btn');
    btn.disabled = true;
    try {
      await fbUpdate('trips', trip._id, { budget: budget });
      trip.budget = budget;
      closeBudgetModal();
      renderTripBudget();
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 예산 저장 완료');
    } catch(err) {
      console.error('[Budget] Save error:', err);
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 저장 실패: ' + err.message);
    } finally {
      btn.disabled = false;
    }
  }

  // ===== 환율 자동 계산 =====
  var _fxCache = {};
  var _fxCurrentRate = null;

  // ===== GBP→KRW 수강료 전용 환율 =====
  var FX_MARKUP_RATE = 1.0175; // 은행 환전 수수료 약 1.75% 반영
  var FX_FALLBACK_RATE = 1850;
  var _gbpKrwMarket = null;   // 시장 환율
  var _gbpKrwPurchase = null; // 구매 환율 (시장 × 수수료)
  var _gbpKrwFetchDate = null;
  var _gbpKrwFallback = false;

  async function fetchGbpKrwRate(forceRefresh) {
    var cacheKey = 'atelier_gbp_krw_rate';
    // 캐시 확인 (12시간)
    if (!forceRefresh) {
      try {
        var cached = JSON.parse(localStorage.getItem(cacheKey));
        if (cached && cached.rate && (Date.now() - cached.fetchedAt < 43200000)) {
          _gbpKrwMarket = cached.rate;
          _gbpKrwPurchase = Math.round(cached.rate * FX_MARKUP_RATE);
          _gbpKrwFetchDate = cached.date || '';
          _gbpKrwFallback = false;
          return _gbpKrwPurchase;
        }
      } catch(e){}
    }
    // API 호출
    try {
      var res = await fetch('https://api.exchangerate-api.com/v4/latest/GBP');
      var data = await res.json();
      if (data.rates && data.rates.KRW) {
        _gbpKrwMarket = data.rates.KRW;
        _gbpKrwPurchase = Math.round(_gbpKrwMarket * FX_MARKUP_RATE);
        _gbpKrwFetchDate = data.date || new Date().toISOString().split('T')[0];
        _gbpKrwFallback = false;
        localStorage.setItem(cacheKey, JSON.stringify({ rate: _gbpKrwMarket, fetchedAt: Date.now(), date: _gbpKrwFetchDate }));
        return _gbpKrwPurchase;
      }
    } catch(e) { console.warn('[FX] GBP→KRW API failed:', e); }
    // 폴백: 오래된 캐시
    try {
      var old = JSON.parse(localStorage.getItem(cacheKey));
      if (old && old.rate) {
        _gbpKrwMarket = old.rate;
        _gbpKrwPurchase = Math.round(old.rate * FX_MARKUP_RATE);
        _gbpKrwFetchDate = old.date || '';
        _gbpKrwFallback = true;
        return _gbpKrwPurchase;
      }
    } catch(e){}
    // 완전 폴백
    _gbpKrwMarket = FX_FALLBACK_RATE;
    _gbpKrwPurchase = Math.round(FX_FALLBACK_RATE * FX_MARKUP_RATE);
    _gbpKrwFetchDate = '';
    _gbpKrwFallback = true;
    console.warn('[FX] Using fallback rate:', FX_FALLBACK_RATE);
    return _gbpKrwPurchase;
  }

  function formatKRW(gbpAmount, purchaseRate) {
    var raw = gbpAmount * purchaseRate;
    var rounded = Math.round(raw / 1000) * 1000;
    return '₩' + rounded.toLocaleString('ko-KR');
  }

  function krwSub(gbpAmount) {
    if (!_gbpKrwPurchase) return '';
    var warn = _gbpKrwFallback ? ' ⚠️' : '';
    return ' <span class="text-xs text-slate-400 font-medium">(' + formatKRW(gbpAmount, _gbpKrwPurchase) + warn + ')</span>';
  }

  async function fetchExchangeRate(currency) {
    if (currency === 'KRW') { _fxCurrentRate = 1; return 1; }
    var cacheKey = currency;
    if (_fxCache[cacheKey] && (Date.now() - _fxCache[cacheKey].ts < 3600000)) {
      _fxCurrentRate = _fxCache[cacheKey].rate;
      return _fxCurrentRate;
    }
    try {
      var res = await fetch('https://api.frankfurter.app/latest?from=' + currency + '&to=KRW');
      var data = await res.json();
      if (data.rates && data.rates.KRW) {
        _fxCurrentRate = data.rates.KRW;
        _fxCache[cacheKey] = { rate: _fxCurrentRate, ts: Date.now() };
        return _fxCurrentRate;
      }
    } catch(e) { console.warn('Exchange rate fetch failed:', e); }
    _fxCurrentRate = null;
    return null;
  }

  async function calcFinanceKRW() {
    var currency = document.getElementById('fin-currency').value;
    var amountStr = document.getElementById('fin-amount').value.replace(/,/g, '');
    var amount = parseFloat(amountStr) || 0;
    var box = document.getElementById('fin-krw-box');
    var amtEl = document.getElementById('fin-krw-amount');
    var rateEl = document.getElementById('fin-krw-rate');

    if (currency === 'KRW') {
      box.style.display = 'none';
      return;
    }
    box.style.display = 'flex';
    if (!amount) { amtEl.textContent = '₩0'; rateEl.textContent = '금액을 입력하세요'; return; }
    amtEl.textContent = '계산 중...';
    var rate = await fetchExchangeRate(currency);
    if (rate) {
      var krwAmount = Math.round(amount * rate);
      amtEl.textContent = '₩' + krwAmount.toLocaleString('ko-KR');
      rateEl.textContent = '1 ' + currency + ' = ₩' + Math.round(rate).toLocaleString('ko-KR');
    } else {
      amtEl.textContent = '환율 조회 실패';
      rateEl.textContent = '네트워크를 확인해주세요';
    }
  }

  function openFinanceModal(idxOrType) {
    var isType = typeof idxOrType === 'string';
    editingFinanceIndex = (!isType && idxOrType!==undefined) ? idxOrType : null;
    var prefillType = isType ? idxOrType : null;
    document.getElementById('finance-modal-title-hdr').textContent =
      prefillType==='입금' ? '입금 추가' : editingFinanceIndex!==null ? '지출 수정' : '지출 추가';
    if(editingFinanceIndex!==null) {
      var row = financeData[editingFinanceIndex];
      document.getElementById('fin-date').value=row[0]||'';
      document.getElementById('fin-desc').value=row[1]||'';
      document.getElementById('fin-trip').value=row[2]||'';
      document.getElementById('fin-cat').value=row[3]||'이동';
      var amtVal = (row[4]||'').toString().replace(/,/g,'');
      document.getElementById('fin-amount').value = amtVal ? Number(amtVal).toLocaleString('ko-KR') : '';
      document.getElementById('fin-currency').value=row[5]||'KRW';
    } else {
      ['fin-date','fin-desc','fin-trip','fin-amount'].forEach(function(id){document.getElementById(id).value=''});
      document.getElementById('fin-date').value=new Date().toISOString().split('T')[0];
      document.getElementById('fin-cat').value=prefillType||'이동';
      document.getElementById('fin-currency').value='KRW';
    }
    // Populate trip dropdown from Firebase trips
    var tripSel = document.getElementById('fin-trip');
    tripSel.innerHTML = '<option value="">— 여행 선택 —</option>' + financeTrips.map(function(t){ return '<option value="'+t.name+'">'+t.name+'</option>'; }).join('');
    if (editingFinanceIndex!==null) tripSel.value = financeData[editingFinanceIndex][2]||'';
    document.getElementById('fin-krw-box').style.display = 'none';
    _fxCurrentRate = null;
    if (editingFinanceIndex!==null && financeData[editingFinanceIndex][5] !== 'KRW') {
      calcFinanceKRW();
    }
    document.getElementById('finance-modal').style.cssText='display:flex!important';
  }

  function closeFinanceModal() {
    document.getElementById('finance-modal').style.cssText='display:none!important';
    editingFinanceIndex=null;
  }

  async function saveFinanceEntry() {
    var btn=document.getElementById('fin-save-btn');
    btn.textContent='저장 중...'; btn.disabled=true;
    var currency = document.getElementById('fin-currency').value;
    var amount = document.getElementById('fin-amount').value.replace(/,/g,'');
    var krwAmount = '';
    if (currency !== 'KRW' && _fxCurrentRate && parseFloat(amount)) {
      krwAmount = String(Math.round(parseFloat(amount) * _fxCurrentRate));
    }
    var row=[
      document.getElementById('fin-date').value,
      document.getElementById('fin-desc').value,
      document.getElementById('fin-trip').value,
      document.getElementById('fin-cat').value,
      amount,
      currency,
      krwAmount,
    ];
    try {
      if(editingFinanceIndex!==null){
        const id = financeData[editingFinanceIndex][7];
        await fbUpdate('finance', id, rowToObj('finance', row));
        financeData[editingFinanceIndex]=row.concat([id]);
      } else {
        const saved = await fbAdd('finance', rowToObj('finance', row));
        financeData.push(row.concat([saved._id]));
      }
      buildFinanceTripFilters();
      filterFinanceByTrip(currentFinanceTrip);
      closeFinanceModal();
    } catch(err){alert('저장에 실패했어요.');}
    finally{btn.textContent='저장';btn.disabled=false;}
  }

