  async function saveInlineEdit(idx) {
    var row = financeData[idx];
    var date = document.getElementById('fie-date').value;
    var desc = document.getElementById('fie-desc').value.trim();
    var cat = document.getElementById('fie-cat').value;
    var deposit = (document.getElementById('fie-deposit').value||'').replace(/,/g,'');
    var expense = (document.getElementById('fie-expense').value||'').replace(/,/g,'');
    var amt = parseFloat(deposit) || parseFloat(expense) || 0;
    if (parseFloat(deposit)) cat = '입금';
    if (!desc) desc = cat;

    if (row[7] === '__default__') {
      // 기본값: localStorage에 수정 저장
      var edits = JSON.parse(localStorage.getItem('atelier_finance_edits')||'{}');
      var key = row[0]+'|'+row[1]+'|'+row[4];
      edits[key] = { date:date, desc:desc, cat:cat, amt:String(amt), trip:row[2] };
      localStorage.setItem('atelier_finance_edits', JSON.stringify(edits));
      saveFinanceLocalStateToFirebase();
      row[0]=date; row[1]=desc; row[3]=cat; row[4]=String(amt);
    } else {
      var newRow = [date, desc, row[2], cat, String(amt), 'KRW', ''];
      try {
        await fbUpdate('finance', row[7], rowToObj('finance', newRow));
        financeData[idx] = newRow.concat([row[7]]);
      } catch(e) { alert('저장 실패'); return; }
    }
    financeData.sort(function(a,b){ return (a[0]||'').localeCompare(b[0]||''); });
    filterFinanceByTrip(currentFinanceTrip);
  }

  // 삭제 (Firebase + 기본값 모두 지원)
  async function deleteFinanceAny(idx) {
    var row = financeData[idx];
    if (!row) return;
    console.log('[Finance Delete] idx=' + idx + ', id=' + row[7] + ', row=', row.slice(0,5));
    if (row[7] === '__default__') {
      var dels = JSON.parse(localStorage.getItem('atelier_finance_dels')||'[]');
      // 현재 row 기준 키 (편집된 금액 포함)
      var delKey = row[0]+'|'+row[1]+'|'+row[4];
      if (dels.indexOf(delKey) < 0) dels.push(delKey);
      // 원본 DEFAULTS에서 date+desc 매칭하여 원본 금액 키도 저장
      var allDefs = FINANCE_DEFAULTS.concat(FINANCE_DEFAULTS2);
      for (var di = 0; di < allDefs.length; di++) {
        var dd = allDefs[di];
        if (dd[0] === row[0] && dd[1] === row[1]) {
          var origKey = dd[0]+'|'+dd[1]+'|'+dd[3];
          var origKey2 = dd[0]+'|'+dd[1]+'|'+String(dd[3]);
          if (dels.indexOf(origKey) < 0) dels.push(origKey);
          if (origKey !== origKey2 && dels.indexOf(origKey2) < 0) dels.push(origKey2);
          break;
        }
      }
      localStorage.setItem('atelier_finance_dels', JSON.stringify(dels));
      saveFinanceLocalStateToFirebase();
      console.log('[Finance Delete] default 삭제, 키:', delKey, '원본키 포함 dels 수:', dels.length);
      financeData.splice(idx,1);
    } else {
      try {
        await fbDelete('finance', row[7]);
        console.log('[Finance Delete] Firestore delete OK, id=' + row[7]);
        financeData.splice(idx,1);
      } catch(e) { console.error('[Finance Delete] Firestore error:', e); showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 삭제 실패: ' + e.message); return; }
    }
    buildFinanceTripFilters();
    filterFinanceByTrip(currentFinanceTrip);
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 삭제 완료');
  }

  async function deleteFinanceRow(i){ await deleteFinanceAny(i); }

  function openFinanceTripModal(){
    // 지출 추가 모달로 바로 연결
    openFinanceModal();
  }


  // ===== SETTINGS: INCOME CATEGORIES =====
  let incomeCategories = [];

  async function loadIncomeCategories() {
    try {
      const docs = await fbRead('income_categories');
      if (docs.length === 0) {
        // 기본 카테고리 세팅
        const defaults = ['에디토리얼 시리얼', '크리에이티브 시리얼', '스페셜 프로젝트', '기타'];
        for (const name of defaults) {
          await fbAdd('income_categories', {name: name});
        }
        incomeCategories = defaults.map(function(n){ return {name:n}; });
      } else {
        incomeCategories = docs;
      }
      refreshIncomeCategorySelect();
    } catch(err) {
      console.error('Category load error:', err);
      incomeCategories = [{name:'에디토리얼 시리얼'},{name:'크리에이티브 시리얼'},{name:'스페셜 프로젝트'},{name:'기타'}];
      refreshIncomeCategorySelect();
    }
  }

  function refreshIncomeCategorySelect() {
    var sel = document.getElementById('i-category');
    if (!sel) return;
    sel.innerHTML = incomeCategories.map(function(c){
      return '<option>' + c.name + '</option>';
    }).join('');
  }

  function renderSettingsCategoryList() {
    var list = document.getElementById('settings-category-list');
    if (!list) return;
    if (incomeCategories.length === 0) {
      list.innerHTML = '<div class="text-xs text-slate-400 text-center py-4">카테고리가 없어요</div>';
      return;
    }
    list.innerHTML = incomeCategories.map(function(cat, i) {
      return '<div class="flex items-center justify-between bg-slate-50 rounded-xl px-4 py-2.5 border border-slate-100 group">' +
        '<span class="text-sm font-semibold text-slate-700">' + cat.name + '</span>' +
        '<div class="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">' +
        '<button onclick="editIncomeCategory(' + i + ')" class="p-1 hover:bg-indigo-100 rounded-lg text-slate-400 hover:text-indigo-600 transition-colors"><span class="material-symbols-outlined text-sm">edit</span></button>' +
        '<button onclick="deleteIncomeCategory(' + i + ')" class="p-1 hover:bg-rose-100 rounded-lg text-slate-400 hover:text-rose-500 transition-colors"><span class="material-symbols-outlined text-sm">delete</span></button>' +
        '</div></div>';
    }).join('');
  }

  async function openSettingsPanel() {
    document.getElementById('settings-panel').style.cssText = 'display:flex!important';
    // API 상태 표시
    var apiStatus = document.getElementById('settings-api-status');
    if (apiStatus) {
      var k = localStorage.getItem('atelier_anthropic_api_key');
      var m = localStorage.getItem('atelier_anthropic_model') || 'claude-opus-4-7';
      apiStatus.textContent = k ? '설정됨 · ' + m : '미설정';
      apiStatus.className = 'text-[10px] mt-0.5 ' + (k ? 'text-emerald-600 font-bold' : 'text-slate-400');
    }
    await loadIncomeCategories();
    renderSettingsCategoryList();
  }

  // ===== 전체 백업/복원 =====
  async function exportAllData() {
    var collections = ['income','income_categories','income_goals','finance','finance_hub','planner','matrix','trips','trip_cities','journey','packing','outfits'];
    var backup = {exportedAt: new Date().toISOString(), collections: {}};
    for (var i = 0; i < collections.length; i++) {
      try {
        var docs = await fbRead(collections[i]);
        backup.collections[collections[i]] = docs;
      } catch(e) { backup.collections[collections[i]] = []; }
    }
    // localStorage 시리즈 데이터도 포함
    backup.localStorage = {};
    ['atelier_series_2026','atelier_series_2025','atelier_lodging','atelier_souvenir'].forEach(function(k) {
      var v = localStorage.getItem(k);
      if (v) backup.localStorage[k] = v;
    });
    var blob = new Blob([JSON.stringify(backup, null, 2)], {type:'application/json'});
    var a = document.createElement('a');
    a.href = URL.createObjectURL(blob);
    a.download = 'atelier_backup_' + new Date().toISOString().replace(/[:.]/g,'-').substring(0,19) + '.json';
    a.click();
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 백업 파일 다운로드 완료');
  }

  async function importAllData(input) {
    var file = input.files[0];
    if (!file) return;
    // 먼저 현재 데이터 자동 백업
    await exportAllData();
    var reader = new FileReader();
    reader.onload = async function(e) {
      try {
        var backup = JSON.parse(e.target.result);
        if (!backup.collections) { alert('올바른 백업 파일이 아닙니다.'); return; }
        var restored = 0;
        for (var col in backup.collections) {
          var docs = backup.collections[col];
          for (var d = 0; d < docs.length; d++) {
            var doc = docs[d];
            var id = doc._id;
            delete doc._id; delete doc._createdAt;
            if (id) {
              await db.collection(col).doc(id).set(doc, {merge:true});
            } else {
              await db.collection(col).add(doc);
            }
            restored++;
          }
        }
        // localStorage 복원
        if (backup.localStorage) {
          for (var k in backup.localStorage) {
            localStorage.setItem(k, backup.localStorage[k]);
          }
        }
        alert('복원 완료! ' + restored + '개 문서 복원됨. 페이지를 새로고침합니다.');
        location.reload();
      } catch(err) { alert('복원 실패: ' + err.message); }
    };
    reader.readAsText(file);
  }

