  async function saveEnglishEntry() {
    const btn = document.getElementById('english-save-btn');
    btn.textContent = '저장 중...'; btn.disabled = true;
    const row = [
      document.getElementById('e-name').value,
      document.getElementById('e-date').value,
      document.getElementById('e-status').value,
      document.getElementById('e-track').value,
      document.getElementById('e-fee').value,
      document.getElementById('e-notes').value,
    ];
    try {
      if (editingEnglishIndex !== null) {
        const id = englishData[editingEnglishIndex][6];
        await fbUpdate('english', id, rowToObj('english', row));
        englishData[editingEnglishIndex] = row.concat([id]);
      } else {
        const saved = await fbAdd('english', rowToObj('english', row));
        englishData.push(row.concat([saved._id]));
      }
      document.getElementById('english-table-wrap').style.display = 'block';
      document.getElementById('english-empty').style.display = 'none';
      renderEnglishTable();
      updateEnglishStats();
      closeEnglishModal();
    } catch(err) { alert('저장에 실패했어요.'); }
    finally { btn.textContent = '저장'; btn.disabled = false; }
  }

  function editEnglishRow(i) { openEnglishModal(i); }

  async function deleteEnglishRow(i) {
    try {
      const id = englishData[i][6];
      await fbDelete('english', id);
      englishData.splice(i, 1);
      renderEnglishTable();
      updateEnglishStats();
      if (englishData.length === 0) {
        document.getElementById('english-table-wrap').style.display = 'none';
        document.getElementById('english-empty').style.display = 'flex';
      }
    } catch(err) { alert('삭제에 실패했어요.'); }
  }



  // ===== FLATPICKR DATE PICKER INIT =====
  var fpInstances = {};

  function initFlatpickr(inputId, options) {
    if (fpInstances[inputId]) { try { fpInstances[inputId].destroy(); } catch(e){} delete fpInstances[inputId]; }
    var el = document.getElementById(inputId);
    if (!el || typeof flatpickr === 'undefined') return null;
    // 모달/스크롤 무관 — viewport 기준 fixed 배치
    function _defaultOnOpen(selectedDates, dateStr, instance) {
      if (typeof _positionFlatpickrFixed === 'function') {
        _positionFlatpickrFixed(instance);
        setTimeout(function(){ _positionFlatpickrFixed(instance); }, 10);
      }
    }
    var customOpen = options && options.onOpen;
    var config = Object.assign({
      locale: 'ko',
      dateFormat: 'Y-m-d',
      disableMobile: true,
      allowInput: true,
      appendTo: document.body
    }, options||{});
    config.onOpen = function() {
      _defaultOnOpen.apply(this, arguments);
      if (customOpen) { try { customOpen.apply(this, arguments); } catch(e){} }
    };
    fpInstances[inputId] = flatpickr(el, config);
    return fpInstances[inputId];
  }

