function openApiSettingsModal() {
  var modal = document.getElementById('api-settings-modal');
  if (!modal) return;
  var existing = localStorage.getItem('atelier_anthropic_api_key') || '';
  var input = document.getElementById('api-key-input');
  if (input) input.value = existing;
  var hint = document.getElementById('api-key-hint');
  if (hint) {
    if (existing) {
      hint.textContent = '✓ 키 저장됨 — 수정하려면 아래에서 변경 후 저장';
      hint.className = 'text-[10px] text-emerald-600 px-1 font-bold';
    } else {
      hint.textContent = '아직 키가 설정되지 않았어요';
      hint.className = 'text-[10px] text-slate-400 px-1';
    }
  }
  var modelSel = document.getElementById('api-model-select');
  if (modelSel) modelSel.value = localStorage.getItem('atelier_anthropic_model') || 'claude-opus-4-7';
  modal.style.cssText = 'display:flex!important';
}

function closeApiSettingsModal() {
  document.getElementById('api-settings-modal').style.cssText = 'display:none!important';
}

function saveApiSettings() {
  var key = document.getElementById('api-key-input').value.trim();
  var model = document.getElementById('api-model-select').value;
  if (!key) {
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> API 키를 입력해주세요');
    document.getElementById('api-key-input').focus();
    return;
  }
  if (!key.startsWith('sk-ant-')) {
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 키 형식이 올바르지 않아요 (sk-ant-... 으로 시작해야 함)');
    return;
  }
  localStorage.setItem('atelier_anthropic_api_key', key);
  localStorage.setItem('atelier_anthropic_model', model);
  showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> API 키 저장 완료!');
  closeApiSettingsModal();
  updateAutoGenButton();
  if (typeof _updateTravelApiKeyBtn === 'function') _updateTravelApiKeyBtn();
}

