  // ===== VAULT =====
  var vaultData = [];
  var vaultFilter = 'all';
  var vaultEditId = null;
  var _vaultHighlightIdx = -1;

  var VAULT_CAT_STYLE = {
    work: 'background:rgba(107,56,212,0.1);color:#6b38d4',
    life: 'background:rgba(201,179,253,0.3);color:#544183',
    study: 'background:rgba(107,56,212,0.1);color:#6b38d4',
    emotions: 'background:rgba(201,179,253,0.3);color:#544183',
    insights: 'background:rgba(255,220,187,0.4);color:#673d00'
  };

  async function loadVault() {
    vaultData = await fbRead('vaultExpressions');
    vaultData.sort(function(a,b){ return (b.createdAt||'').localeCompare(a.createdAt||''); });
    updateVaultStats();
    renderVaultHighlight();
    renderVaultGrid();
  }

  function updateVaultStats() {
    document.getElementById('vault-stat-total').textContent = vaultData.length;
    var now = new Date();
    var monthKey = now.getFullYear() + '-' + String(now.getMonth()+1).padStart(2,'0');
    var monthCount = vaultData.filter(function(d){ return (d.createdAt||'').startsWith(monthKey); }).length;
    document.getElementById('vault-stat-month').textContent = monthCount;
  }

  function formatSentences(text, maxSentences) {
    if (!text) return '';
    var abbrs = ['Mr.','Mrs.','Dr.','Ms.','Jr.','Sr.','vs.','etc.','e.g.','i.e.','U.S.','U.K.'];
    var t = text;
    abbrs.forEach(function(a,i){ t = t.split(a).join('__A'+i+'__'); });
    var parts = t.split(/(?<=[.!?])\s+/);
    parts = parts.map(function(s){ abbrs.forEach(function(a,i){ s = s.split('__A'+i+'__').join(a); }); return s; });
    var truncated = false;
    if (maxSentences && parts.length > maxSentences) { parts = parts.slice(0, maxSentences); truncated = true; }
    if (parts.length <= 1) return text + (truncated ? '...' : '');
    return parts.map(function(s){ return '<span class="block mb-1.5">' + s + '</span>'; }).join('') + (truncated ? '<span class="text-xs opacity-60">...</span>' : '');
  }

  function renderConvoHtml(convo, theme) {
    if (!convo || !convo.length) return '';
    var isDark = theme === 'dark';
    return '<div class="' + (isDark ? 'bg-white/10 rounded-2xl p-4 mt-5' : 'bg-[#f3f4f5] rounded-2xl p-4 mt-4') + ' text-left space-y-3">' +
      '<p class="text-[10px] font-bold uppercase tracking-wider ' + (isDark ? 'text-white/50' : 'text-[#494454]/60') + ' mb-2">💬 Context</p>' +
      convo.map(function(t) {
        var isMe = (t.speaker||'').toLowerCase() === 'me';
        var spkColor = isDark ? (isMe ? 'text-white' : 'text-white/70') : (isMe ? 'text-[#6b38d4]' : 'text-[#494454]');
        var textColor = isDark ? 'text-white/90' : 'text-[#191c1d]';
        var krColor = isDark ? 'text-white/50' : 'text-[#494454]/60';
        return '<div>' +
          '<p class="text-[10px] font-bold uppercase tracking-wider ' + spkColor + ' mb-0.5">' + (t.speaker||'') + '</p>' +
          '<p class="text-sm ' + textColor + ' leading-relaxed">"' + (t.text||'') + '"</p>' +
          (t.korean ? '<p class="text-xs ' + krColor + ' mt-0.5">' + t.korean + '</p>' : '') +
        '</div>';
      }).join('') +
    '</div>';
  }

  function splitSentences(text) {
    if (!text) return [''];
    var abbrs = ['Mr.','Mrs.','Dr.','Ms.','Jr.','Sr.','vs.','etc.','e.g.','i.e.','U.S.','U.K.'];
    var t = text; abbrs.forEach(function(a,i){ t = t.split(a).join('__A'+i+'__'); });
    var parts = t.split(/(?<=[.!?])\s+/);
    return parts.map(function(s){ abbrs.forEach(function(a,i){ s = s.split('__A'+i+'__').join(a); }); return s; }).filter(function(s){ return s.trim(); });
  }

  function truncateSentences(text, max) {
    var s = splitSentences(text);
    if (s.length <= max) return { text: text, truncated: false };
    return { text: s.slice(0, max).join(' '), truncated: true };
  }

  function renderVaultHighlight() {
    var pairsEl = document.getElementById('vault-hl-pairs');
    var ctxEl = document.getElementById('vault-hl-ctx');
    var ctxText = document.getElementById('vault-hl-ctx-text');
    var emptyEl = document.getElementById('vault-hl-empty');
    if (vaultData.length === 0) {
      pairsEl.innerHTML = '';
      ctxEl.style.display = 'none'; emptyEl.style.display = '';
      return;
    }
    emptyEl.style.display = 'none'; ctxEl.style.display = '';
    var idx;
    do { idx = Math.floor(Math.random() * vaultData.length); } while (idx === _vaultHighlightIdx && vaultData.length > 1);
    _vaultHighlightIdx = idx;
    var item = vaultData[idx];

    // Parallel sentence pairs (max 3)
    var enS = splitSentences(item.english||'').slice(0, 3);
    var krS = splitSentences(item.korean||'').slice(0, 3);
    var max = Math.max(enS.length, krS.length);
    var html = '';
    for (var i = 0; i < max; i++) {
      html += '<div class="grid grid-cols-1 md:grid-cols-2 gap-x-6 py-1.5' + (i > 0 ? ' border-t border-white/10' : '') + '">' +
        '<p class="text-sm text-white font-medium italic leading-relaxed">' + (enS[i]||'') + '</p>' +
        '<p class="text-xs text-white/70 leading-relaxed mt-1 md:mt-0">' + (krS[i]||'') + '</p>' +
      '</div>';
    }
    pairsEl.innerHTML = html;
    document.getElementById('vault-hl-convo').innerHTML = renderConvoHtml(item.conversation, 'dark');
    ctxText.textContent = item.context || '';
    if (!item.context) ctxEl.style.display = 'none';
  }

  function shuffleVaultHighlight() { renderVaultHighlight(); }

  function setVaultFilter(cat) {
    vaultFilter = cat;
    document.querySelectorAll('.vault-filter-chip').forEach(function(btn){
      btn.classList.toggle('active', btn.dataset.cat === cat);
    });
    renderVaultGrid();
  }

  function renderVaultGrid() {
    var grid = document.getElementById('vault-grid');
    var query = (document.getElementById('vault-search').value || '').toLowerCase().trim();
    var filtered = vaultData.filter(function(d) {
      if (vaultFilter !== 'all' && d.category !== vaultFilter) return false;
      if (query) {
        var text = ((d.english||'') + ' ' + (d.korean||'') + ' ' + (d.context||'')).toLowerCase();
        if (text.indexOf(query) < 0) return false;
      }
      return true;
    });
    if (filtered.length === 0) {
      grid.innerHTML = '<div class="text-sm text-[#494454] text-center py-12 col-span-full">' +
        (vaultData.length === 0 ? '아직 수집된 표현이 없어요. 첫 표현을 추가해보세요!' : '검색 결과가 없습니다.') + '</div>';
      return;
    }
    grid.innerHTML = filtered.map(function(d) {
      var catStyle = VAULT_CAT_STYLE[d.category] || VAULT_CAT_STYLE.work;
      var dateLabel = d.createdAt ? new Date(d.createdAt).toLocaleDateString('en-US', {month:'short',day:'numeric',year:'numeric'}).toUpperCase() : '';
      return '<article class="vault-card" onclick="openVaultDetail(\'' + d._id + '\')">' +
        '<div class="flex justify-between items-start mb-6">' +
          '<span class="px-3 py-1 rounded-lg text-[10px] font-bold uppercase tracking-widest" style="' + catStyle + '">' + (d.category||'work') + '</span>' +
          '<span class="text-[10px] font-medium text-[#494454]/60">' + dateLabel + '</span>' +
        '</div>' +
        (function(){ var te = truncateSentences(d.english||'', 2); return '<h3 class="font-headline text-lg font-bold text-[#191c1d] mb-3 leading-snug">"' + te.text + (te.truncated ? '...' : '') + '"</h3>'; })() +
        (function(){ var tk = truncateSentences(d.korean||'', 2); return '<p class="text-[#494454] font-medium mb-4">' + tk.text + (tk.truncated ? '...' : '') + '</p>'; })() +
        renderConvoHtml(d.conversation, 'light') +
        (d.context ? '<div class="bg-[#f3f4f5] rounded-2xl p-4 text-sm text-[#494454]/80 leading-relaxed mt-3">' + d.context + '</div>' : '') +
      '</article>';
    }).join('');
  }

  function openVaultModal() {
    vaultEditId = null;
    document.getElementById('vault-modal-title').textContent = 'New Expression';
    document.getElementById('vault-english').value = '';
    document.getElementById('vault-korean').value = '';
    document.getElementById('vault-category').value = 'work';
    document.getElementById('vault-context').value = '';
    document.getElementById('vault-delete-btn').style.display = 'none';
    document.getElementById('vault-modal').style.cssText = 'display:flex!important';
  }

  function openVaultDetail(id) {
    var item = vaultData.find(function(d){ return d._id === id; });
    if (!item) return;
    vaultEditId = id;
    document.getElementById('vault-modal-title').textContent = 'Edit Expression';
    document.getElementById('vault-english').value = item.english || '';
    document.getElementById('vault-korean').value = item.korean || '';
    document.getElementById('vault-category').value = item.category || 'work';
    document.getElementById('vault-context').value = item.context || '';
    document.getElementById('vault-delete-btn').style.display = '';
    document.getElementById('vault-modal').style.cssText = 'display:flex!important';
  }

  function closeVaultModal() {
    document.getElementById('vault-modal').style.cssText = 'display:none!important';
    vaultEditId = null;
  }

  async function saveVaultEntry() {
    var en = document.getElementById('vault-english').value.trim();
    var kr = document.getElementById('vault-korean').value.trim();
    if (!en || !kr) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 영어 표현과 한국어 뜻은 필수입니다'); return; }
    var data = {
      english: en,
      korean: kr,
      category: document.getElementById('vault-category').value,
      context: document.getElementById('vault-context').value.trim(),
      updatedAt: new Date().toISOString()
    };
    try {
      if (vaultEditId) {
        await fbUpdate('vaultExpressions', vaultEditId, data);
      } else {
        data.createdAt = new Date().toISOString();
        await fbAdd('vaultExpressions', data);
      }
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 표현이 저장되었습니다');
      closeVaultModal();
      await loadVault();
    } catch(err) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 저장 실패: ' + err.message); }
  }

  async function deleteVaultEntry() {
    if (!vaultEditId) return;
    try {
      await db.collection('vaultExpressions').doc(vaultEditId).delete();
      showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> 삭제 완료');
      closeVaultModal();
      await loadVault();
    } catch(err) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">error</span> 삭제 실패'); }
  }

