  function estimateTokens(text) { return Math.ceil((text||'').length * 0.5); }
  function estimateCostKRW(inputTokens, model) {
    var prices = { 'claude-haiku-4-5':{i:1,o:5}, 'claude-sonnet-4-6':{i:3,o:15}, 'claude-opus-4-7':{i:15,o:75} };
    var p = prices[model] || prices['claude-sonnet-4-6'];
    var outputTokens = inputTokens * 0.3;
    return Math.round((inputTokens * p.i + outputTokens * p.o) / 1000000 * 1400);
  }

  function updateVaultAiCost() {
    var text = document.getElementById('vault-ai-input').value;
    var model = (document.querySelector('input[name="vault-model"]:checked') || {}).value || 'claude-sonnet-4-6';
    var tokens = estimateTokens(text);
    var cost = estimateCostKRW(tokens, model);
    document.getElementById('vault-ai-cost').textContent = '예상 비용: 약 ' + cost + '원 (≈' + tokens + ' 토큰)';
  }

  var VAULT_AI_SYSTEM = `당신은 한국인 영어 학습자를 위한 '충실한 번역가'입니다.

★ 핵심 원칙: 원본 보존 ★

사용자는 Gemini, ChatGPT 같은 AI와 한국어로 나눈 대화를 붙여넣습니다.
당신의 역할은 이 대화 중 학습 가치가 있는 부분을 찾아서
원본에 최대한 충실하게 영어로 옮기는 것입니다.

절대 하지 말 것 (엄격):
1. 원본에 없는 내용 창작 금지
   ❌ 없던 친구 질문 만들기: Friend: "Why does it have to be him?"
   ❌ 가상의 상황 추가
   ❌ 원본의 맥락을 벗어난 설명 덧붙이기

2. 과도한 축약 금지
   ❌ 5문장 설명을 1문장으로 압축
   ❌ 원본의 디테일을 삭제

3. 형식 강요 금지
   ❌ 독백을 억지로 Q&A로 변환
   ❌ 평서문을 질문으로 바꾸기

반드시 할 것:
1. 원본 화자가 실제로 한 말만 영어로 번역
2. 원본의 길이, 뉘앙스, 흐름 최대한 보존
3. 연결된 긴 발화는 연결된 채로 유지
4. 감정의 결, 망설임, 흐름까지 살리기

각 추출 항목:
- english: 원본 발화의 영어 번역 (완성된 문장, 원본 길이 존중. 3~5문장도 OK)
- korean: 원본 한국어 (원본 그대로 또는 약간만 정리)
- category: 'work' | 'life' | 'study' | 'emotions' | 'insights'
- context: 언제/어떻게 쓰면 좋을지 (한국어 1줄)
- conversation: 원본 대화의 흐름을 보존한 배열

conversation 배열 규칙:
- 원본 대화에 실제로 있는 턴만 포함
- 독백이면 1개 턴만 (speaker: 'Me')
- 대화가 오가는 거면 여러 턴 (실제 원본 순서대로)
- 각 턴: { "speaker": "Me"/"AI"/"Coach" 등, "text": "영어", "korean": "한국어" }
- 원본에 없는 가상의 대화 턴 절대 금지

speaker 설정:
- Nuri가 쓴 부분: 'Me'
- AI(Gemini/Claude)가 답한 부분: 'AI' 또는 맥락에 맞는 역할명
- 그 외 등장인물: 원본에서 명시된 대로

카테고리 가이드:
- work: 업무, 비즈니스, 커리어
- life: 일상, 캐주얼 대화, 관계
- study: 학습, 책/영화에서 얻은 것
- emotions: 감정, 심리 상태
- insights: 깨달음, 통찰, 자기성찰

5~10개. 양보다 질.
응답은 순수 JSON 배열만. 마크다운(\\\`\\\`\\\`) 없이.

예시:

[원본] '내가 쓴 카톡만 봐도 알겠지만, 나는 정말 내 마음이 커서, 준혁이랑 함께 하고 싶어서 가자고 한거지...(생략)'

[올바른 추출]
[{"english":"Looking at my own messages, I can tell that my feelings are really strong. I suggested going because I wanted to go with Junhyuk, not because I particularly wanted to visit New Zealand or the art museum. Well, that's partly true too — I wanted to visit those places, and going with him would just be a bonus. But the key point is this: I'd rather go alone than with just anyone to places like New Zealand or the museum. But if it's with Junhyuk, I'd choose him over going alone.","korean":"내가 쓴 카톡만 봐도 알겠지만, 나는 정말 내 마음이 커서, 준혁이랑 함께 하고 싶어서 가자고 한거지...(원본 전체)","category":"emotions","context":"특정한 사람이 자신에게 얼마나 특별한지를 설명할 때","conversation":[{"speaker":"Me","text":"Looking at my own messages, I can tell that my feelings are really strong. I suggested going because I wanted to go with Junhyuk, not because I particularly wanted to visit New Zealand or the art museum. Well, that's partly true too — I wanted to visit those places, and going with him would just be a bonus. But the key point is this: I'd rather go alone than with just anyone to places like New Zealand or the museum. But if it's with Junhyuk, I'd choose him over going alone.","korean":"내가 쓴 카톡만 봐도 알겠지만...(원본 전체)"}]}]

중요: 독백은 conversation에 1개 턴만. 창작된 friend 질문 넣지 않기.

표현 길이 제한:
- english 필드는 최대 3문장 이내
- 원본이 더 길면 핵심만 담아서 3문장으로 마무리
- 원본이 너무 길어 3문장으로 담을 수 없으면, 의미 단위로 여러 개 표현으로 나누어 추출
- conversation 배열 내 개별 턴도 최대 3문장 이내

출력 길이 제한: 전체 응답이 너무 길어지지 않도록 주의.
원본이 매우 긴 경우 가장 핵심적인 5~8개만 추출.`;

  function safeParseVaultJSON(text) {
    try { return { success: true, data: JSON.parse(text) }; } catch(e) {}
    // 잘린 JSON 복구: 마지막 완전한 객체까지 찾기
    if (!text.startsWith('[')) return { success: false };
    var depth = 0, inStr = false, esc = false, lastEnd = -1;
    for (var i = 0; i < text.length; i++) {
      var c = text[i];
      if (esc) { esc = false; continue; }
      if (c === '\\') { esc = true; continue; }
      if (c === '"' && !esc) { inStr = !inStr; continue; }
      if (inStr) continue;
      if (c === '[' || c === '{') depth++;
      if (c === ']' || c === '}') {
        depth--;
        if (depth === 1 && c === '}') lastEnd = i;
      }
    }
    if (lastEnd > 0) {
      var recovered = text.substring(0, lastEnd + 1) + ']';
      try { return { success: true, data: JSON.parse(recovered), partial: true }; } catch(e2) {}
    }
    return { success: false };
  }

  async function runVaultAiExtract() {
    var text = document.getElementById('vault-ai-input').value.trim();
    if (!text) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 대화 내용을 붙여넣으세요'); return; }
    var apiKey = localStorage.getItem('atelier_anthropic_api_key');
    if (!apiKey) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 설정에서 Anthropic API 키를 먼저 등록해주세요'); return; }
    var model = (document.querySelector('input[name="vault-model"]:checked') || {}).value || 'claude-sonnet-4-6';

    document.getElementById('vault-ai-step1').style.display = 'none';
    document.getElementById('vault-ai-loading').className = 'text-center py-8';
    document.getElementById('vault-ai-error').className = 'hidden p-4 rounded-xl bg-rose-50';

    // 모델별 max_tokens
    var maxTokensMap = { 'claude-haiku-4-5': 8192, 'claude-sonnet-4-6': 8192, 'claude-opus-4-7': 16000 };
    var maxTokens = maxTokensMap[model] || 8192;

    try {
      var res = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: { 'x-api-key': apiKey, 'anthropic-version': '2023-06-01', 'anthropic-dangerous-direct-browser-access': 'true', 'content-type': 'application/json' },
        body: JSON.stringify({ model: model, max_tokens: maxTokens, system: VAULT_AI_SYSTEM, messages: [{ role: 'user', content: text }] })
      });
      if (!res.ok) {
        var errBody = {}; try { errBody = await res.json(); } catch(e){}
        throw new Error((errBody.error && errBody.error.message) || 'HTTP ' + res.status);
      }
      var data = await res.json();
      var responseText = (data.content && data.content[0] && data.content[0].text) || '';
      var cleaned = responseText.trim().replace(/^```(?:json|js)?\s*/gm,'').replace(/```\s*$/gm,'').trim();

      // JSON 파싱 (잘린 응답 복구 포함)
      var parseResult = safeParseVaultJSON(cleaned);
      if (!parseResult.success) throw new Error('parse_fail');
      _vaultAiResults = parseResult.data;
      if (!Array.isArray(_vaultAiResults) || _vaultAiResults.length === 0) throw new Error('empty');

      _vaultAiResults.forEach(function(r){ r._checked = true; });
      renderVaultAiResults();
      document.getElementById('vault-ai-loading').className = 'hidden text-center py-8';
      document.getElementById('vault-ai-step2').style.display = '';
      if (parseResult.partial) {
        showSyncToast('<span class="material-symbols-outlined text-sm mr-1">info</span> 응답이 길어서 ' + _vaultAiResults.length + '개만 복구되었어요');
      }
    } catch(err) {
      document.getElementById('vault-ai-loading').className = 'hidden text-center py-8';
      var msg = err.message === 'empty' ? '유용한 영어 표현을 찾지 못했어요. 다른 대화로 시도해주세요.'
        : err.message === 'parse_fail' ? '응답 형식 에러. 다시 시도해주세요.'
        : 'AI 추출 실패: ' + err.message;
      document.getElementById('vault-ai-error-msg').textContent = msg;
      document.getElementById('vault-ai-error').className = 'p-4 rounded-xl bg-rose-50';
      document.getElementById('vault-ai-step1').style.display = '';
    }
  }

  function renderVaultAiResults() {
    var container = document.getElementById('vault-ai-results');
    container.innerHTML = _vaultAiResults.map(function(r, i) {
      var cs = VAULT_CAT_STYLE[r.category] || VAULT_CAT_STYLE.work;
      return '<div class="vault-ai-item flex items-start gap-3">' +
        '<input type="checkbox" ' + (r._checked ? 'checked' : '') + ' onchange="_vaultAiResults['+i+']._checked=this.checked;updateVaultAiSaveBtn()" class="mt-1.5 accent-[#6b38d4]"/>' +
        '<div class="flex-1 min-w-0">' +
          '<div class="flex items-center gap-2 mb-1"><span class="px-2 py-0.5 rounded text-[9px] font-bold uppercase" style="' + cs + '">' + (r.category||'work') + '</span></div>' +
          '<p class="text-sm font-bold text-[#191c1d]">"' + (r.english||'') + '"</p>' +
          '<p class="text-xs text-[#494454] mt-0.5">' + (r.korean||'') + '</p>' +
          renderConvoHtml(r.conversation, 'light') +
          (r.context ? '<p class="text-[10px] text-[#494454]/60 mt-2">' + r.context + '</p>' : '') +
        '</div></div>';
    }).join('');
    updateVaultAiSaveBtn();
  }

  function toggleAllVaultAi(state) {
    _vaultAiResults.forEach(function(r){ r._checked = state; });
    renderVaultAiResults();
  }

  function updateVaultAiSaveBtn() {
    var count = _vaultAiResults.filter(function(r){ return r._checked; }).length;
    document.getElementById('vault-ai-save-btn').textContent = count + '개 저장';
  }

  async function saveVaultAiResults() {
    var toSave = _vaultAiResults.filter(function(r){ return r._checked; });
    if (!toSave.length) { showSyncToast('<span class="material-symbols-outlined text-sm mr-1">warning</span> 저장할 표현을 선택해주세요'); return; }
    var now = Date.now();
    for (var i = 0; i < toSave.length; i++) {
      var d = { english: toSave[i].english, korean: toSave[i].korean, category: toSave[i].category || 'work', context: toSave[i].context || '', conversation: toSave[i].conversation || [], createdAt: new Date(now + i * 100).toISOString(), updatedAt: new Date(now + i * 100).toISOString() };
      await fbAdd('vaultExpressions', d);
    }
    showSyncToast('<span class="material-symbols-outlined text-sm mr-1">check_circle</span> ' + toSave.length + '개 표현이 저장되었어요 ✨');
    closeVaultAiModal();
    await loadVault();
  }

  // ===== 전역 검색 =====
  var _searchTimeout = null;
  var _searchInput = null;
  var _searchResults = null;

  document.addEventListener('DOMContentLoaded', function() {
    _searchInput = document.getElementById('global-search-input');
    _searchResults = document.getElementById('global-search-results');
    if (!_searchInput) return;

    _searchInput.addEventListener('input', function() {
      clearTimeout(_searchTimeout);
      var q = this.value.trim().toLowerCase();
      if (q.length < 2) { _searchResults.style.display = 'none'; return; }
      _searchTimeout = setTimeout(function(){ performSearch(q); }, 200);
    });
    _searchInput.addEventListener('focus', function() {
      if (this.value.trim().length >= 2) performSearch(this.value.trim().toLowerCase());
    });
    document.addEventListener('click', function(e) {
      if (!e.target.closest('#global-search-input') && !e.target.closest('#global-search-results')) {
        if (_searchResults) _searchResults.style.display = 'none';
      }
    });
    document.addEventListener('keydown', function(e) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); _searchInput.focus(); _searchInput.select(); }
      if (e.key === 'Escape' && _searchResults) _searchResults.style.display = 'none';
    });
  });

  function performSearch(q) {
    var results = [];
    // 여행
    if (typeof tripsData !== 'undefined') tripsData.forEach(function(t) {
      if ((t.name||'').toLowerCase().indexOf(q) >= 0) results.push({cat:'여행',icon:'explore',title:t.name,sub:t.start_date||'',page:'journey'});
    });
    // 도시
    if (typeof citiesData !== 'undefined') citiesData.forEach(function(c) {
      if ((c.name||'').toLowerCase().indexOf(q) >= 0) results.push({cat:'도시',icon:'location_city',title:c.name,sub:c.start_date||'',page:'journey'});
    });
    // 여행 일정 (항공편/숙소/이동수단/기념품)
    if (typeof journeyData !== 'undefined') journeyData.forEach(function(j) {
      var text = ((j.title||'')+(j.description||'')+(j.city||'')).toLowerCase();
      if (text.indexOf(q) >= 0) results.push({cat:j.type||'여행',icon:j.type==='항공편'?'flight':j.type==='숙소'?'hotel':j.type==='이동수단'?'commute':'card_giftcard',title:j.title||j.description||'',sub:j.date||'',page:'journey'});
    });
    // 영어 수업
    if (typeof engSessionsData !== 'undefined') engSessionsData.forEach(function(s) {
      var text = ((s.title||'')+(s.subtitle||'')).toLowerCase();
      if (text.indexOf(q) >= 0) results.push({cat:'영어 수업',icon:'school',title:s.title,sub:s._id,page:'english'});
      // 표현 검색
      (s.expressions||[]).forEach(function(ex) {
        if (((ex.expr||'')+(ex.kr||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'영어 표현',icon:'chat',title:ex.expr,sub:ex.kr,page:'english'});
      });
      // 어휘 검색
      (s.vocabSets||[]).forEach(function(vs) { (vs.words||[]).forEach(function(w) {
        if (((w.word||'')+(w.mean||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'어휘',icon:'translate',title:w.word,sub:w.mean,page:'english'});
      }); });
    });
    // 현금 흐름
    if (typeof hubData !== 'undefined') hubData.forEach(function(r) {
      if (((r[2]||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'현금 흐름',icon:'payments',title:r[2],sub:r[0]||'',page:'finance-hub'});
    });
    // 캘린더
    if (typeof plannerData !== 'undefined') plannerData.forEach(function(r) {
      if (((r[1]||'')).toLowerCase().indexOf(q) >= 0) results.push({cat:'캘린더',icon:'event',title:r[1],sub:r[0]||'',page:'planner'});
    });

    // 50개 제한
    var limited = results.slice(0, 50);
    renderSearchResults(limited, results.length);
  }

  function renderSearchResults(results, totalCount) {
    if (results.length === 0) {
      _searchResults.innerHTML = '<div class="p-4 text-center text-sm text-slate-400">검색 결과가 없습니다</div>';
      _searchResults.style.display = 'block';
      return;
    }
    // 카테고리별 그룹화
    var groups = {};
    results.forEach(function(r) { if (!groups[r.cat]) groups[r.cat] = []; groups[r.cat].push(r); });
    var html = '';
    Object.keys(groups).forEach(function(cat) {
      html += '<div class="px-4 py-1.5 text-[9px] font-bold uppercase tracking-widest text-slate-400 bg-slate-50">' + cat + ' (' + groups[cat].length + ')</div>';
      groups[cat].forEach(function(r) {
        html += '<button onclick="searchNavigate(\'' + r.page + '\');document.getElementById(\'global-search-results\').style.display=\'none\';document.getElementById(\'global-search-input\').value=\'\';" class="w-full text-left px-4 py-2.5 flex items-center gap-3 hover:bg-indigo-50 transition-colors">' +
          '<span class="material-symbols-outlined text-indigo-400" style="font-size:18px">' + r.icon + '</span>' +
          '<div class="min-w-0 flex-1"><p class="text-sm font-medium text-slate-800 truncate">' + r.title + '</p><p class="text-[10px] text-slate-400 truncate">' + r.sub + '</p></div>' +
          '<span class="text-[9px] text-slate-300">' + r.page + '</span></button>';
      });
    });
    if (totalCount > 50) html += '<div class="px-4 py-2 text-center text-xs text-slate-400">외 ' + (totalCount - 50) + '개 더...</div>';
    _searchResults.innerHTML = html;
    _searchResults.style.display = 'block';
  }

  function searchNavigate(pageId) { navigate(pageId); }

